                                    <img src={u.avatar} alt={u.name} className="w-8 h-8 rounded-full bg-slate-200" />
                                    <div>
                                        <p className="font-medium text-slate-900">{u.name}</p>
                                        <p className="text-xs text-slate-500">{u.email}</p>
                                    </div>
                                </td>
                                <td className="px-6 py-4 font-mono text-slate-600">
                                    {u.nickname || '-'}
                                </td>
                                <td className="px-6 py-4 text-center">
                                    <span className={`inline-flex items-center px-2 py-0.5 rounded-full text-[10px] font-bold uppercase ${u.active !== false ? 'bg-green-100 text-green-700 border border-green-200' : 'bg-slate-200 text-slate-500 border border-slate-300'}`}>
                                        {u.active !== false ? 'Activo' : 'Inactivo'}
                                    </span>
                                </td>
                                <td className="px-6 py-4">
                                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium 
                                        ${u.role === UserRole.ADMIN ? 'bg-purple-100 text-purple-800' : 
                                          u.role === UserRole.COORDINATOR ? 'bg-blue-100 text-blue-800' : 
                                          'bg-green-100 text-green-800'}`}>
                                        {u.role}
                                    </span>
                                </td>
                                <td className="px-6 py-4 text-slate-600">{u.organization}</td>
                                <td className="px-6 py-4 text-right">
                                    <div className="flex justify-end gap-1">
                                        <button 
                                            onClick={() => handleToggleStatus(u)}
                                            className={`p-1.5 rounded transition-colors ${u.active !== false ? 'text-slate-400 hover:text-red-600 hover:bg-red-50' : 'text-slate-400 hover:text-green-600 hover:bg-green-50'}`}
                                            title={u.active !== false ? "Inactivar usuario" : "Activar usuario"}
                                        >
                                            <Power size={18} />
                                        </button>
                                        <button 
                                            onClick={() => handleEdit(u)}
                                            className="text-slate-400 hover:text-indigo-600 p-1.5 hover:bg-indigo-50 rounded transition-colors"
                                            title="Editar usuario"
                                        >
                                            <Pencil size={18} />
                                        </button>
                                        <button 
                                            onClick={() => handleDelete(u.id)}
                                            className="text-slate-400 hover:text-red-600 p-1.5 hover:bg-red-50 rounded transition-colors"
                                            title="Eliminar permanentemente"
                                        >
                                            <Trash2 size={18} />
                                        </button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                        {users.length === 0 && !loading && (
                            <tr><td colSpan={6} className="px-6 py-8 text-center text-slate-400">No hay usuarios registrados.</td></tr>
                        )}
                    </tbody>
                </table>
            </div>
        </div>

        {users.some(u => u.active === false) && (
            <div className="flex items-center gap-2 p-3 bg-blue-50 border border-blue-100 rounded-lg text-blue-700 text-xs">
                <AlertCircle size={16} />
                <span>Los usuarios <b>Inactivos</b> no pueden iniciar sesión ni realizar gestiones en el sistema.</span>
            </div>
        )}
    </div>
  );
};

export default AdminUsers;

import { useState, useEffect } from 'react';
import { auth, db } from '../services/firebaseConfig';
import { onAuthStateChanged, signOut } from 'firebase/auth';
import { doc, getDoc, setDoc, deleteDoc, query, collection, where, getDocs, updateDoc } from 'firebase/firestore';
import { User, UserRole } from '../types';
import { UserService } from '../services/firebaseBackend';

export const useAuthStatus = () => {
    const [user, setUser] = useState<User | null>(null);
    const [cargando, setCargando] = useState(true);

    useEffect(() => {
        const cachedInit = localStorage.getItem('sgd_user_cache');
        if (cachedInit) {
            setUser(JSON.parse(cachedInit));
        }

        const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
            if (firebaseUser) {
                try {
                    const userRef = doc(db, "users", firebaseUser.uid);
                    const userSnap = await getDoc(userRef);
                    const email = firebaseUser.email || '';

                    const adminEmails = ['admin@empresa.com'];
                    const shouldBeAdmin = adminEmails.includes(email) || email.toLowerCase().startsWith('admin');

                    if (userSnap.exists()) {
                        const userData = userSnap.data() as User;

                        // VERIFICACIÓN DE ESTADO ACTIVO
                        if (userData.active === false) {
                            console.warn("Intento de acceso de cuenta inactiva:", email);
                            await signOut(auth);
                            localStorage.removeItem('sgd_user_cache');
                            setUser(null);
                            alert("Su cuenta ha sido desactivada por el administrador. Contacte a soporte.");
                            return;
                        }

                        if (shouldBeAdmin && userData.role !== UserRole.ADMIN) {
                            console.log("Upgrading user to ADMIN.");
                            const updatedUser = { ...userData, role: UserRole.ADMIN, organization: 'Administración Sistema' };
                            await updateDoc(userRef, { role: UserRole.ADMIN, organization: 'Administración Sistema' });
                            setUser(updatedUser);
                        } else {
                            setUser(userData);
                        }
                    } else {
                        let existingProfile: User | null = null;
                        let oldDocRef = null;

                        if (email) {
                            const q = query(collection(db, "users"), where("email", "==", email));
                            const querySnapshot = await getDocs(q);
                            if (!querySnapshot.empty) {
                                const docFound = querySnapshot.docs[0];
                                existingProfile = docFound.data() as User;
                                oldDocRef = docFound.ref;
                            }
                        }

                        if (existingProfile && oldDocRef) {
                            const migratedUser: User = {
                                ...existingProfile,
                                id: firebaseUser.uid, 
                                avatar: firebaseUser.photoURL || existingProfile.avatar || `https://ui-avatars.com/api/?name=${encodeURIComponent(existingProfile.name || 'User')}`, 
                                role: shouldBeAdmin ? UserRole.ADMIN : existingProfile.role,
                                active: true
                            };

                            const safeUser = JSON.parse(JSON.stringify(migratedUser));
                            await setDoc(userRef, safeUser);
                            await UserService.migrateLegacyReferences(existingProfile.id, firebaseUser.uid);
                            await deleteDoc(oldDocRef);
                            setUser(migratedUser);
                        } else {
                            const newUser: User = {
                                id: firebaseUser.uid,
                                email: email,
                                name: firebaseUser.displayName || email.split('@')[0],
                                nickname: email.split('@')[0],
                                role: shouldBeAdmin ? UserRole.ADMIN : UserRole.ANALYST,
                                avatar: firebaseUser.photoURL || `https://ui-avatars.com/api/?name=${firebaseUser.displayName || email}`,
                                organization: shouldBeAdmin ? 'Administración Sistema' : 'Sin Asignar',
                                active: true 
                            };

                            const safeNewUser = JSON.parse(JSON.stringify(newUser));
                            await setDoc(userRef, safeNewUser);
                            setUser(newUser);
                        }
                    }
                } catch (error) {
                    console.error("Error fetching/creating user profile:", error);
                    setUser(null);
                }
            } else {
                const cached = localStorage.getItem('sgd_user_cache');
                if (cached) {
                    try {
                        const parsedUser = JSON.parse(cached);
                        if (parsedUser && parsedUser.id && parsedUser.role && parsedUser.active !== false) {
                            setUser(parsedUser);
                        } else {
                            setUser(null);
                        }
                    } catch (e) {
                        setUser(null);
                    }
                } else {
                    setUser(null);
                }
            }
            setCargando(false);
        });

        return () => unsubscribe(); 
    }, []);

    return { user, cargando };
};

import React, { useEffect, useState, useMemo } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService } from '../services/firebaseBackend';
import { Document, User, UserRole, DocState, DocType, FullHierarchy } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    Plus, Clock, CheckCircle, Filter, X, Calendar, ArrowRight, Activity, 
    BookOpen, Users, ShieldCheck, ArrowUp, ArrowDown, ArrowUpDown, Loader2,
    User as UserIcon, Database, AlertTriangle, Archive, PlayCircle, Search,
    ChevronLeft, ChevronRight, FileSpreadsheet
} from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

interface DashboardProps {
  user: User;
}

// Extend Document interface locally to handle the "Required" flag for the Dashboard view
interface DashboardDoc extends Document {
    isRequired: boolean; // True if it matches the Matrix, False if it's an extra historical doc
}

type SortKey = 'project' | 'microprocess' | 'state' | 'updatedAt';
type QuickFilterType = 'ALL' | 'NOT_STARTED' | 'IN_PROCESS' | 'REFERENT' | 'CONTROL' | 'FINISHED';

const ITEMS_PER_PAGE = 10;

// Helper to order DocTypes logically
const getDocTypeOrder = (type: string | undefined): number => {
    switch (type) {
        case 'AS IS': return 1;
        case 'FCE': return 2;
        case 'PM': return 3;
        case 'TO BE': return 4;
        default: return 99;
    }
};

const Dashboard: React.FC<DashboardProps> = ({ user }) => {
  const navigate = useNavigate();
  const location = useLocation(); 

  const [mergedDocs, setMergedDocs] = useState<DashboardDoc[]>([]);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSystemEmpty, setIsSystemEmpty] = useState(false);

  // Filters State
  const [filterProject, setFilterProject] = useState('');
  const [filterAnalyst, setFilterAnalyst] = useState('');
  const [filterMacro, setFilterMacro] = useState('');
  const [filterProcess, setFilterProcess] = useState('');
  const [filterSearch, setFilterSearch] = useState(''); 
  const [filterDocType, setFilterDocType] = useState('');
  const [filterState, setFilterState] = useState(''); 

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);

  // External Filter (From Reports)
  const [externalFilterIds, setExternalFilterIds] = useState<string[] | null>(null);

  // Quick Stats Filter (Cards)
  const [quickFilter, setQuickFilter] = useState<QuickFilterType>('ALL');

  const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: 'asc' | 'desc' }>({
    key: 'project', 
    direction: 'asc'
  });

  useEffect(() => {
    if (location.state?.filterIds && Array.isArray(location.state.filterIds)) {
        setExternalFilterIds(location.state.filterIds);
        setQuickFilter('ALL');
    } else {
        setExternalFilterIds(null);
    }
    loadData();
  }, [location.state]);

  // Reset pagination when filters change
  useEffect(() => {
    setCurrentPage(1);
  }, [filterProject, filterAnalyst, filterMacro, filterProcess, filterSearch, filterDocType, filterState, quickFilter, sortConfig]);

  const normalize = (str: string | undefined) => {
      if (!str) return '';
      return str.trim().toUpperCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  };

  const loadData = async () => {
    setLoading(true);
    try {
        const [realDocsData, users, fullHierarchy] = await Promise.all([
            DocumentService.getAll(),
            UserService.getAll(),
            HierarchyService.getFullHierarchy()
        ]);

        setAllUsers(users);

        const hierarchyKeys = Object.keys(fullHierarchy);

        if (hierarchyKeys.length === 0 && realDocsData.length === 0) {
            setIsSystemEmpty(true);
            setMergedDocs([]);
            setLoading(false);
            return;
        }
        setIsSystemEmpty(false);

        const realDocMap = new Map<string, Document>();
        const processedDocIds = new Set<string>();

        realDocsData.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalize(doc.project)}|${normalize(microName)}|${normalize(docType)}`;

                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        const finalDocsList: DashboardDoc[] = [];

        hierarchyKeys.forEach(proj => {
            Object.keys(fullHierarchy[proj]).forEach(macro => {
                Object.keys(fullHierarchy[proj][macro]).forEach(proc => {
                    const nodes = fullHierarchy[proj][macro][proc];
                    nodes.forEach(node => {
                        if (node.active === false) return; 

                        const requiredTypes = (node.requiredTypes && node.requiredTypes.length > 0) 
                            ? node.requiredTypes 
                            : ['AS IS', 'FCE', 'PM', 'TO BE'];

                        requiredTypes.forEach(type => {
                            const key = `${normalize(proj)}|${normalize(node.name)}|${normalize(type)}`;

                            if (realDocMap.has(key)) {
                                const realDoc = realDocMap.get(key)!;
                                finalDocsList.push({
                                    ...realDoc,
                                    macroprocess: macro,
                                    process: proc,
                                    project: proj,
                                    assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []),
                                    isRequired: true 
                                });
                                processedDocIds.add(realDoc.id); 
                            } else {
                                finalDocsList.push({
                                    id: `virtual-${key}`, 
                                    title: `${node.name} - ${type}`,
                                    description: 'Pendiente de inicio',
                                    project: proj,
                                    macroprocess: macro,
                                    process: proc,
                                    microprocess: node.name,
                                    docType: type as DocType,
                                    authorId: '',
                                    authorName: '',
                                    assignedTo: node.assignees?.[0] || '',
                                    assignees: node.assignees || [],
                                    state: DocState.NOT_STARTED,
                                    version: '-',
                                    progress: 0,
                                    files: [],
                                    createdAt: new Date().toISOString(),
                                    updatedAt: new Date(0).toISOString(), 
                                    hasPendingRequest: false,
                                    isRequired: true 
                                });
                            }
                        });
                    });
                });
            });
        });

        realDocMap.forEach((doc) => {
            if (!processedDocIds.has(doc.id)) {
                finalDocsList.push({
                    ...doc,
                    macroprocess: doc.macroprocess || 'Sin Clasificar',
                    process: doc.process || 'Sin Clasificar',
                    isRequired: false 
                });
            }
        });

        setMergedDocs(finalDocsList);

    } catch (error) {
        console.error("Error loading dashboard data:", error);
    } finally {
        setLoading(false);
    }
  };

  const contextDocs = useMemo(() => {
      let filtered = mergedDocs;

      if (externalFilterIds && externalFilterIds.length > 0) {
          filtered = filtered.filter(d => externalFilterIds.includes(d.id));
      } else {
          if (filterProject) filtered = filtered.filter(d => d.project === filterProject);
          if (filterAnalyst) filtered = filtered.filter(d => d.assignees && d.assignees.includes(filterAnalyst));
          if (filterMacro) filtered = filtered.filter(d => d.macroprocess === filterMacro);
          if (filterProcess) filtered = filtered.filter(d => d.process === filterProcess);
          if (filterDocType) filtered = filtered.filter(d => d.docType === filterDocType);
          if (filterState) filtered = filtered.filter(d => d.state === filterState);

          if (filterSearch) {
              const term = filterSearch.toLowerCase();
              filtered = filtered.filter(d => 
                  (d.microprocess || '').toLowerCase().includes(term) || 
                  (d.title || '').toLowerCase().includes(term)
              );
          }
      }

      return filtered;
  }, [mergedDocs, filterProject, filterAnalyst, filterMacro, filterProcess, filterDocType, filterState, filterSearch, externalFilterIds]);

  const stats = useMemo(() => {
      const requiredDocs = contextDocs.filter(d => d.isRequired);

      return {
        total: requiredDocs.length,
        notStarted: requiredDocs.filter(d => d.state === DocState.NOT_STARTED).length,
        inProcess: requiredDocs.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW).length,
        referent: requiredDocs.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW).length,
        control: requiredDocs.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW).length,
        finished: requiredDocs.filter(d => d.state === DocState.APPROVED).length
      };
  }, [contextDocs]);

  const tableDocs = useMemo(() => {
      let filtered = contextDocs;

      if (quickFilter !== 'ALL') {
          switch (quickFilter) {
              case 'NOT_STARTED': filtered = filtered.filter(d => d.state === DocState.NOT_STARTED); break;
              case 'IN_PROCESS': filtered = filtered.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW); break;
              case 'REFERENT': filtered = filtered.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW); break;
              case 'CONTROL': filtered = filtered.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW); break;
              case 'FINISHED': filtered = filtered.filter(d => d.state === DocState.APPROVED); break;
          }
      }
      return filtered;
  }, [contextDocs, quickFilter]);

  const sortedDocs = useMemo(() => {
      return [...tableDocs].sort((a, b) => {
          if (a.isRequired !== b.isRequired) {
              return a.isRequired ? -1 : 1;
          }

          const modifier = sortConfig.direction === 'asc' ? 1 : -1;

          switch (sortConfig.key) {
              case 'updatedAt': 
                  const timeA = new Date(a.updatedAt).getTime();
                  const timeB = new Date(b.updatedAt).getTime();
                  return (timeA - timeB) * modifier;

              case 'project': 
                  if ((a.project || '') !== (b.project || '')) return (a.project || '').localeCompare(b.project || '') * modifier;
                  if ((a.macroprocess || '') !== (b.macroprocess || '')) return (a.macroprocess || '').localeCompare(b.macroprocess || '') * modifier;
                  if ((a.process || '') !== (b.process || '')) return (a.process || '').localeCompare(b.process || '') * modifier;
                  if ((a.microprocess || '') !== (b.microprocess || '')) return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
                  return (getDocTypeOrder(a.docType) - getDocTypeOrder(b.docType)) * modifier;

              case 'microprocess': return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
              case 'state': return (a.progress - b.progress) * modifier;
              default: return 0;
          }
      });
  }, [tableDocs, sortConfig]);

  // PAGINATION LOGIC
  const totalItems = sortedDocs.length;
  const totalPages = Math.ceil(totalItems / ITEMS_PER_PAGE);
  const paginatedDocs = useMemo(() => {
      const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
      return sortedDocs.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [sortedDocs, currentPage]);

  const handleExportExcel = () => {
      if (sortedDocs.length === 0) return;

      const getUserNames = (ids: string[]) => ids.map(id => allUsers.find(u => u.id === id)?.name || id).join('; ');

      const headers = [
          'Requerido', 'Proyecto', 'Macroproceso', 'Proceso', 'Microproceso', 
          'Tipo Documento', 'Estado', 'Versión', 'Avance %', 'Última Actualización', 'Analistas'
      ];

      const rows = sortedDocs.map(d => [
          d.isRequired ? 'SI' : 'NO',
          d.project || '-',
          d.macroprocess || '-',
          d.process || '-',
          d.microprocess || '-',
          d.docType || '-',
          STATE_CONFIG[d.state]?.label.split('(')[0] || '-',
          d.version || '-',
          `${d.progress}%`,
          new Date(d.updatedAt).toLocaleDateString(),
          getUserNames(d.assignees || [])
      ]);

      const csvContent = [
          headers.join(','),
          ...rows.map(r => r.map(cell => `"${cell}"`).join(','))
      ].join('\n');

      const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.setAttribute('href', url);
      link.setAttribute('download', `SGD_Export_${new Date().toISOString().split('T')[0]}.csv`);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
  };

  const chartData = [
    { name: 'No Iniciado', value: stats.notStarted, color: '#e2e8f0' },
    { name: 'En Proceso', value: stats.inProcess, color: '#3b82f6' },
    { name: 'Referente', value: stats.referent, color: '#a855f7' },
    { name: 'Control', value: stats.control, color: '#f97316' },
    { name: 'Finalizado', value: stats.finished, color: '#22c55e' },
  ].filter(d => d.value > 0);

  const handleSort = (key: SortKey) => {
      setSortConfig({ key, direction: sortConfig.key === key && sortConfig.direction === 'asc' ? 'desc' : 'asc' });
  };

  const handleQuickFilter = (type: QuickFilterType) => {
      setQuickFilter(quickFilter === type ? 'ALL' : type);
  };

  const clearFilters = () => {
      setFilterProject('');
      setFilterAnalyst('');
      setFilterMacro('');
      setFilterProcess('');
      setFilterSearch(''); 
      setFilterDocType('');
      setFilterState('');
      setQuickFilter('ALL');
      setExternalFilterIds(null); 
      navigate(location.pathname, { replace: true, state: {} });
  };

  const SortIcon = ({ column }: { column: SortKey }) => (
      sortConfig.key === column ? (sortConfig.direction === 'asc' ? <ArrowUp size={12} className="text-indigo-600"/> : <ArrowDown size={12} className="text-indigo-600"/>) : <ArrowUpDown size={12} className="opacity-30 group-hover:opacity-100"/>
  );

  const availableProjects = useMemo(() => Array.from(new Set(mergedDocs.map(d => d.project).filter(Boolean))).sort(), [mergedDocs]);
  const availableMacros = useMemo(() => {
      const docs = filterProject ? mergedDocs.filter(d => d.project === filterProject) : mergedDocs;
      return Array.from(new Set(docs.map(d => d.macroprocess).filter(Boolean))).sort();
  }, [mergedDocs, filterProject]);
  const availableProcesses = useMemo(() => {
      let docs = mergedDocs;
      if (filterProject) docs = docs.filter(d => d.project === filterProject);
      if (filterMacro) docs = docs.filter(d => d.macroprocess === filterMacro);
      return Array.from(new Set(docs.map(d => d.process).filter(Boolean))).sort();
  }, [mergedDocs, filterProject, filterMacro]);

  const getUserName = (id: string) => allUsers.find(user => user.id === id)?.name || 'Sin Asignar';

  if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Actualizando dashboard...</div>;

  if (isSystemEmpty) {
      return (
          <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6 bg-white rounded-xl shadow-sm border border-slate-200">
              <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center mb-6">
                  <Database size={40} className="text-indigo-600" />
              </div>
              <h2 className="text-2xl font-bold text-slate-900 mb-2">Sistema sin Inicializar</h2>
              <p className="text-slate-500 max-w-md mb-8">La matriz de procesos está vacía. Para visualizar el avance, es necesario cargar la estructura de procesos inicial.</p>
              {(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) ? (
                  <Link to="/admin/assignments" className="flex items-center px-6 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-medium shadow-md transition-transform active:scale-95">
                      <Database size={18} className="mr-2" /> Ir a Carga de Datos
                  </Link>
              ) : (
                  <div className="flex items-center gap-2 text-amber-600 bg-amber-50 px-4 py-2 rounded-lg border border-amber-100">
                      <AlertTriangle size={18} /> <span>Contacte al administrador para inicializar el sistema.</span>
                  </div>
              )}
          </div>
      );
  }

  const hasActiveFilters = filterProject || filterAnalyst || filterMacro || filterProcess || filterSearch || filterDocType || filterState || externalFilterIds;

  return (
    <div className="space-y-6 pb-12">
      <div className="flex justify-between items-center">
        <div><h1 className="text-2xl font-bold text-slate-900">Dashboard</h1><p className="text-slate-500">Vista general</p></div>
        <div className="flex items-center gap-2">
            <button 
                onClick={handleExportExcel}
                className="px-4 py-2 bg-white border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 flex items-center shadow-sm font-medium transition-colors"
                title="Exportar a CSV/Excel"
            >
                <FileSpreadsheet size={18} className="mr-2 text-green-600"/> Exportar Excel
            </button>
            {user.role === UserRole.ANALYST && <Link to="/new" className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 flex items-center shadow-sm font-medium"><Plus size={18} className="mr-2"/> Nueva Solicitud</Link>}
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-3">
        <StatCard title="Doc. Requeridos" value={stats.total} icon={BookOpen} color="bg-slate-50 text-slate-600 border-slate-200" onClick={() => handleQuickFilter('ALL')} isActive={quickFilter === 'ALL'}/>
        <StatCard title="No Iniciado" value={stats.notStarted} icon={Clock} color="bg-white text-slate-600 border-slate-200" onClick={() => handleQuickFilter('NOT_STARTED')} isActive={quickFilter === 'NOT_STARTED'}/>
        <StatCard title="En Proceso" value={stats.inProcess} icon={Activity} color="bg-blue-50 text-blue-600 border-blue-100" onClick={() => handleQuickFilter('IN_PROCESS')} isActive={quickFilter === 'IN_PROCESS'}/>
        <StatCard title="Referente" value={stats.referent} icon={Users} color="bg-purple-50 text-purple-600 border-purple-100" onClick={() => handleQuickFilter('REFERENT')} isActive={quickFilter === 'REFERENT'}/>
        <StatCard title="Control Gestión" value={stats.control} icon={ShieldCheck} color="bg-orange-50 text-orange-600 border-orange-100" onClick={() => handleQuickFilter('CONTROL')} isActive={quickFilter === 'CONTROL'}/>
        <StatCard title="Terminados" value={stats.finished} icon={CheckCircle} color="bg-green-50 text-green-600 border-green-100" onClick={() => handleQuickFilter('FINISHED')} isActive={quickFilter === 'FINISHED'}/>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        <div className="lg:col-span-3 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col">
            <div className="p-4 border-b border-slate-100 bg-white">
                <div className="flex items-center justify-between mb-3">
                    <div className="flex items-center gap-2 text-indigo-600 font-semibold text-sm"><Filter size={16} /> Filtros de Visualización</div>
                    {hasActiveFilters && (
                        <button onClick={clearFilters} className="text-xs text-red-500 hover:text-red-700 flex items-center gap-1 font-medium transition-colors">
                            <X size={14} /> Limpiar filtros
                        </button>
                    )}
                </div>
                {externalFilterIds ? (
                     <div className="bg-blue-50 border border-blue-100 p-3 rounded-lg mb-2 flex justify-between items-center animate-fadeIn">
                        <span className="text-xs text-blue-700 font-semibold">Filtro Activo: Visualizando {externalFilterIds.length} documentos específicos.</span>
                        <button onClick={clearFilters} className="text-xs bg-white border border-blue-200 px-2 py-1 rounded text-blue-600 hover:bg-blue-50">Mostrar Todo</button>
                     </div>
                ) : (
                    <div className="flex flex-wrap gap-3">
                        <select value={filterProject} onChange={(e) => setFilterProject(e.target.value)} className="text-xs p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500 w-32">
                            <option value="">Proyecto (Todos)</option>
                            {availableProjects.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                        <select value={filterMacro} onChange={(e) => setFilterMacro(e.target.value)} className="text-xs p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500 w-40">
                            <option value="">Macro (Todos)</option>
                            {availableMacros.map(m => <option key={m} value={m}>{m}</option>)}
                        </select>
                        <select value={filterProcess} onChange={(e) => setFilterProcess(e.target.value)} className="text-xs p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500 w-40">
                            <option value="">Proceso (Todos)</option>
                            {availableProcesses.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                        <div className="relative w-40">
                            <Search size={14} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400" />
                            <input type="text" value={filterSearch} onChange={(e) => setFilterSearch(e.target.value)} placeholder="Buscar..." className="w-full text-xs pl-8 p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500" />
                        </div>
                    </div>
                )}
            </div>

            <div className="overflow-x-auto flex-1">
                <table className="w-full text-xs text-left">
                    <thead className="text-[10px] text-slate-400 uppercase font-bold bg-white border-b border-slate-100">
                        <tr>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('project')}>PROYECTO <SortIcon column="project"/></th>
                            <th className="px-4 py-3">JERARQUÍA</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('microprocess')}>MICROPROCESO <SortIcon column="microprocess"/></th>
                            <th className="px-4 py-3">DOC</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('state')}>ESTADO <SortIcon column="state"/></th>
                            <th className="px-4 py-3 text-right">ACTIVIDAD</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                        {paginatedDocs.length === 0 ? <tr><td colSpan={6} className="p-8 text-center text-slate-400">Sin resultados.</td></tr> : paginatedDocs.map((doc, idx) => (
                            <tr key={`${doc.id}-${idx}`} className={`transition-colors ${!doc.isRequired ? 'bg-gray-100 hover:bg-gray-200' : 'hover:bg-slate-50'}`}>
                                <td className={`px-4 py-3 font-bold align-top ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.project}</td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`font-bold ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.macroprocess}</div>
                                    <div className="text-slate-500 text-[10px]">{doc.process}</div>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`font-bold mb-1 ${!doc.isRequired ? 'text-gray-600' : 'text-slate-800'}`}>{doc.microprocess}</div>
                                    <div className="flex items-center gap-1 text-slate-500" title="Analista Asignado">
                                        <UserIcon size={10} /> <span className="text-[10px]">{doc.assignees && doc.assignees.length > 0 ? getUserName(doc.assignees[0]) : 'Sin Asignar'}</span>
                                    </div>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <span className={`inline-block px-1.5 py-0.5 rounded border text-[10px] font-bold mb-1 ${!doc.isRequired ? 'bg-gray-200 text-gray-500 border-gray-300' : 'bg-indigo-50 text-indigo-700 border-indigo-100'}`}>{doc.docType}</span>
                                    <Link to={`/doc/${doc.id}`} state={{ docData: doc }} className="flex items-center gap-1 text-[10px] font-bold text-indigo-500 hover:text-indigo-700">Ver <ArrowRight size={10}/></Link>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`inline-block px-2 py-0.5 rounded-full text-[10px] font-bold mb-1 border ${!doc.isRequired ? 'bg-gray-200 text-gray-500 border-gray-300' : STATE_CONFIG[doc.state].color}`}>{STATE_CONFIG[doc.state].label.split('(')[0]}</div>
                                    <div className="text-[10px] font-mono text-slate-500">v{doc.version} ({doc.progress}%)</div>
                                </td>
                                <td className="px-4 py-3 align-top text-right">
                                    {doc.state !== DocState.NOT_STARTED ? (
                                        <div className="text-slate-600 font-medium">{new Date(doc.updatedAt).toLocaleDateString()}</div>
                                    ) : <span className="text-slate-300">-</span>}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {/* PAGINATION FOOTER */}
            {totalItems > 0 && (
                <div className="px-4 py-3 border-t border-slate-100 bg-slate-50/50 flex items-center justify-between">
                    <div className="text-xs text-slate-500">
                        Mostrando <span className="font-bold text-slate-700">{Math.min(totalItems, (currentPage - 1) * ITEMS_PER_PAGE + 1)}</span> a <span className="font-bold text-slate-700">{Math.min(totalItems, currentPage * ITEMS_PER_PAGE)}</span> de <span className="font-bold text-slate-700">{totalItems}</span> registros
                    </div>
                    <div className="flex items-center gap-2">
                        <button 
                            onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))}
                            disabled={currentPage === 1}
                            className="p-1.5 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
                        >
                            <ChevronLeft size={16} />
                        </button>
                        <div className="flex items-center gap-1">
                            {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                                // Simple logic to show pages around current
                                let pageNum = i + 1;
                                if (totalPages > 5 && currentPage > 3) {
                                    pageNum = currentPage - 3 + i + 1;
                                    if (pageNum > totalPages) pageNum = totalPages - (4 - i);
                                }
                                return (
                                    <button
                                        key={pageNum}
                                        onClick={() => setCurrentPage(pageNum)}
                                        className={`w-8 h-8 rounded-lg text-xs font-bold transition-all border ${currentPage === pageNum ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white text-slate-600 border-slate-200 hover:border-indigo-400'}`}
                                    >
                                        {pageNum}
                                    </button>
                                );
                            })}
                        </div>
                        <button 
                            onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))}
                            disabled={currentPage === totalPages}
                            className="p-1.5 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
                        >
                            <ChevronRight size={16} />
                        </button>
                    </div>
                </div>
            )}
        </div>

        <div className="lg:col-span-1 space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4 min-h-[250px] flex flex-col items-center justify-center">
                <h3 className="font-bold text-center mb-2 text-slate-700 text-sm">Estado (Requeridos)</h3>
                {chartData.length > 0 ? (
                    <div className="h-48 w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie data={chartData} cx="50%" cy="50%" innerRadius={50} outerRadius={70} paddingAngle={2} dataKey="value">
                                    {chartData.map((e, i) => <Cell key={i} fill={e.color}/>)}
                                </Pie>
                                <Tooltip contentStyle={{fontSize: '12px'}}/>
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                ) : <p className="text-center text-slate-400 text-xs">Sin datos.</p>}
                <div className="flex flex-wrap justify-center gap-2 mt-2">
                    {chartData.map((d, i) => (
                        <div key={i} className="flex items-center gap-1">
                            <span className="w-2 h-2 rounded-full" style={{backgroundColor: d.color}}></span>
                            <span className="text-[10px] text-slate-500">{d.name}</span>
                        </div>
                    ))}
                </div>
            </div>

            <div className="bg-indigo-50 rounded-xl shadow-sm border border-indigo-100 p-4">
                <h3 className="font-bold text-indigo-900 text-sm mb-3">Resumen de Cumplimiento</h3>
                <ul className="space-y-2 text-xs">
                    <li className="border-t border-indigo-200 pt-1 flex justify-between text-slate-600"><span>No Iniciados:</span> <span>{stats.notStarted}</span></li>
                    <li className="flex justify-between text-blue-600 font-medium"><span>En Proceso:</span> <span>{stats.inProcess}</span></li>
                    <li className="flex justify-between text-purple-600 font-medium"><span>Referente:</span> <span>{stats.referent}</span></li>
                    <li className="flex justify-between text-orange-600 font-medium"><span>Control Gestión:</span> <span>{stats.control}</span></li>
                    <li className="border-t border-indigo-200 pt-1 flex justify-between text-green-600 font-bold"><span>Terminados:</span> <span>{stats.finished}</span></li>
                </ul>
                <div className="mt-4 pt-3 border-t border-indigo-200 text-[10px] text-slate-500 flex items-center gap-2"><Archive size={12} /><span>Registros en <span className="font-bold text-gray-500">GRIS</span> son históricos.</span></div>
            </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon: Icon, color, isActive, onClick }: any) => (
    <div onClick={onClick} className={`p-3 rounded-xl shadow-sm border cursor-pointer flex items-center space-x-3 transition-all ${isActive ? 'ring-2 ring-indigo-200 scale-105' : 'hover:border-indigo-300'} ${color}`}>
        <div className="p-1.5 bg-white/50 rounded-lg"><Icon size={18}/></div>
        <div>
            <p className="text-[9px] uppercase font-bold opacity-70">{title}</p>
            <p className="text-lg font-bold leading-none">{value}</p>
        </div>
    </div>
);

export default Dashboard;

import React, { useEffect, useState, useMemo } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService } from '../services/firebaseBackend';
import { Document, User, UserRole, DocState, DocType, FullHierarchy } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    Plus, Clock, CheckCircle, Filter, X, Calendar, ArrowRight, Activity, 
    BookOpen, Users, ShieldCheck, ArrowUp, ArrowDown, ArrowUpDown, Loader2,
    User as UserIcon, Database, AlertTriangle, Archive, PlayCircle, Search,
    ChevronLeft, ChevronRight, FileSpreadsheet
} from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

interface DashboardProps {
  user: User;
}

// Extend Document interface locally to handle the "Required" flag for the Dashboard view
interface DashboardDoc extends Document {
    isRequired: boolean; // True if it matches the Matrix, False if it's an extra historical doc
}

type SortKey = 'project' | 'microprocess' | 'state' | 'updatedAt';
type QuickFilterType = 'ALL' | 'NOT_STARTED' | 'IN_PROCESS' | 'REFERENT' | 'CONTROL' | 'FINISHED';

// Configuración de paginación
const ITEMS_PER_PAGE = 10;

// Helper to order DocTypes logically
const getDocTypeOrder = (type: string | undefined): number => {
    switch (type) {
        case 'AS IS': return 1;
        case 'FCE': return 2;
        case 'PM': return 3;
        case 'TO BE': return 4;
        default: return 99;
    }
};

const Dashboard: React.FC<DashboardProps> = ({ user }) => {
  const navigate = useNavigate();
  const location = useLocation(); 

  const [mergedDocs, setMergedDocs] = useState<DashboardDoc[]>([]);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSystemEmpty, setIsSystemEmpty] = useState(false);

  // Filters State
  const [filterProject, setFilterProject] = useState('');
  const [filterAnalyst, setFilterAnalyst] = useState('');
  const [filterMacro, setFilterMacro] = useState('');
  const [filterProcess, setFilterProcess] = useState('');
  const [filterSearch, setFilterSearch] = useState(''); 
  const [filterDocType, setFilterDocType] = useState('');
  const [filterState, setFilterState] = useState(''); 

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);

  // External Filter (From Reports)
  const [externalFilterIds, setExternalFilterIds] = useState<string[] | null>(null);

  // Quick Stats Filter (Cards)
  const [quickFilter, setQuickFilter] = useState<QuickFilterType>('ALL');

  const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: 'asc' | 'desc' }>({
    key: 'project', 
    direction: 'asc'
  });

  useEffect(() => {
    if (location.state?.filterIds && Array.isArray(location.state.filterIds)) {
        setExternalFilterIds(location.state.filterIds);
        setQuickFilter('ALL');
    } else {
        setExternalFilterIds(null);
    }
    loadData();
  }, [location.state]);

  // Reiniciar a la página 1 cuando cambian los filtros o el orden
  useEffect(() => {
    setCurrentPage(1);
  }, [filterProject, filterAnalyst, filterMacro, filterProcess, filterSearch, filterDocType, filterState, quickFilter, sortConfig]);

  const normalize = (str: string | undefined) => {
      if (!str) return '';
      return str.trim().toUpperCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  };

  const loadData = async () => {
    setLoading(true);
    try {
        const [realDocsData, users, fullHierarchy] = await Promise.all([
            DocumentService.getAll(),
            UserService.getAll(),
            HierarchyService.getFullHierarchy()
        ]);

        setAllUsers(users);

        const hierarchyKeys = Object.keys(fullHierarchy);

        if (hierarchyKeys.length === 0 && realDocsData.length === 0) {
            setIsSystemEmpty(true);
            setMergedDocs([]);
            setLoading(false);
            return;
        }
        setIsSystemEmpty(false);

        const realDocMap = new Map<string, Document>();
        const processedDocIds = new Set<string>();

        realDocsData.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalize(doc.project)}|${normalize(microName)}|${normalize(docType)}`;

                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        const finalDocsList: DashboardDoc[] = [];

        hierarchyKeys.forEach(proj => {
            Object.keys(fullHierarchy[proj]).forEach(macro => {
                Object.keys(fullHierarchy[proj][macro]).forEach(proc => {
                    const nodes = fullHierarchy[proj][macro][proc];
                    nodes.forEach(node => {
                        if (node.active === false) return; 

                        const requiredTypes = (node.requiredTypes && node.requiredTypes.length > 0) 
                            ? node.requiredTypes 
                            : ['AS IS', 'FCE', 'PM', 'TO BE'];

                        requiredTypes.forEach(type => {
                            const key = `${normalize(proj)}|${normalize(node.name)}|${normalize(type)}`;

                            if (realDocMap.has(key)) {
                                const realDoc = realDocMap.get(key)!;
                                finalDocsList.push({
                                    ...realDoc,
                                    macroprocess: macro,
                                    process: proc,
                                    project: proj,
                                    assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []),
                                    isRequired: true 
                                });
                                processedDocIds.add(realDoc.id); 
                            } else {
                                finalDocsList.push({
                                    id: `virtual-${key}`, 
                                    title: `${node.name} - ${type}`,
                                    description: 'Pendiente de inicio',
                                    project: proj,
                                    macroprocess: macro,
                                    process: proc,
                                    microprocess: node.name,
                                    docType: type as DocType,
                                    authorId: '',
                                    authorName: '',
                                    assignedTo: node.assignees?.[0] || '',
                                    assignees: node.assignees || [],
                                    state: DocState.NOT_STARTED,
                                    version: '-',
                                    progress: 0,
                                    files: [],
                                    createdAt: new Date().toISOString(),
                                    updatedAt: new Date(0).toISOString(), 
                                    hasPendingRequest: false,
                                    isRequired: true 
                                });
                            }
                        });
                    });
                });
            });
        });

        realDocMap.forEach((doc) => {
            if (!processedDocIds.has(doc.id)) {
                finalDocsList.push({
                    ...doc,
                    macroprocess: doc.macroprocess || 'Sin Clasificar',
                    process: doc.process || 'Sin Clasificar',
                    isRequired: false 
                });
            }
        });

        setMergedDocs(finalDocsList);

    } catch (error) {
        console.error("Error loading dashboard data:", error);
    } finally {
        setLoading(false);
    }
  };

  const contextDocs = useMemo(() => {
      let filtered = mergedDocs;

      if (externalFilterIds && externalFilterIds.length > 0) {
          filtered = filtered.filter(d => externalFilterIds.includes(d.id));
      } else {
          if (filterProject) filtered = filtered.filter(d => d.project === filterProject);
          if (filterAnalyst) filtered = filtered.filter(d => d.assignees && d.assignees.includes(filterAnalyst));
          if (filterMacro) filtered = filtered.filter(d => d.macroprocess === filterMacro);
          if (filterProcess) filtered = filtered.filter(d => d.process === filterProcess);
          if (filterDocType) filtered = filtered.filter(d => d.docType === filterDocType);
          if (filterState) filtered = filtered.filter(d => d.state === filterState);

          if (filterSearch) {
              const term = filterSearch.toLowerCase();
              filtered = filtered.filter(d => 
                  (d.microprocess || '').toLowerCase().includes(term) || 
                  (d.title || '').toLowerCase().includes(term)
              );
          }
      }

      return filtered;
  }, [mergedDocs, filterProject, filterAnalyst, filterMacro, filterProcess, filterDocType, filterState, filterSearch, externalFilterIds]);

  const stats = useMemo(() => {
      const requiredDocs = contextDocs.filter(d => d.isRequired);

      return {
        total: requiredDocs.length,
        notStarted: requiredDocs.filter(d => d.state === DocState.NOT_STARTED).length,
        inProcess: requiredDocs.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW).length,
        referent: requiredDocs.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW).length,
        control: requiredDocs.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW).length,
        finished: requiredDocs.filter(d => d.state === DocState.APPROVED).length
      };
  }, [contextDocs]);

  const tableDocs = useMemo(() => {
      let filtered = contextDocs;

      if (quickFilter !== 'ALL') {
          switch (quickFilter) {
              case 'NOT_STARTED': filtered = filtered.filter(d => d.state === DocState.NOT_STARTED); break;
              case 'IN_PROCESS': filtered = filtered.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW); break;
              case 'REFERENT': filtered = filtered.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW); break;
              case 'CONTROL': filtered = filtered.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW); break;
              case 'FINISHED': filtered = filtered.filter(d => d.state === DocState.APPROVED); break;
          }
      }
      return filtered;
  }, [contextDocs, quickFilter]);

  const sortedDocs = useMemo(() => {
      return [...tableDocs].sort((a, b) => {
          if (a.isRequired !== b.isRequired) {
              return a.isRequired ? -1 : 1;
          }

          const modifier = sortConfig.direction === 'asc' ? 1 : -1;

          switch (sortConfig.key) {
              case 'updatedAt': 
                  const timeA = new Date(a.updatedAt).getTime();
                  const timeB = new Date(b.updatedAt).getTime();
                  return (timeA - timeB) * modifier;

              case 'project': 
                  if ((a.project || '') !== (b.project || '')) return (a.project || '').localeCompare(b.project || '') * modifier;
                  if ((a.macroprocess || '') !== (b.macroprocess || '')) return (a.macroprocess || '').localeCompare(b.macroprocess || '') * modifier;
                  if ((a.process || '') !== (b.process || '')) return (a.process || '').localeCompare(b.process || '') * modifier;
                  if ((a.microprocess || '') !== (b.microprocess || '')) return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
                  return (getDocTypeOrder(a.docType) - getDocTypeOrder(b.docType)) * modifier;

              case 'microprocess': return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
              case 'state': return (a.progress - b.progress) * modifier;
              default: return 0;
          }
      });
  }, [tableDocs, sortConfig]);

  // LÓGICA DE PAGINACIÓN
  const totalItems = sortedDocs.length;
  const totalPages = Math.ceil(totalItems / ITEMS_PER_PAGE);
  const paginatedDocs = useMemo(() => {
      const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
      return sortedDocs.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [sortedDocs, currentPage]);

  const handleExportExcel = () => {
      if (sortedDocs.length === 0) return;

      const getUserNames = (ids: string[]) => ids.map(id => allUsers.find(u => u.id === id)?.name || id).join('; ');

      const headers = [
          'Requerido', 
          'Proyecto', 
          'Macroproceso', 
          'Proceso', 
          'Microproceso', 
          'Tipo Documento', 
          'Estado', 
          'Versión', 
          'Avance %', 
          'Última Actividad', // Incluido como se solicitó
          'Analistas Responsables'
      ];

      const rows = sortedDocs.map(d => [
          d.isRequired ? 'SI' : 'NO',
          d.project || '-',
          d.macroprocess || '-',
          d.process || '-',
          d.microprocess || '-',
          d.docType || '-',
          STATE_CONFIG[d.state]?.label.split('(')[0] || '-',
          d.version || '-',
          `${d.progress}%`,
          d.state === DocState.NOT_STARTED ? 'Sin actividad' : new Date(d.updatedAt).toLocaleString('es-CL'),
          getUserNames(d.assignees || [])
      ]);

      const csvContent = [
          headers.join(','),
          ...rows.map(r => r.map(cell => `"${cell}"`).join(','))
      ].join('\n');

      // Bom para compatibilidad con Excel (UTF-8 con BOM)
      const blob = new Blob(["\ufeff", csvContent], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.setAttribute('href', url);
      link.setAttribute('download', `SGD_Export_${new Date().toISOString().split('T')[0]}.csv`);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
  };

  const chartData = [
    { name: 'No Iniciado', value: stats.notStarted, color: '#e2e8f0' },
    { name: 'En Proceso', value: stats.inProcess, color: '#3b82f6' },
    { name: 'Referente', value: stats.referent, color: '#a855f7' },
    { name: 'Control', value: stats.control, color: '#f97316' },
    { name: 'Finalizado', value: stats.finished, color: '#22c55e' },
  ].filter(d => d.value > 0);

  const handleSort = (key: SortKey) => {
      setSortConfig({ key, direction: sortConfig.key === key && sortConfig.direction === 'asc' ? 'desc' : 'asc' });
  };

  const handleQuickFilter = (type: QuickFilterType) => {
      setQuickFilter(quickFilter === type ? 'ALL' : type);
  };

  const clearFilters = () => {
      setFilterProject('');
      setFilterAnalyst('');
      setFilterMacro('');
      setFilterProcess('');
      setFilterSearch(''); 
      setFilterDocType('');
      setFilterState('');
      setQuickFilter('ALL');
      setExternalFilterIds(null); 
      navigate(location.pathname, { replace: true, state: {} });
  };

  const SortIcon = ({ column }: { column: SortKey }) => (
      sortConfig.key === column ? (sortConfig.direction === 'asc' ? <ArrowUp size={12} className="text-indigo-600"/> : <ArrowDown size={12} className="text-indigo-600"/>) : <ArrowUpDown size={12} className="opacity-30 group-hover:opacity-100"/>
  );

  const availableProjects = useMemo(() => Array.from(new Set(mergedDocs.map(d => d.project).filter(Boolean))).sort(), [mergedDocs]);
  const availableMacros = useMemo(() => {
      const docs = filterProject ? mergedDocs.filter(d => d.project === filterProject) : mergedDocs;
      return Array.from(new Set(docs.map(d => d.macroprocess).filter(Boolean))).sort();
  }, [mergedDocs, filterProject]);
  const availableProcesses = useMemo(() => {
      let docs = mergedDocs;
      if (filterProject) docs = docs.filter(d => d.project === filterProject);
      if (filterMacro) docs = docs.filter(d => d.macroprocess === filterMacro);
      return Array.from(new Set(docs.map(d => d.process).filter(Boolean))).sort();
  }, [mergedDocs, filterProject, filterMacro]);

  const getUserName = (id: string) => allUsers.find(user => user.id === id)?.name || 'Sin Asignar';

  if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Actualizando dashboard...</div>;

  if (isSystemEmpty) {
      return (
          <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6 bg-white rounded-xl shadow-sm border border-slate-200">
              <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center mb-6">
                  <Database size={40} className="text-indigo-600" />
              </div>
              <h2 className="text-2xl font-bold text-slate-900 mb-2">Sistema sin Inicializar</h2>
              <p className="text-slate-500 max-w-md mb-8">La matriz de procesos está vacía. Para visualizar el avance, es necesario cargar la estructura de procesos inicial.</p>
              {(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) ? (
                  <Link to="/admin/assignments" className="flex items-center px-6 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-medium shadow-md transition-transform active:scale-95">
                      <Database size={18} className="mr-2" /> Ir a Carga de Datos
                  </Link>
              ) : (
                  <div className="flex items-center gap-2 text-amber-600 bg-amber-50 px-4 py-2 rounded-lg border border-amber-100">
                      <AlertTriangle size={18} /> <span>Contacte al administrador para inicializar el sistema.</span>
                  </div>
              )}
          </div>
      );
  }

  const hasActiveFilters = filterProject || filterAnalyst || filterMacro || filterProcess || filterSearch || filterDocType || filterState || externalFilterIds;

  return (
    <div className="space-y-6 pb-12">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div><h1 className="text-2xl font-bold text-slate-900">Dashboard</h1><p className="text-slate-500">Vista general de avance institucional</p></div>
        <div className="flex items-center gap-2 w-full sm:w-auto">
            <button 
                onClick={handleExportExcel}
                className="flex-1 sm:flex-none px-4 py-2 bg-white border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 flex items-center justify-center shadow-sm font-medium transition-colors"
                title="Exportar listado completo filtrado a CSV/Excel"
            >
                <FileSpreadsheet size={18} className="mr-2 text-green-600"/> 
                <span className="hidden md:inline">Exportar Excel</span>
                <span className="md:hidden">Excel</span>
            </button>
            {user.role === UserRole.ANALYST && <Link to="/new" className="flex-1 sm:flex-none px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 flex items-center justify-center shadow-sm font-medium transition-transform active:scale-95"><Plus size={18} className="mr-2"/> Nueva Solicitud</Link>}
        </div>
      </div>

      {/* Tarjetas de Resumen */}
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-3">
        <StatCard title="Doc. Requeridos" value={stats.total} icon={BookOpen} color="bg-slate-50 text-slate-600 border-slate-200" onClick={() => handleQuickFilter('ALL')} isActive={quickFilter === 'ALL'}/>
        <StatCard title="No Iniciado" value={stats.notStarted} icon={Clock} color="bg-white text-slate-600 border-slate-200" onClick={() => handleQuickFilter('NOT_STARTED')} isActive={quickFilter === 'NOT_STARTED'}/>
        <StatCard title="En Proceso" value={stats.inProcess} icon={Activity} color="bg-blue-50 text-blue-600 border-blue-100" onClick={() => handleQuickFilter('IN_PROCESS')} isActive={quickFilter === 'IN_PROCESS'}/>
        <StatCard title="Referente" value={stats.referent} icon={Users} color="bg-purple-50 text-purple-600 border-purple-100" onClick={() => handleQuickFilter('REFERENT')} isActive={quickFilter === 'REFERENT'}/>
        <StatCard title="Control Gestión" value={stats.control} icon={ShieldCheck} color="bg-orange-50 text-orange-600 border-orange-100" onClick={() => handleQuickFilter('CONTROL')} isActive={quickFilter === 'CONTROL'}/>
        <StatCard title="Terminados" value={stats.finished} icon={CheckCircle} color="bg-green-50 text-green-600 border-green-100" onClick={() => handleQuickFilter('FINISHED')} isActive={quickFilter === 'FINISHED'}/>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        <div className="lg:col-span-3 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col min-h-[500px]">
            {/* Cabecera de filtros */}
            <div className="p-4 border-b border-slate-100 bg-white">
                <div className="flex items-center justify-between mb-3">
                    <div className="flex items-center gap-2 text-indigo-600 font-semibold text-sm"><Filter size={16} /> Filtros de Visualización</div>
                    {hasActiveFilters && (
                        <button onClick={clearFilters} className="text-xs text-red-500 hover:text-red-700 flex items-center gap-1 font-medium transition-colors">
                            <X size={14} /> Limpiar filtros
                        </button>
                    )}
                </div>
                {externalFilterIds ? (
                     <div className="bg-blue-50 border border-blue-100 p-3 rounded-lg mb-2 flex justify-between items-center animate-fadeIn">
                        <span className="text-xs text-blue-700 font-semibold">Filtro Activo: Visualizando {externalFilterIds.length} documentos específicos seleccionados desde reportes.</span>
                        <button onClick={clearFilters} className="text-xs bg-white border border-blue-200 px-2 py-1 rounded text-blue-600 hover:bg-blue-50 transition-colors">Mostrar Todo</button>
                     </div>
                ) : (
                    <div className="flex flex-wrap gap-3">
                        <select value={filterProject} onChange={(e) => setFilterProject(e.target.value)} className="text-xs p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500 w-32">
                            <option value="">Proyecto (Todos)</option>
                            {availableProjects.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                        <select value={filterMacro} onChange={(e) => setFilterMacro(e.target.value)} className="text-xs p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500 w-40">
                            <option value="">Macro (Todos)</option>
                            {availableMacros.map(m => <option key={m} value={m}>{m}</option>)}
                        </select>
                        <select value={filterProcess} onChange={(e) => setFilterProcess(e.target.value)} className="text-xs p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500 w-40">
                            <option value="">Proceso (Todos)</option>
                            {availableProcesses.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                        <div className="relative w-full sm:w-48">
                            <Search size={14} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400" />
                            <input type="text" value={filterSearch} onChange={(e) => setFilterSearch(e.target.value)} placeholder="Buscar microproceso..." className="w-full text-xs pl-8 p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500" />
                        </div>
                    </div>
                )}
            </div>

            {/* Tabla de Resultados */}
            <div className="overflow-x-auto flex-1">
                <table className="w-full text-xs text-left">
                    <thead className="text-[10px] text-slate-400 uppercase font-bold bg-white border-b border-slate-100">
                        <tr>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('project')}>PROYECTO <SortIcon column="project"/></th>
                            <th className="px-4 py-3">JERARQUÍA</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('microprocess')}>MICROPROCESO <SortIcon column="microprocess"/></th>
                            <th className="px-4 py-3">DOC</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('state')}>ESTADO <SortIcon column="state"/></th>
                            <th className="px-4 py-3 text-right cursor-pointer group" onClick={() => handleSort('updatedAt')}>ACTIVIDAD <SortIcon column="updatedAt"/></th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                        {paginatedDocs.length === 0 ? (
                            <tr><td colSpan={6} className="p-12 text-center text-slate-400 flex flex-col items-center justify-center min-h-[300px]"><Search size={40} className="mb-2 opacity-20"/><p>Sin resultados para la selección actual.</p></td></tr>
                        ) : paginatedDocs.map((doc, idx) => (
                            <tr key={`${doc.id}-${idx}`} className={`transition-colors ${!doc.isRequired ? 'bg-gray-100 hover:bg-gray-200' : 'hover:bg-slate-50'}`}>
                                <td className={`px-4 py-3 font-bold align-top ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.project}</td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`font-bold ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.macroprocess}</div>
                                    <div className="text-slate-500 text-[10px]">{doc.process}</div>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`font-bold mb-1 ${!doc.isRequired ? 'text-gray-600' : 'text-slate-800'}`}>{doc.microprocess}</div>
                                    <div className="flex items-center gap-1 text-slate-500" title="Analista Asignado">
                                        <UserIcon size={10} /> <span className="text-[10px] truncate max-w-[120px]">{doc.assignees && doc.assignees.length > 0 ? getUserName(doc.assignees[0]) : 'Sin Asignar'}</span>
                                    </div>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <span className={`inline-block px-1.5 py-0.5 rounded border text-[10px] font-bold mb-1 ${!doc.isRequired ? 'bg-gray-200 text-gray-500 border-gray-300' : 'bg-indigo-50 text-indigo-700 border-indigo-100'}`}>{doc.docType}</span>
                                    <Link to={`/doc/${doc.id}`} state={{ docData: doc }} className="flex items-center gap-1 text-[10px] font-bold text-indigo-500 hover:text-indigo-700">Ver <ArrowRight size={10}/></Link>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`inline-block px-2 py-0.5 rounded-full text-[10px] font-bold mb-1 border ${!doc.isRequired ? 'bg-gray-200 text-gray-500 border-gray-300' : STATE_CONFIG[doc.state].color}`}>{STATE_CONFIG[doc.state].label.split('(')[0]}</div>
                                    <div className="text-[10px] font-mono text-slate-500">v{doc.version} ({doc.progress}%)</div>
                                </td>
                                <td className="px-4 py-3 align-top text-right">
                                    {doc.state !== DocState.NOT_STARTED ? (
                                        <div className="text-slate-600 font-medium">{new Date(doc.updatedAt).toLocaleDateString()}</div>
                                    ) : <span className="text-slate-300">-</span>}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {/* CONTROLES DE PAGINACIÓN */}
            {totalItems > 0 && (
                <div className="px-4 py-3 border-t border-slate-100 bg-slate-50/50 flex flex-col sm:flex-row items-center justify-between gap-4">
                    <div className="text-xs text-slate-500 text-center sm:text-left">
                        Mostrando <span className="font-bold text-slate-700">{Math.min(totalItems, (currentPage - 1) * ITEMS_PER_PAGE + 1)}</span> a <span className="font-bold text-slate-700">{Math.min(totalItems, currentPage * ITEMS_PER_PAGE)}</span> de <span className="font-bold text-slate-700">{totalItems}</span> registros
                    </div>
                    <div className="flex items-center gap-2">
                        <button 
                            onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))}
                            disabled={currentPage === 1}
                            className="p-1.5 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-sm"
                            title="Anterior"
                        >
                            <ChevronLeft size={16} />
                        </button>

                        <div className="flex items-center gap-1">
                            {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                                // Lógica para mostrar páginas alrededor de la actual si hay muchas
                                let pageNum = i + 1;
                                if (totalPages > 5 && currentPage > 3) {
                                    pageNum = currentPage - 2 + i;
                                    if (pageNum > totalPages) pageNum = totalPages - (4 - i);
                                }
                                return (
                                    <button
                                        key={pageNum}
                                        onClick={() => setCurrentPage(pageNum)}
                                        className={`w-8 h-8 rounded-lg text-xs font-bold transition-all border shadow-sm ${currentPage === pageNum ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white text-slate-600 border-slate-200 hover:border-indigo-400'}`}
                                    >
                                        {pageNum}
                                    </button>
                                );
                            })}
                        </div>

                        <button 
                            onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))}
                            disabled={currentPage === totalPages}
                            className="p-1.5 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-sm"
                            title="Siguiente"
                        >
                            <ChevronRight size={16} />
                        </button>
                    </div>
                </div>
            )}
        </div>

        <div className="lg:col-span-1 space-y-6">
            {/* Gráfico de Avance */}
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4 min-h-[250px] flex flex-col items-center justify-center">
                <h3 className="font-bold text-center mb-2 text-slate-700 text-sm">Estado (Requeridos)</h3>
                {chartData.length > 0 ? (
                    <div className="h-48 w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie data={chartData} cx="50%" cy="50%" innerRadius={50} outerRadius={70} paddingAngle={2} dataKey="value">
                                    {chartData.map((e, i) => <Cell key={i} fill={e.color}/>)}
                                </Pie>
                                <Tooltip contentStyle={{fontSize: '12px', borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}}/>
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                ) : <p className="text-center text-slate-400 text-xs">Sin datos para graficar.</p>}
                <div className="flex flex-wrap justify-center gap-2 mt-2">
                    {chartData.map((d, i) => (
                        <div key={i} className="flex items-center gap-1">
                            <span className="w-2 h-2 rounded-full" style={{backgroundColor: d.color}}></span>
                            <span className="text-[10px] text-slate-500">{d.name}</span>
                        </div>
                    ))}
                </div>
            </div>

            {/* Resumen de Cumplimiento */}
            <div className="bg-indigo-50 rounded-xl shadow-sm border border-indigo-100 p-4">
                <h3 className="font-bold text-indigo-900 text-sm mb-3">Resumen de Cumplimiento</h3>
                <ul className="space-y-2 text-xs">
                    <li className="border-t border-indigo-200 pt-1 flex justify-between text-slate-600"><span>No Iniciados:</span> <span>{stats.notStarted}</span></li>
                    <li className="flex justify-between text-blue-600 font-medium"><span>En Proceso:</span> <span>{stats.inProcess}</span></li>
                    <li className="flex justify-between text-purple-600 font-medium"><span>Referente:</span> <span>{stats.referent}</span></li>
                    <li className="flex justify-between text-orange-600 font-medium"><span>Control Gestión:</span> <span>{stats.control}</span></li>
                    <li className="border-t border-indigo-200 pt-1 flex justify-between text-green-600 font-bold"><span>Terminados:</span> <span>{stats.finished}</span></li>
                </ul>
                <div className="mt-4 pt-3 border-t border-indigo-200 text-[10px] text-slate-500 flex items-center gap-2"><Archive size={12} /><span>Registros en <span className="font-bold text-gray-500">GRIS</span> son históricos externos a la matriz.</span></div>
            </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon: Icon, color, isActive, onClick }: any) => (
    <div onClick={onClick} className={`p-3 rounded-xl shadow-sm border cursor-pointer flex items-center space-x-3 transition-all ${isActive ? 'ring-2 ring-indigo-200 scale-105' : 'hover:border-indigo-300'} ${color}`}>
        <div className="p-1.5 bg-white/50 rounded-lg shrink-0"><Icon size={18}/></div>
        <div className="min-w-0">
            <p className="text-[9px] uppercase font-bold opacity-70 truncate">{title}</p>
            <p className="text-lg font-bold leading-none">{value}</p>
        </div>
    </div>
);

export default Dashboard;

import React, { useEffect, useState, useMemo } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService } from '../services/firebaseBackend';
import { Document, User, UserRole, DocState, DocType, FullHierarchy } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    Plus, Clock, CheckCircle, Filter, X, Calendar, ArrowRight, Activity, 
    BookOpen, Users, ShieldCheck, ArrowUp, ArrowDown, ArrowUpDown, Loader2,
    User as UserIcon, Database, AlertTriangle, Archive, PlayCircle, Search,
    ChevronLeft, ChevronRight, FileSpreadsheet
} from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

interface DashboardProps {
  user: User;
}

// Extend Document interface locally to handle the "Required" flag for the Dashboard view
interface DashboardDoc extends Document {
    isRequired: boolean; // True if it matches the Matrix, False if it's an extra historical doc
}

type SortKey = 'project' | 'microprocess' | 'state' | 'updatedAt';
type QuickFilterType = 'ALL' | 'NOT_STARTED' | 'IN_PROCESS' | 'REFERENT' | 'CONTROL' | 'FINISHED';

// Configuración de paginación
const ITEMS_PER_PAGE = 10;

// Helper to order DocTypes logically
const getDocTypeOrder = (type: string | undefined): number => {
    switch (type) {
        case 'AS IS': return 1;
        case 'FCE': return 2;
        case 'PM': return 3;
        case 'TO BE': return 4;
        default: return 99;
    }
};

const Dashboard: React.FC<DashboardProps> = ({ user }) => {
  const navigate = useNavigate();
  const location = useLocation(); 

  const [mergedDocs, setMergedDocs] = useState<DashboardDoc[]>([]);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSystemEmpty, setIsSystemEmpty] = useState(false);

  // Filters State
  const [filterProject, setFilterProject] = useState('');
  const [filterAnalyst, setFilterAnalyst] = useState('');
  const [filterMacro, setFilterMacro] = useState('');
  const [filterProcess, setFilterProcess] = useState('');
  const [filterSearch, setFilterSearch] = useState(''); 
  const [filterDocType, setFilterDocType] = useState('');
  const [filterState, setFilterState] = useState(''); 

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);

  // External Filter (From Reports)
  const [externalFilterIds, setExternalFilterIds] = useState<string[] | null>(null);

  // Quick Stats Filter (Cards)
  const [quickFilter, setQuickFilter] = useState<QuickFilterType>('ALL');

  const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: 'asc' | 'desc' }>({
    key: 'project', 
    direction: 'asc'
  });

  useEffect(() => {
    if (location.state?.filterIds && Array.isArray(location.state.filterIds)) {
        setExternalFilterIds(location.state.filterIds);
        setQuickFilter('ALL');
    } else {
        setExternalFilterIds(null);
    }
    loadData();
  }, [location.state]);

  // Reiniciar a la página 1 cuando cambian los filtros o el orden
  useEffect(() => {
    setCurrentPage(1);
  }, [filterProject, filterAnalyst, filterMacro, filterProcess, filterSearch, filterDocType, filterState, quickFilter, sortConfig]);

  const normalize = (str: string | undefined) => {
      if (!str) return '';
      return str.trim().toUpperCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  };

  const loadData = async () => {
    setLoading(true);
    try {
        const [realDocsData, users, fullHierarchy] = await Promise.all([
            DocumentService.getAll(),
            UserService.getAll(),
            HierarchyService.getFullHierarchy()
        ]);

        setAllUsers(users);

        const hierarchyKeys = Object.keys(fullHierarchy);

        if (hierarchyKeys.length === 0 && realDocsData.length === 0) {
            setIsSystemEmpty(true);
            setMergedDocs([]);
            setLoading(false);
            return;
        }
        setIsSystemEmpty(false);

        const realDocMap = new Map<string, Document>();
        const processedDocIds = new Set<string>();

        realDocsData.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalize(doc.project)}|${normalize(microName)}|${normalize(docType)}`;

                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        const finalDocsList: DashboardDoc[] = [];

        hierarchyKeys.forEach(proj => {
            Object.keys(fullHierarchy[proj]).forEach(macro => {
                Object.keys(fullHierarchy[proj][macro]).forEach(proc => {
                    const nodes = fullHierarchy[proj][macro][proc];
                    nodes.forEach(node => {
                        if (node.active === false) return; 

                        const requiredTypes = (node.requiredTypes && node.requiredTypes.length > 0) 
                            ? node.requiredTypes 
                            : ['AS IS', 'FCE', 'PM', 'TO BE'];

                        requiredTypes.forEach(type => {
                            const key = `${normalize(proj)}|${normalize(node.name)}|${normalize(type)}`;

                            if (realDocMap.has(key)) {
                                const realDoc = realDocMap.get(key)!;
                                finalDocsList.push({
                                    ...realDoc,
                                    macroprocess: macro,
                                    process: proc,
                                    project: proj,
                                    assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []),
                                    isRequired: true 
                                });
                                processedDocIds.add(realDoc.id); 
                            } else {
                                finalDocsList.push({
                                    id: `virtual-${key}`, 
                                    title: `${node.name} - ${type}`,
                                    description: 'Pendiente de inicio',
                                    project: proj,
                                    macroprocess: macro,
                                    process: proc,
                                    microprocess: node.name,
                                    docType: type as DocType,
                                    authorId: '',
                                    authorName: '',
                                    assignedTo: node.assignees?.[0] || '',
                                    assignees: node.assignees || [],
                                    state: DocState.NOT_STARTED,
                                    version: '-',
                                    progress: 0,
                                    files: [],
                                    createdAt: new Date().toISOString(),
                                    updatedAt: new Date(0).toISOString(), 
                                    hasPendingRequest: false,
                                    isRequired: true 
                                });
                            }
                        });
                    });
                });
            });
        });

        realDocMap.forEach((doc) => {
            if (!processedDocIds.has(doc.id)) {
                finalDocsList.push({
                    ...doc,
                    macroprocess: doc.macroprocess || 'Sin Clasificar',
                    process: doc.process || 'Sin Clasificar',
                    isRequired: false 
                });
            }
        });

        setMergedDocs(finalDocsList);

    } catch (error) {
        console.error("Error loading dashboard data:", error);
    } finally {
        setLoading(false);
    }
  };

  const contextDocs = useMemo(() => {
      let filtered = mergedDocs;

      if (externalFilterIds && externalFilterIds.length > 0) {
          filtered = filtered.filter(d => externalFilterIds.includes(d.id));
      } else {
          if (filterProject) filtered = filtered.filter(d => d.project === filterProject);
          if (filterAnalyst) filtered = filtered.filter(d => d.assignees && d.assignees.includes(filterAnalyst));
          if (filterMacro) filtered = filtered.filter(d => d.macroprocess === filterMacro);
          if (filterProcess) filtered = filtered.filter(d => d.process === filterProcess);
          if (filterDocType) filtered = filtered.filter(d => d.docType === filterDocType);
          if (filterState) filtered = filtered.filter(d => d.state === filterState);

          if (filterSearch) {
              const term = filterSearch.toLowerCase();
              filtered = filtered.filter(d => 
                  (d.microprocess || '').toLowerCase().includes(term) || 
                  (d.title || '').toLowerCase().includes(term)
              );
          }
      }

      return filtered;
  }, [mergedDocs, filterProject, filterAnalyst, filterMacro, filterProcess, filterDocType, filterState, filterSearch, externalFilterIds]);

  const stats = useMemo(() => {
      const requiredDocs = contextDocs.filter(d => d.isRequired);

      return {
        total: requiredDocs.length,
        notStarted: requiredDocs.filter(d => d.state === DocState.NOT_STARTED).length,
        inProcess: requiredDocs.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW).length,
        referent: requiredDocs.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW).length,
        control: requiredDocs.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW).length,
        finished: requiredDocs.filter(d => d.state === DocState.APPROVED).length
      };
  }, [contextDocs]);

  const tableDocs = useMemo(() => {
      let filtered = contextDocs;

      if (quickFilter !== 'ALL') {
          switch (quickFilter) {
              case 'NOT_STARTED': filtered = filtered.filter(d => d.state === DocState.NOT_STARTED); break;
              case 'IN_PROCESS': filtered = filtered.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW); break;
              case 'REFERENT': filtered = filtered.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW); break;
              case 'CONTROL': filtered = filtered.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW); break;
              case 'FINISHED': filtered = filtered.filter(d => d.state === DocState.APPROVED); break;
          }
      }
      return filtered;
  }, [contextDocs, quickFilter]);

  const sortedDocs = useMemo(() => {
      return [...tableDocs].sort((a, b) => {
          if (a.isRequired !== b.isRequired) {
              return a.isRequired ? -1 : 1;
          }

          const modifier = sortConfig.direction === 'asc' ? 1 : -1;

          switch (sortConfig.key) {
              case 'updatedAt': 
                  const timeA = new Date(a.updatedAt).getTime();
                  const timeB = new Date(b.updatedAt).getTime();
                  return (timeA - timeB) * modifier;

              case 'project': 
                  if ((a.project || '') !== (b.project || '')) return (a.project || '').localeCompare(b.project || '') * modifier;
                  if ((a.macroprocess || '') !== (b.macroprocess || '')) return (a.macroprocess || '').localeCompare(b.macroprocess || '') * modifier;
                  if ((a.process || '') !== (b.process || '')) return (a.process || '').localeCompare(b.process || '') * modifier;
                  if ((a.microprocess || '') !== (b.microprocess || '')) return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
                  return (getDocTypeOrder(a.docType) - getDocTypeOrder(b.docType)) * modifier;

              case 'microprocess': return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
              case 'state': return (a.progress - b.progress) * modifier;
              default: return 0;
          }
      });
  }, [tableDocs, sortConfig]);

  // LÓGICA DE PAGINACIÓN
  const totalItems = sortedDocs.length;
  const totalPages = Math.ceil(totalItems / ITEMS_PER_PAGE);
  const paginatedDocs = useMemo(() => {
      const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
      return sortedDocs.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [sortedDocs, currentPage]);

  const handleExportExcel = () => {
      if (sortedDocs.length === 0) return;

      const getUserNames = (ids: string[]) => ids.map(id => allUsers.find(u => u.id === id)?.name || id).join('; ');

      // Orden exacto solicitado: PROYECTO, MACROPROCESO, PROCESO, MICROPROCESO, ANALISTA, DOCUMENTO, VERSION, ESTADO, FECHA
      const headers = [
          'PROYECTO', 
          'MACROPROCESO', 
          'PROCESO', 
          'MICROPROCESO', 
          'ANALISTA', 
          'DOCUMENTO', 
          'VERSION',
          'ESTADO', 
          'FECHA'
      ];

      const rows = sortedDocs.map(d => [
          d.project || '-',
          d.macroprocess || '-',
          d.process || '-',
          d.microprocess || '-',
          getUserNames(d.assignees || []),
          d.docType || '-',
          d.version || '-',
          STATE_CONFIG[d.state]?.label.split('(')[0] || '-',
          d.state === DocState.NOT_STARTED ? 'Sin actividad' : new Date(d.updatedAt).toLocaleString('es-CL')
      ]);

      // Generar contenido CSV usando punto y coma (;) como separador para mejor compatibilidad con Excel en español
      const csvContent = [
          headers.join(';'),
          ...rows.map(r => r.map(cell => `"${cell}"`).join(';'))
      ].join('\n');

      // PREPEND UTF-8 BOM (\ufeff) para asegurar que Excel reconozca los acentos y caracteres especiales
      const blob = new Blob(["\ufeff", csvContent], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.setAttribute('href', url);
      link.setAttribute('download', `SGD_Reporte_${new Date().toISOString().split('T')[0]}.csv`);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
  };

  const chartData = [
    { name: 'No Iniciado', value: stats.notStarted, color: '#e2e8f0' },
    { name: 'En Proceso', value: stats.inProcess, color: '#3b82f6' },
    { name: 'Referente', value: stats.referent, color: '#a855f7' },
    { name: 'Control', value: stats.control, color: '#f97316' },
    { name: 'Finalizado', value: stats.finished, color: '#22c55e' },
  ].filter(d => d.value > 0);

  const handleSort = (key: SortKey) => {
      setSortConfig({ key, direction: sortConfig.key === key && sortConfig.direction === 'asc' ? 'desc' : 'asc' });
  };

  const handleQuickFilter = (type: QuickFilterType) => {
      setQuickFilter(quickFilter === type ? 'ALL' : type);
  };

  const clearFilters = () => {
      setFilterProject('');
      setFilterAnalyst('');
      setFilterMacro('');
      setFilterProcess('');
      setFilterSearch(''); 
      setFilterDocType('');
      setFilterState('');
      setQuickFilter('ALL');
      setExternalFilterIds(null); 
      navigate(location.pathname, { replace: true, state: {} });
  };

  const SortIcon = ({ column }: { column: SortKey }) => (
      sortConfig.key === column ? (sortConfig.direction === 'asc' ? <ArrowUp size={12} className="text-indigo-600"/> : <ArrowDown size={12} className="text-indigo-600"/>) : <ArrowUpDown size={12} className="opacity-30 group-hover:opacity-100"/>
  );

  const availableProjects = useMemo(() => Array.from(new Set(mergedDocs.map(d => d.project).filter(Boolean))).sort(), [mergedDocs]);
  const availableMacros = useMemo(() => {
      const docs = filterProject ? mergedDocs.filter(d => d.project === filterProject) : mergedDocs;
      return Array.from(new Set(docs.map(d => d.macroprocess).filter(Boolean))).sort();
  }, [mergedDocs, filterProject]);
  const availableProcesses = useMemo(() => {
      let docs = mergedDocs;
      if (filterProject) docs = docs.filter(d => d.project === filterProject);
      if (filterMacro) docs = docs.filter(d => d.macroprocess === filterMacro);
      return Array.from(new Set(docs.map(d => d.process).filter(Boolean))).sort();
  }, [mergedDocs, filterProject, filterMacro]);

  const getUserName = (id: string) => allUsers.find(user => user.id === id)?.name || 'Sin Asignar';

  if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Actualizando dashboard...</div>;

  if (isSystemEmpty) {
      return (
          <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6 bg-white rounded-xl shadow-sm border border-slate-200">
              <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center mb-6">
                  <Database size={40} className="text-indigo-600" />
              </div>
              <h2 className="text-2xl font-bold text-slate-900 mb-2">Sistema sin Inicializar</h2>
              <p className="text-slate-500 max-w-md mb-8">La matriz de procesos está vacía. Para visualizar el avance, es necesario cargar la estructura de procesos inicial.</p>
              {(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) ? (
                  <Link to="/admin/assignments" className="flex items-center px-6 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-medium shadow-md transition-transform active:scale-95">
                      <Database size={18} className="mr-2" /> Ir a Carga de Datos
                  </Link>
              ) : (
                  <div className="flex items-center gap-2 text-amber-600 bg-amber-50 px-4 py-2 rounded-lg border border-amber-100">
                      <AlertTriangle size={18} /> <span>Contacte al administrador para inicializar el sistema.</span>
                  </div>
              )}
          </div>
      );
  }

  const hasActiveFilters = filterProject || filterAnalyst || filterMacro || filterProcess || filterSearch || filterDocType || filterState || externalFilterIds;

  return (
    <div className="space-y-6 pb-12">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div><h1 className="text-2xl font-bold text-slate-900">Dashboard</h1><p className="text-slate-500">Vista general de avance institucional</p></div>
        <div className="flex items-center gap-2 w-full sm:w-auto">
            <button 
                onClick={handleExportExcel}
                className="flex-1 sm:flex-none px-4 py-2 bg-white border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 flex items-center justify-center shadow-sm font-medium transition-colors"
                title="Exportar listado completo filtrado a CSV/Excel con acentos"
            >
                <FileSpreadsheet size={18} className="mr-2 text-green-600"/> 
                <span className="hidden md:inline">Exportar Excel</span>
                <span className="md:hidden">Excel</span>
            </button>
            {user.role === UserRole.ANALYST && <Link to="/new" className="flex-1 sm:flex-none px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 flex items-center justify-center shadow-sm font-medium transition-transform active:scale-95"><Plus size={18} className="mr-2"/> Nueva Solicitud</Link>}
        </div>
      </div>

      {/* Tarjetas de Resumen */}
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-3">
        <StatCard title="Doc. Requeridos" value={stats.total} icon={BookOpen} color="bg-slate-50 text-slate-600 border-slate-200" onClick={() => handleQuickFilter('ALL')} isActive={quickFilter === 'ALL'}/>
        <StatCard title="No Iniciado" value={stats.notStarted} icon={Clock} color="bg-white text-slate-600 border-slate-200" onClick={() => handleQuickFilter('NOT_STARTED')} isActive={quickFilter === 'NOT_STARTED'}/>
        <StatCard title="En Proceso" value={stats.inProcess} icon={Activity} color="bg-blue-50 text-blue-600 border-blue-100" onClick={() => handleQuickFilter('IN_PROCESS')} isActive={quickFilter === 'IN_PROCESS'}/>
        <StatCard title="Referente" value={stats.referent} icon={Users} color="bg-purple-50 text-purple-600 border-purple-100" onClick={() => handleQuickFilter('REFERENT')} isActive={quickFilter === 'REFERENT'}/>
        <StatCard title="Control Gestión" value={stats.control} icon={ShieldCheck} color="bg-orange-50 text-orange-600 border-orange-100" onClick={() => handleQuickFilter('CONTROL')} isActive={quickFilter === 'CONTROL'}/>
        <StatCard title="Terminados" value={stats.finished} icon={CheckCircle} color="bg-green-50 text-green-600 border-green-100" onClick={() => handleQuickFilter('FINISHED')} isActive={quickFilter === 'FINISHED'}/>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        <div className="lg:col-span-3 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col min-h-[500px]">
            {/* Cabecera de filtros */}
            <div className="p-4 border-b border-slate-100 bg-white">
                <div className="flex items-center justify-between mb-3">
                    <div className="flex items-center gap-2 text-indigo-600 font-semibold text-sm"><Filter size={16} /> Filtros de Visualización</div>
                    {hasActiveFilters && (
                        <button onClick={clearFilters} className="text-xs text-red-500 hover:text-red-700 flex items-center gap-1 font-medium transition-colors">
                            <X size={14} /> Limpiar filtros
                        </button>
                    )}
                </div>
                {externalFilterIds ? (
                     <div className="bg-blue-50 border border-blue-100 p-3 rounded-lg mb-2 flex justify-between items-center animate-fadeIn">
                        <span className="text-xs text-blue-700 font-semibold">Filtro Activo: Visualizando {externalFilterIds.length} documentos específicos seleccionados desde reportes.</span>
                        <button onClick={clearFilters} className="text-xs bg-white border border-blue-200 px-2 py-1 rounded text-blue-600 hover:bg-blue-50 transition-colors">Mostrar Todo</button>
                     </div>
                ) : (
                    <div className="flex flex-wrap gap-3">
                        <select value={filterProject} onChange={(e) => setFilterProject(e.target.value)} className="text-xs p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500 w-32">
                            <option value="">Proyecto (Todos)</option>
                            {availableProjects.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                        <select value={filterMacro} onChange={(e) => setFilterMacro(e.target.value)} className="text-xs p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500 w-40">
                            <option value="">Macro (Todos)</option>
                            {availableMacros.map(m => <option key={m} value={m}>{m}</option>)}
                        </select>
                        <select value={filterProcess} onChange={(e) => setFilterProcess(e.target.value)} className="text-xs p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500 w-40">
                            <option value="">Proceso (Todos)</option>
                            {availableProcesses.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                        <div className="relative w-full sm:w-48">
                            <Search size={14} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400" />
                            <input type="text" value={filterSearch} onChange={(e) => setFilterSearch(e.target.value)} placeholder="Buscar microproceso..." className="w-full text-xs pl-8 p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500" />
                        </div>
                    </div>
                )}
            </div>

            {/* Tabla de Resultados */}
            <div className="overflow-x-auto flex-1">
                <table className="w-full text-xs text-left">
                    <thead className="text-[10px] text-slate-400 uppercase font-bold bg-white border-b border-slate-100">
                        <tr>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('project')}>PROYECTO <SortIcon column="project"/></th>
                            <th className="px-4 py-3">JERARQUÍA</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('microprocess')}>MICROPROCESO <SortIcon column="microprocess"/></th>
                            <th className="px-4 py-3">DOC</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('state')}>ESTADO <SortIcon column="state"/></th>
                            <th className="px-4 py-3 text-right cursor-pointer group" onClick={() => handleSort('updatedAt')}>ACTIVIDAD <SortIcon column="updatedAt"/></th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                        {paginatedDocs.length === 0 ? (
                            <tr><td colSpan={6} className="p-12 text-center text-slate-400 flex flex-col items-center justify-center min-h-[300px]"><Search size={40} className="mb-2 opacity-20"/><p>Sin resultados para la selección actual.</p></td></tr>
                        ) : paginatedDocs.map((doc, idx) => (
                            <tr key={`${doc.id}-${idx}`} className={`transition-colors ${!doc.isRequired ? 'bg-gray-100 hover:bg-gray-200' : 'hover:bg-slate-50'}`}>
                                <td className={`px-4 py-3 font-bold align-top ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.project}</td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`font-bold ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.macroprocess}</div>
                                    <div className="text-slate-500 text-[10px]">{doc.process}</div>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`font-bold mb-1 ${!doc.isRequired ? 'text-gray-600' : 'text-slate-800'}`}>{doc.microprocess}</div>
                                    <div className="flex items-center gap-1 text-slate-500" title="Analista Asignado">
                                        <UserIcon size={10} /> <span className="text-[10px] truncate max-w-[120px]">{doc.assignees && doc.assignees.length > 0 ? getUserName(doc.assignees[0]) : 'Sin Asignar'}</span>
                                    </div>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <span className={`inline-block px-1.5 py-0.5 rounded border text-[10px] font-bold mb-1 ${!doc.isRequired ? 'bg-gray-200 text-gray-500 border-gray-300' : 'bg-indigo-50 text-indigo-700 border-indigo-100'}`}>{doc.docType}</span>
                                    <Link to={`/doc/${doc.id}`} state={{ docData: doc }} className="flex items-center gap-1 text-[10px] font-bold text-indigo-500 hover:text-indigo-700">Ver <ArrowRight size={10}/></Link>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`inline-block px-2 py-0.5 rounded-full text-[10px] font-bold mb-1 border ${!doc.isRequired ? 'bg-gray-200 text-gray-500 border-gray-300' : STATE_CONFIG[doc.state].color}`}>{STATE_CONFIG[doc.state].label.split('(')[0]}</div>
                                    <div className="text-[10px] font-mono text-slate-500">v{doc.version} ({doc.progress}%)</div>
                                </td>
                                <td className="px-4 py-3 align-top text-right">
                                    {doc.state !== DocState.NOT_STARTED ? (
                                        <div className="text-slate-600 font-medium">{new Date(doc.updatedAt).toLocaleDateString()}</div>
                                    ) : <span className="text-slate-300">-</span>}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {/* CONTROLES DE PAGINACIÓN */}
            {totalItems > 0 && (
                <div className="px-4 py-3 border-t border-slate-100 bg-slate-50/50 flex flex-col sm:flex-row items-center justify-between gap-4">
                    <div className="text-xs text-slate-500 text-center sm:text-left">
                        Mostrando <span className="font-bold text-slate-700">{Math.min(totalItems, (currentPage - 1) * ITEMS_PER_PAGE + 1)}</span> a <span className="font-bold text-slate-700">{Math.min(totalItems, currentPage * ITEMS_PER_PAGE)}</span> de <span className="font-bold text-slate-700">{totalItems}</span> registros
                    </div>
                    <div className="flex items-center gap-2">
                        <button 
                            onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))}
                            disabled={currentPage === 1}
                            className="p-1.5 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-sm"
                            title="Anterior"
                        >
                            <ChevronLeft size={16} />
                        </button>

                        <div className="flex items-center gap-1">
                            {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                                // Lógica para mostrar páginas alrededor de la actual si hay muchas
                                let pageNum = i + 1;
                                if (totalPages > 5 && currentPage > 3) {
                                    pageNum = currentPage - 2 + i;
                                    if (pageNum > totalPages) pageNum = totalPages - (4 - i);
                                }
                                return (
                                    <button
                                        key={pageNum}
                                        onClick={() => setCurrentPage(pageNum)}
                                        className={`w-8 h-8 rounded-lg text-xs font-bold transition-all border shadow-sm ${currentPage === pageNum ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white text-slate-600 border-slate-200 hover:border-indigo-400'}`}
                                    >
                                        {pageNum}
                                    </button>
                                );
                            })}
                        </div>

                        <button 
                            onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))}
                            disabled={currentPage === totalPages}
                            className="p-1.5 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-sm"
                            title="Siguiente"
                        >
                            <ChevronRight size={16} />
                        </button>
                    </div>
                </div>
            )}
        </div>

        <div className="lg:col-span-1 space-y-6">
            {/* Gráfico de Avance */}
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4 min-h-[250px] flex flex-col items-center justify-center">
                <h3 className="font-bold text-center mb-2 text-slate-700 text-sm">Estado (Requeridos)</h3>
                {chartData.length > 0 ? (
                    <div className="h-48 w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie data={chartData} cx="50%" cy="50%" innerRadius={50} outerRadius={70} paddingAngle={2} dataKey="value">
                                    {chartData.map((e, i) => <Cell key={i} fill={e.color}/>)}
                                </Pie>
                                <Tooltip contentStyle={{fontSize: '12px', borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}}/>
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                ) : <p className="text-center text-slate-400 text-xs">Sin datos para graficar.</p>}
                <div className="flex flex-wrap justify-center gap-2 mt-2">
                    {chartData.map((d, i) => (
                        <div key={i} className="flex items-center gap-1">
                            <span className="w-2 h-2 rounded-full" style={{backgroundColor: d.color}}></span>
                            <span className="text-[10px] text-slate-500">{d.name}</span>
                        </div>
                    ))}
                </div>
            </div>

            {/* Resumen de Cumplimiento */}
            <div className="bg-indigo-50 rounded-xl shadow-sm border border-indigo-100 p-4">
                <h3 className="font-bold text-indigo-900 text-sm mb-3">Resumen de Cumplimiento</h3>
                <ul className="space-y-2 text-xs">
                    <li className="border-t border-indigo-200 pt-1 flex justify-between text-slate-600"><span>No Iniciados:</span> <span>{stats.notStarted}</span></li>
                    <li className="flex justify-between text-blue-600 font-medium"><span>En Proceso:</span> <span>{stats.inProcess}</span></li>
                    <li className="flex justify-between text-purple-600 font-medium"><span>Referente:</span> <span>{stats.referent}</span></li>
                    <li className="flex justify-between text-orange-600 font-medium"><span>Control Gestión:</span> <span>{stats.control}</span></li>
                    <li className="border-t border-indigo-200 pt-1 flex justify-between text-green-600 font-bold"><span>Terminados:</span> <span>{stats.finished}</span></li>
                </ul>
                <div className="mt-4 pt-3 border-t border-indigo-200 text-[10px] text-slate-500 flex items-center gap-2"><Archive size={12} /><span>Registros en <span className="font-bold text-gray-500">GRIS</span> son históricos externos a la matriz.</span></div>
            </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon: Icon, color, isActive, onClick }: any) => (
    <div onClick={onClick} className={`p-3 rounded-xl shadow-sm border cursor-pointer flex items-center space-x-3 transition-all ${isActive ? 'ring-2 ring-indigo-200 scale-105' : 'hover:border-indigo-300'} ${color}`}>
        <div className="p-1.5 bg-white/50 rounded-lg shrink-0"><Icon size={18}/></div>
        <div className="min-w-0">
            <p className="text-[9px] uppercase font-bold opacity-70 truncate">{title}</p>
            <p className="text-lg font-bold leading-none">{value}</p>
        </div>
    </div>
);

export default Dashboard;

import React, { useEffect, useState, useMemo } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService } from '../services/firebaseBackend';
import { Document, User, UserRole, DocState, DocType, FullHierarchy } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    Plus, Clock, CheckCircle, Filter, X, Calendar, ArrowRight, Activity, 
    BookOpen, Users, ShieldCheck, ArrowUp, ArrowDown, ArrowUpDown, Loader2,
    User as UserIcon, Database, AlertTriangle, Archive, PlayCircle, Search,
    ChevronLeft, ChevronRight, FileSpreadsheet
} from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

interface DashboardProps {
  user: User;
}

interface DashboardDoc extends Document {
    isRequired: boolean;
}

type SortKey = 'project' | 'microprocess' | 'state' | 'updatedAt';
type QuickFilterType = 'ALL' | 'NOT_STARTED' | 'IN_PROCESS' | 'REFERENT' | 'CONTROL' | 'FINISHED';

const ITEMS_PER_PAGE = 10;

const getDocTypeOrder = (type: string | undefined): number => {
    switch (type) {
        case 'AS IS': return 1;
        case 'FCE': return 2;
        case 'PM': return 3;
        case 'TO BE': return 4;
        default: return 99;
    }
};

const Dashboard: React.FC<DashboardProps> = ({ user }) => {
  const navigate = useNavigate();
  const location = useLocation(); 

  const [mergedDocs, setMergedDocs] = useState<DashboardDoc[]>([]);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSystemEmpty, setIsSystemEmpty] = useState(false);

  // Filtros de Estado
  const [filterProject, setFilterProject] = useState('');
  const [filterMacro, setFilterMacro] = useState('');
  const [filterProcess, setFilterProcess] = useState('');
  const [filterSearch, setFilterSearch] = useState(''); 
  const [filterDocType, setFilterDocType] = useState('');
  const [filterState, setFilterState] = useState(''); 
  const [filterAnalyst, setFilterAnalyst] = useState('');

  // Paginación
  const [currentPage, setCurrentPage] = useState(1);
  const [externalFilterIds, setExternalFilterIds] = useState<string[] | null>(null);
  const [quickFilter, setQuickFilter] = useState<QuickFilterType>('ALL');

  const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: 'asc' | 'desc' }>({
    key: 'project', 
    direction: 'asc'
  });

  useEffect(() => {
    if (location.state?.filterIds && Array.isArray(location.state.filterIds)) {
        setExternalFilterIds(location.state.filterIds);
        setQuickFilter('ALL');
    } else {
        setExternalFilterIds(null);
    }
    loadData();
  }, [location.state]);

  useEffect(() => {
    setCurrentPage(1);
  }, [filterProject, filterMacro, filterProcess, filterSearch, filterDocType, filterState, filterAnalyst, quickFilter, sortConfig]);

  const normalize = (str: string | undefined) => {
      if (!str) return '';
      return str.trim().toUpperCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  };

  const loadData = async () => {
    setLoading(true);
    try {
        const [realDocsData, users, fullHierarchy] = await Promise.all([
            DocumentService.getAll(),
            UserService.getAll(),
            HierarchyService.getFullHierarchy()
        ]);

        setAllUsers(users);
        const hierarchyKeys = Object.keys(fullHierarchy);

        if (hierarchyKeys.length === 0 && realDocsData.length === 0) {
            setIsSystemEmpty(true);
            setMergedDocs([]);
            setLoading(false);
            return;
        }
        setIsSystemEmpty(false);

        const realDocMap = new Map<string, Document>();
        const processedDocIds = new Set<string>();

        realDocsData.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalize(doc.project)}|${normalize(microName)}|${normalize(docType)}`;

                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        const finalDocsList: DashboardDoc[] = [];

        hierarchyKeys.forEach(proj => {
            Object.keys(fullHierarchy[proj]).forEach(macro => {
                Object.keys(fullHierarchy[proj][macro]).forEach(proc => {
                    const nodes = fullHierarchy[proj][macro][proc];
                    nodes.forEach(node => {
                        if (node.active === false) return; 

                        const requiredTypes = (node.requiredTypes && node.requiredTypes.length > 0) 
                            ? node.requiredTypes 
                            : ['AS IS', 'FCE', 'PM', 'TO BE'];

                        requiredTypes.forEach(type => {
                            const key = `${normalize(proj)}|${normalize(node.name)}|${normalize(type)}`;

                            if (realDocMap.has(key)) {
                                const realDoc = realDocMap.get(key)!;
                                finalDocsList.push({
                                    ...realDoc,
                                    macroprocess: macro,
                                    process: proc,
                                    project: proj,
                                    assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []),
                                    isRequired: true 
                                });
                                processedDocIds.add(realDoc.id); 
                            } else {
                                finalDocsList.push({
                                    id: `virtual-${key}`, 
                                    title: `${node.name} - ${type}`,
                                    description: 'Pendiente de inicio',
                                    project: proj,
                                    macroprocess: macro,
                                    process: proc,
                                    microprocess: node.name,
                                    docType: type as DocType,
                                    authorId: '',
                                    authorName: '',
                                    assignedTo: node.assignees?.[0] || '',
                                    assignees: node.assignees || [],
                                    state: DocState.NOT_STARTED,
                                    version: '-',
                                    progress: 0,
                                    files: [],
                                    createdAt: new Date().toISOString(),
                                    updatedAt: new Date(0).toISOString(), 
                                    hasPendingRequest: false,
                                    isRequired: true 
                                });
                            }
                        });
                    });
                });
            });
        });

        realDocMap.forEach((doc) => {
            if (!processedDocIds.has(doc.id)) {
                finalDocsList.push({
                    ...doc,
                    macroprocess: doc.macroprocess || 'Sin Clasificar',
                    process: doc.process || 'Sin Clasificar',
                    isRequired: false 
                });
            }
        });

        setMergedDocs(finalDocsList);

    } catch (error) {
        console.error("Error loading dashboard data:", error);
    } finally {
        setLoading(false);
    }
  };

  const contextDocs = useMemo(() => {
      let filtered = mergedDocs;

      if (externalFilterIds && externalFilterIds.length > 0) {
          filtered = filtered.filter(d => externalFilterIds.includes(d.id));
      } else {
          if (filterProject) filtered = filtered.filter(d => d.project === filterProject);
          if (filterMacro) filtered = filtered.filter(d => d.macroprocess === filterMacro);
          if (filterProcess) filtered = filtered.filter(d => d.process === filterProcess);
          if (filterDocType) filtered = filtered.filter(d => d.docType === filterDocType);
          if (filterState) filtered = filtered.filter(d => d.state === filterState);
          if (filterAnalyst) filtered = filtered.filter(d => d.assignees && d.assignees.includes(filterAnalyst));

          if (filterSearch) {
              const term = filterSearch.toLowerCase();
              filtered = filtered.filter(d => 
                  (d.microprocess || '').toLowerCase().includes(term) || 
                  (d.title || '').toLowerCase().includes(term)
              );
          }
      }

      return filtered;
  }, [mergedDocs, filterProject, filterMacro, filterProcess, filterDocType, filterState, filterAnalyst, filterSearch, externalFilterIds]);

  const stats = useMemo(() => {
      const requiredDocs = contextDocs.filter(d => d.isRequired);

      return {
        total: requiredDocs.length,
        notStarted: requiredDocs.filter(d => d.state === DocState.NOT_STARTED).length,
        inProcess: requiredDocs.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW).length,
        referent: requiredDocs.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW).length,
        control: requiredDocs.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW).length,
        finished: requiredDocs.filter(d => d.state === DocState.APPROVED).length
      };
  }, [contextDocs]);

  const tableDocs = useMemo(() => {
      let filtered = contextDocs;

      if (quickFilter !== 'ALL') {
          switch (quickFilter) {
              case 'NOT_STARTED': filtered = filtered.filter(d => d.state === DocState.NOT_STARTED); break;
              case 'IN_PROCESS': filtered = filtered.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW); break;
              case 'REFERENT': filtered = filtered.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW); break;
              case 'CONTROL': filtered = filtered.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW); break;
              case 'FINISHED': filtered = filtered.filter(d => d.state === DocState.APPROVED); break;
          }
      }
      return filtered;
  }, [contextDocs, quickFilter]);

  const sortedDocs = useMemo(() => {
      return [...tableDocs].sort((a, b) => {
          if (a.isRequired !== b.isRequired) {
              return a.isRequired ? -1 : 1;
          }

          const modifier = sortConfig.direction === 'asc' ? 1 : -1;

          switch (sortConfig.key) {
              case 'updatedAt': 
                  const timeA = new Date(a.updatedAt).getTime();
                  const timeB = new Date(b.updatedAt).getTime();
                  return (timeA - timeB) * modifier;

              case 'project': 
                  if ((a.project || '') !== (b.project || '')) return (a.project || '').localeCompare(b.project || '') * modifier;
                  if ((a.macroprocess || '') !== (b.macroprocess || '')) return (a.macroprocess || '').localeCompare(b.macroprocess || '') * modifier;
                  if ((a.process || '') !== (b.process || '')) return (a.process || '').localeCompare(b.process || '') * modifier;
                  if ((a.microprocess || '') !== (b.microprocess || '')) return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
                  return (getDocTypeOrder(a.docType) - getDocTypeOrder(b.docType)) * modifier;

              case 'microprocess': return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
              case 'state': return (a.progress - b.progress) * modifier;
              default: return 0;
          }
      });
  }, [tableDocs, sortConfig]);

  const totalItems = sortedDocs.length;
  const totalPages = Math.ceil(totalItems / ITEMS_PER_PAGE);
  const paginatedDocs = useMemo(() => {
      const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
      return sortedDocs.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [sortedDocs, currentPage]);

  const handleExportExcel = () => {
      if (sortedDocs.length === 0) return;
      const getUserNames = (ids: string[]) => ids.map(id => allUsers.find(u => u.id === id)?.name || id).join('; ');

      const headers = ['PROYECTO', 'MACROPROCESO', 'PROCESO', 'MICROPROCESO', 'ANALISTA', 'DOCUMENTO', 'VERSION', 'ESTADO', 'FECHA'];
      const rows = sortedDocs.map(d => [
          d.project || '-',
          d.macroprocess || '-',
          d.process || '-',
          d.microprocess || '-',
          getUserNames(d.assignees || []),
          d.docType || '-',
          d.version || '-',
          STATE_CONFIG[d.state]?.label.split('(')[0] || '-',
          d.state === DocState.NOT_STARTED ? 'Sin actividad' : new Date(d.updatedAt).toLocaleString('es-CL')
      ]);

      const csvContent = [headers.join(';'), ...rows.map(r => r.map(cell => `"${cell}"`).join(';'))].join('\n');
      const blob = new Blob(["\ufeff", csvContent], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.setAttribute('href', url);
      link.setAttribute('download', `SGD_Reporte_${new Date().toISOString().split('T')[0]}.csv`);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
  };

  const chartData = [
    { name: 'No Iniciado', value: stats.notStarted, color: '#e2e8f0' },
    { name: 'En Proceso', value: stats.inProcess, color: '#3b82f6' },
    { name: 'Referente', value: stats.referent, color: '#a855f7' },
    { name: 'Control', value: stats.control, color: '#f97316' },
    { name: 'Finalizado', value: stats.finished, color: '#22c55e' },
  ].filter(d => d.value > 0);

  const handleSort = (key: SortKey) => {
      setSortConfig({ key, direction: sortConfig.key === key && sortConfig.direction === 'asc' ? 'desc' : 'asc' });
  };

  const clearFilters = () => {
      setFilterProject(''); setFilterMacro(''); setFilterProcess(''); setFilterSearch(''); 
      setFilterDocType(''); setFilterState(''); setFilterAnalyst(''); setQuickFilter('ALL');
      setExternalFilterIds(null); navigate(location.pathname, { replace: true, state: {} });
  };

  const SortIcon = ({ column }: { column: SortKey }) => (
      sortConfig.key === column ? (sortConfig.direction === 'asc' ? <ArrowUp size={12} className="text-indigo-600"/> : <ArrowDown size={12} className="text-indigo-600"/>) : <ArrowUpDown size={12} className="opacity-30 group-hover:opacity-100"/>
  );

  const availableProjects = useMemo(() => Array.from(new Set(mergedDocs.map(d => d.project).filter(Boolean))).sort(), [mergedDocs]);
  const availableMacros = useMemo(() => {
      const docs = filterProject ? mergedDocs.filter(d => d.project === filterProject) : mergedDocs;
      return Array.from(new Set(docs.map(d => d.macroprocess).filter(Boolean))).sort();
  }, [mergedDocs, filterProject]);
  const availableProcesses = useMemo(() => {
      let docs = mergedDocs;
      if (filterProject) docs = docs.filter(d => d.project === filterProject);
      if (filterMacro) docs = docs.filter(d => d.macroprocess === filterMacro);
      return Array.from(new Set(docs.map(d => d.process).filter(Boolean))).sort();
  }, [mergedDocs, filterProject, filterMacro]);

  const getUserName = (id: string) => allUsers.find(user => user.id === id)?.name || 'Sin Asignar';

  if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Actualizando dashboard...</div>;

  if (isSystemEmpty) {
      return (
          <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6 bg-white rounded-xl shadow-sm border border-slate-200">
              <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center mb-6"><Database size={40} className="text-indigo-600" /></div>
              <h2 className="text-2xl font-bold text-slate-900 mb-2">Sistema sin Inicializar</h2>
              <p className="text-slate-500 max-w-md mb-8">La matriz de procesos está vacía. Cargue la estructura de procesos para comenzar.</p>
              {(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) && (
                  <Link to="/admin/assignments" className="flex items-center px-6 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-medium shadow-md transition-transform active:scale-95">
                      <Database size={18} className="mr-2" /> Ir a Carga de Datos
                  </Link>
              )}
          </div>
      );
  }

  const hasActiveFilters = filterProject || filterMacro || filterProcess || filterSearch || filterDocType || filterState || filterAnalyst || externalFilterIds;

  return (
    <div className="space-y-6 pb-12">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div><h1 className="text-2xl font-bold text-slate-900">Dashboard</h1><p className="text-slate-500">Vista general de avance institucional</p></div>
        <div className="flex items-center gap-2 w-full sm:w-auto">
            <button onClick={handleExportExcel} className="flex-1 sm:flex-none px-4 py-2 bg-white border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 flex items-center justify-center shadow-sm font-medium transition-colors">
                <FileSpreadsheet size={18} className="mr-2 text-green-600"/> <span className="hidden md:inline">Exportar Excel</span><span className="md:hidden">Excel</span>
            </button>
            {user.role === UserRole.ANALYST && <Link to="/new" className="flex-1 sm:flex-none px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 flex items-center justify-center shadow-sm font-medium"><Plus size={18} className="mr-2"/> Nueva Solicitud</Link>}
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-3">
        <StatCard title="Doc. Requeridos" value={stats.total} icon={BookOpen} color="bg-slate-50 text-slate-600" onClick={() => handleQuickFilter('ALL')} isActive={quickFilter === 'ALL'}/>
        <StatCard title="No Iniciado" value={stats.notStarted} icon={Clock} color="bg-white text-slate-600" onClick={() => handleQuickFilter('NOT_STARTED')} isActive={quickFilter === 'NOT_STARTED'}/>
        <StatCard title="En Proceso" value={stats.inProcess} icon={Activity} color="bg-blue-50 text-blue-600" onClick={() => handleQuickFilter('IN_PROCESS')} isActive={quickFilter === 'IN_PROCESS'}/>
        <StatCard title="Referente" value={stats.referent} icon={Users} color="bg-purple-50 text-purple-600" onClick={() => handleQuickFilter('REFERENT')} isActive={quickFilter === 'REFERENT'}/>
        <StatCard title="Control Gestión" value={stats.control} icon={ShieldCheck} color="bg-orange-50 text-orange-600" onClick={() => handleQuickFilter('CONTROL')} isActive={quickFilter === 'CONTROL'}/>
        <StatCard title="Terminados" value={stats.finished} icon={CheckCircle} color="bg-green-50 text-green-600" onClick={() => handleQuickFilter('FINISHED')} isActive={quickFilter === 'FINISHED'}/>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        <div className="lg:col-span-3 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col min-h-[500px]">
            <div className="p-4 border-b border-slate-100 bg-white">
                <div className="flex items-center justify-between mb-3">
                    <div className="flex items-center gap-2 text-indigo-600 font-semibold text-sm"><Filter size={16} /> Filtros de Visualización</div>
                    {hasActiveFilters && <button onClick={clearFilters} className="text-xs text-red-500 hover:text-red-700 flex items-center gap-1 font-medium"><X size={14} /> Limpiar filtros</button>}
                </div>
                {externalFilterIds ? (
                     <div className="bg-blue-50 border border-blue-100 p-3 rounded-lg mb-2 flex justify-between items-center animate-fadeIn">
                        <span className="text-xs text-blue-700 font-semibold">Filtro Activo: Visualizando {externalFilterIds.length} documentos específicos desde reportes.</span>
                        <button onClick={clearFilters} className="text-xs bg-white border border-blue-200 px-2 py-1 rounded text-blue-600">Mostrar Todo</button>
                     </div>
                ) : (
                    <div className="flex flex-wrap gap-2">
                        {/* ORDEN SOLICITADO: PROYECTO, MACROPROCESO, PROCESO, BUSCAR, DOC, ESTADO, ANALISTA */}
                        <select value={filterProject} onChange={(e) => setFilterProject(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-28">
                            <option value="">PROYECTO</option>
                            {availableProjects.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                        <select value={filterMacro} onChange={(e) => setFilterMacro(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-32">
                            <option value="">MACROPROCESO</option>
                            {availableMacros.map(m => <option key={m} value={m}>{m}</option>)}
                        </select>
                        <select value={filterProcess} onChange={(e) => setFilterProcess(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-32">
                            <option value="">PROCESO</option>
                            {availableProcesses.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                        <div className="relative w-36">
                            <Search size={12} className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400" />
                            <input type="text" value={filterSearch} onChange={(e) => setFilterSearch(e.target.value)} placeholder="BUSCAR..." className="w-full text-[11px] pl-7 p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none" />
                        </div>
                        <select value={filterDocType} onChange={(e) => setFilterDocType(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-24">
                            <option value="">DOC</option>
                            <option value="AS IS">AS IS</option>
                            <option value="FCE">FCE</option>
                            <option value="PM">PM</option>
                            <option value="TO BE">TO BE</option>
                        </select>
                        <select value={filterState} onChange={(e) => setFilterState(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-24">
                            <option value="">ESTADO</option>
                            {Object.entries(STATE_CONFIG).map(([key, cfg]) => <option key={key} value={key}>{cfg.label.split('(')[0]}</option>)}
                        </select>
                        <select value={filterAnalyst} onChange={(e) => setFilterAnalyst(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-32">
                            <option value="">ANALISTA</option>
                            {allUsers.filter(u => u.role === UserRole.ANALYST).map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                        </select>
                    </div>
                )}
            </div>

            <div className="overflow-x-auto flex-1">
                <table className="w-full text-[11px] text-left">
                    <thead className="text-[10px] text-slate-400 uppercase font-bold bg-white border-b border-slate-100">
                        <tr>
                            {/* CABECERAS SOLICITADAS: PROYECTO, JERARQUÍA (MACRO / PROCESO), MICROPROCESO, DOCUMENTO, ESTADO ACTUAL, ÚLTIMA ACTIVIDAD */}
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('project')}>PROYECTO <SortIcon column="project"/></th>
                            <th className="px-4 py-3">JERARQUÍA (MACRO / PROCESO)</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('microprocess')}>MICROPROCESO <SortIcon column="microprocess"/></th>
                            <th className="px-4 py-3">DOCUMENTO</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('state')}>ESTADO ACTUAL <SortIcon column="state"/></th>
                            <th className="px-4 py-3 text-right cursor-pointer group" onClick={() => handleSort('updatedAt')}>ÚLTIMA ACTIVIDAD <SortIcon column="updatedAt"/></th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                        {paginatedDocs.length === 0 ? (
                            <tr><td colSpan={6} className="p-12 text-center text-slate-400"><Search size={40} className="mx-auto mb-2 opacity-20"/><p>Sin resultados.</p></td></tr>
                        ) : paginatedDocs.map((doc, idx) => (
                            <tr key={`${doc.id}-${idx}`} className={`transition-colors ${!doc.isRequired ? 'bg-gray-100 hover:bg-gray-200' : 'hover:bg-slate-50'}`}>
                                <td className={`px-4 py-3 font-bold align-top ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.project}</td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`font-bold ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.macroprocess}</div>
                                    <div className="text-slate-500 text-[10px]">{doc.process}</div>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`font-bold mb-1 ${!doc.isRequired ? 'text-gray-600' : 'text-slate-800'}`}>{doc.microprocess}</div>
                                    <div className="flex items-center gap-1 text-slate-400" title="Analista Asignado">
                                        <UserIcon size={10} /> <span className="text-[10px] truncate max-w-[120px]">{doc.assignees && doc.assignees.length > 0 ? getUserName(doc.assignees[0]) : 'Sin Asignar'}</span>
                                    </div>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <span className={`inline-block px-1.5 py-0.5 rounded border text-[10px] font-bold mb-1 ${!doc.isRequired ? 'bg-gray-200 text-gray-400 border-gray-300' : 'bg-indigo-50 text-indigo-700 border-indigo-100'}`}>{doc.docType}</span>
                                    <Link to={`/doc/${doc.id}`} state={{ docData: doc }} className="flex items-center gap-1 text-[10px] font-bold text-indigo-500 hover:text-indigo-700 underline">Ver Detalle</Link>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`inline-block px-2 py-0.5 rounded-full text-[10px] font-bold mb-1 border ${!doc.isRequired ? 'bg-gray-200 text-gray-500 border-gray-300' : STATE_CONFIG[doc.state].color}`}>{STATE_CONFIG[doc.state].label.split('(')[0]}</div>
                                    <div className="text-[10px] font-mono text-slate-500">v{doc.version} ({doc.progress}%)</div>
                                </td>
                                <td className="px-4 py-3 align-top text-right">
                                    {doc.state !== DocState.NOT_STARTED ? (
                                        <div className="text-slate-600 font-medium">{new Date(doc.updatedAt).toLocaleDateString()}</div>
                                    ) : <span className="text-slate-300">-</span>}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {totalItems > 0 && (
                <div className="px-4 py-3 border-t border-slate-100 bg-slate-50/50 flex flex-col sm:flex-row items-center justify-between gap-4">
                    <div className="text-[11px] text-slate-500">Mostrando <b>{Math.min(totalItems, (currentPage - 1) * ITEMS_PER_PAGE + 1)}</b> a <b>{Math.min(totalItems, currentPage * ITEMS_PER_PAGE)}</b> de <b>{totalItems}</b> registros</div>
                    <div className="flex items-center gap-2">
                        <button onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))} disabled={currentPage === 1} className="p-1.5 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 disabled:opacity-50"><ChevronLeft size={16} /></button>
                        <div className="flex items-center gap-1">
                            {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                                let pageNum = i + 1;
                                if (totalPages > 5 && currentPage > 3) { pageNum = currentPage - 2 + i; if (pageNum > totalPages) pageNum = totalPages - (4 - i); }
                                return <button key={pageNum} onClick={() => setCurrentPage(pageNum)} className={`w-7 h-7 rounded-lg text-xs font-bold border transition-all ${currentPage === pageNum ? 'bg-indigo-600 text-white' : 'bg-white text-slate-600 hover:border-indigo-400'}`}>{pageNum}</button>;
                            })}
                        </div>
                        <button onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))} disabled={currentPage === totalPages} className="p-1.5 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 disabled:opacity-50"><ChevronRight size={16} /></button>
                    </div>
                </div>
            )}
        </div>

        <div className="lg:col-span-1 space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4 min-h-[250px] flex flex-col items-center justify-center">
                <h3 className="font-bold text-center mb-2 text-slate-700 text-xs uppercase">Estado Universo Requerido</h3>
                {chartData.length > 0 ? (
                    <div className="h-44 w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie data={chartData} cx="50%" cy="50%" innerRadius={45} outerRadius={65} paddingAngle={2} dataKey="value">
                                    {chartData.map((e, i) => <Cell key={i} fill={e.color}/>)}
                                </Pie>
                                <Tooltip contentStyle={{fontSize: '11px', borderRadius: '8px'}}/>
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                ) : <p className="text-center text-slate-400 text-[10px]">Sin datos.</p>}
                <div className="flex flex-wrap justify-center gap-x-3 gap-y-1 mt-2">
                    {chartData.map((d, i) => (
                        <div key={i} className="flex items-center gap-1"><span className="w-2 h-2 rounded-full" style={{backgroundColor: d.color}}></span><span className="text-[9px] text-slate-500 uppercase font-bold">{d.name}</span></div>
                    ))}
                </div>
            </div>
            <div className="bg-indigo-50 rounded-xl shadow-sm border border-indigo-100 p-4">
                <h3 className="font-bold text-indigo-900 text-xs uppercase mb-3">Resumen de Cumplimiento</h3>
                <ul className="space-y-2 text-[11px]">
                    <li className="flex justify-between text-slate-600"><span>No Iniciados:</span> <b>{stats.notStarted}</b></li>
                    <li className="flex justify-between text-blue-600"><span>En Proceso:</span> <b>{stats.inProcess}</b></li>
                    <li className="flex justify-between text-purple-600"><span>Referente:</span> <b>{stats.referent}</b></li>
                    <li className="flex justify-between text-orange-600"><span>Control Gestión:</span> <b>{stats.control}</b></li>
                    <li className="border-t border-indigo-200 pt-1 flex justify-between text-green-600 font-bold"><span>Terminados:</span> <span>{stats.finished}</span></li>
                </ul>
                <div className="mt-4 pt-3 border-t border-indigo-200 text-[9px] text-slate-500 flex items-center gap-2"><Archive size={12} /><span>Registros en <b>GRIS</b> son históricos externos.</span></div>
            </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon: Icon, color, isActive, onClick }: any) => (
    <div onClick={onClick} className={`p-3 rounded-xl shadow-sm border cursor-pointer flex items-center space-x-3 transition-all ${isActive ? 'ring-2 ring-indigo-300 scale-105' : 'hover:border-indigo-300'} ${color} border-transparent`}>
        <div className="p-1.5 bg-white/50 rounded-lg shrink-0"><Icon size={18}/></div>
        <div className="min-w-0">
            <p className="text-[9px] uppercase font-bold opacity-70 truncate">{title}</p>
            <p className="text-lg font-bold leading-none">{value}</p>
        </div>
    </div>
);

export default Dashboard;

import React, { useEffect, useState, useMemo } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService } from '../services/firebaseBackend';
import { Document, User, UserRole, DocState, DocType, FullHierarchy } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    Plus, Clock, CheckCircle, Filter, X, Calendar, ArrowRight, Activity, 
    BookOpen, Users, ShieldCheck, ArrowUp, ArrowDown, ArrowUpDown, Loader2,
    User as UserIcon, Database, AlertTriangle, Archive, PlayCircle, Search,
    ChevronLeft, ChevronRight, FileSpreadsheet
} from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

interface DashboardProps {
  user: User;
}

interface DashboardDoc extends Document {
    isRequired: boolean;
}

type SortKey = 'project' | 'microprocess' | 'state' | 'updatedAt';
type QuickFilterType = 'ALL' | 'NOT_STARTED' | 'IN_PROCESS' | 'REFERENT' | 'CONTROL' | 'FINISHED';

const ITEMS_PER_PAGE = 10;

const getDocTypeOrder = (type: string | undefined): number => {
    switch (type) {
        case 'AS IS': return 1;
        case 'FCE': return 2;
        case 'PM': return 3;
        case 'TO BE': return 4;
        default: return 99;
    }
};

const Dashboard: React.FC<DashboardProps> = ({ user }) => {
  const navigate = useNavigate();
  const location = useLocation(); 

  const [mergedDocs, setMergedDocs] = useState<DashboardDoc[]>([]);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSystemEmpty, setIsSystemEmpty] = useState(false);

  // Filtros de Estado
  const [filterProject, setFilterProject] = useState('');
  const [filterMacro, setFilterMacro] = useState('');
  const [filterProcess, setFilterProcess] = useState('');
  const [filterSearch, setFilterSearch] = useState(''); 
  const [filterDocType, setFilterDocType] = useState('');
  const [filterState, setFilterState] = useState(''); 
  const [filterAnalyst, setFilterAnalyst] = useState('');

  // Paginación
  const [currentPage, setCurrentPage] = useState(1);
  const [externalFilterIds, setExternalFilterIds] = useState<string[] | null>(null);
  const [quickFilter, setQuickFilter] = useState<QuickFilterType>('ALL');

  const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: 'asc' | 'desc' }>({
    key: 'project', 
    direction: 'asc'
  });

  useEffect(() => {
    if (location.state?.filterIds && Array.isArray(location.state.filterIds)) {
        setExternalFilterIds(location.state.filterIds);
        setQuickFilter('ALL');
    } else {
        setExternalFilterIds(null);
    }
    loadData();
  }, [location.state]);

  useEffect(() => {
    setCurrentPage(1);
  }, [filterProject, filterMacro, filterProcess, filterSearch, filterDocType, filterState, filterAnalyst, quickFilter, sortConfig]);

  const normalize = (str: string | undefined) => {
      if (!str) return '';
      return str.trim().toUpperCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  };

  const loadData = async () => {
    setLoading(true);
    try {
        const [realDocsData, users, fullHierarchy] = await Promise.all([
            DocumentService.getAll(),
            UserService.getAll(),
            HierarchyService.getFullHierarchy()
        ]);

        setAllUsers(users);
        const hierarchyKeys = Object.keys(fullHierarchy);

        if (hierarchyKeys.length === 0 && realDocsData.length === 0) {
            setIsSystemEmpty(true);
            setMergedDocs([]);
            setLoading(false);
            return;
        }
        setIsSystemEmpty(false);

        const realDocMap = new Map<string, Document>();
        const processedDocIds = new Set<string>();

        realDocsData.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalize(doc.project)}|${normalize(microName)}|${normalize(docType)}`;

                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        const finalDocsList: DashboardDoc[] = [];

        hierarchyKeys.forEach(proj => {
            Object.keys(fullHierarchy[proj]).forEach(macro => {
                Object.keys(fullHierarchy[proj][macro]).forEach(proc => {
                    const nodes = fullHierarchy[proj][macro][proc];
                    nodes.forEach(node => {
                        if (node.active === false) return; 

                        const requiredTypes = (node.requiredTypes && node.requiredTypes.length > 0) 
                            ? node.requiredTypes 
                            : ['AS IS', 'FCE', 'PM', 'TO BE'];

                        requiredTypes.forEach(type => {
                            const key = `${normalize(proj)}|${normalize(node.name)}|${normalize(type)}`;

                            if (realDocMap.has(key)) {
                                const realDoc = realDocMap.get(key)!;
                                finalDocsList.push({
                                    ...realDoc,
                                    macroprocess: macro,
                                    process: proc,
                                    project: proj,
                                    assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []),
                                    isRequired: true 
                                });
                                processedDocIds.add(realDoc.id); 
                            } else {
                                finalDocsList.push({
                                    id: `virtual-${key}`, 
                                    title: `${node.name} - ${type}`,
                                    description: 'Pendiente de inicio',
                                    project: proj,
                                    macroprocess: macro,
                                    process: proc,
                                    microprocess: node.name,
                                    docType: type as DocType,
                                    authorId: '',
                                    authorName: '',
                                    assignedTo: node.assignees?.[0] || '',
                                    assignees: node.assignees || [],
                                    state: DocState.NOT_STARTED,
                                    version: '-',
                                    progress: 0,
                                    files: [],
                                    createdAt: new Date().toISOString(),
                                    updatedAt: new Date(0).toISOString(), 
                                    hasPendingRequest: false,
                                    isRequired: true 
                                });
                            }
                        });
                    });
                });
            });
        });

        realDocMap.forEach((doc) => {
            if (!processedDocIds.has(doc.id)) {
                finalDocsList.push({
                    ...doc,
                    macroprocess: doc.macroprocess || 'Sin Clasificar',
                    process: doc.process || 'Sin Clasificar',
                    isRequired: false 
                });
            }
        });

        setMergedDocs(finalDocsList);

    } catch (error) {
        console.error("Error loading dashboard data:", error);
    } finally {
        setLoading(false);
    }
  };

  const contextDocs = useMemo(() => {
      let filtered = mergedDocs;

      if (externalFilterIds && externalFilterIds.length > 0) {
          filtered = filtered.filter(d => externalFilterIds.includes(d.id));
      } else {
          if (filterProject) filtered = filtered.filter(d => d.project === filterProject);
          if (filterMacro) filtered = filtered.filter(d => d.macroprocess === filterMacro);
          if (filterProcess) filtered = filtered.filter(d => d.process === filterProcess);
          if (filterDocType) filtered = filtered.filter(d => d.docType === filterDocType);
          if (filterState) filtered = filtered.filter(d => d.state === filterState);
          if (filterAnalyst) filtered = filtered.filter(d => d.assignees && d.assignees.includes(filterAnalyst));

          if (filterSearch) {
              const term = filterSearch.toLowerCase();
              filtered = filtered.filter(d => 
                  (d.microprocess || '').toLowerCase().includes(term) || 
                  (d.title || '').toLowerCase().includes(term)
              );
          }
      }

      return filtered;
  }, [mergedDocs, filterProject, filterMacro, filterProcess, filterDocType, filterState, filterAnalyst, filterSearch, externalFilterIds]);

  const stats = useMemo(() => {
      const requiredDocs = contextDocs.filter(d => d.isRequired);

      return {
        total: requiredDocs.length,
        notStarted: requiredDocs.filter(d => d.state === DocState.NOT_STARTED).length,
        inProcess: requiredDocs.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW).length,
        referent: requiredDocs.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW).length,
        control: requiredDocs.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW).length,
        finished: requiredDocs.filter(d => d.state === DocState.APPROVED).length
      };
  }, [contextDocs]);

  const tableDocs = useMemo(() => {
      let filtered = contextDocs;

      if (quickFilter !== 'ALL') {
          switch (quickFilter) {
              case 'NOT_STARTED': filtered = filtered.filter(d => d.state === DocState.NOT_STARTED); break;
              case 'IN_PROCESS': filtered = filtered.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW); break;
              case 'REFERENT': filtered = filtered.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW); break;
              case 'CONTROL': filtered = filtered.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW); break;
              case 'FINISHED': filtered = filtered.filter(d => d.state === DocState.APPROVED); break;
          }
      }
      return filtered;
  }, [contextDocs, quickFilter]);

  const sortedDocs = useMemo(() => {
      return [...tableDocs].sort((a, b) => {
          if (a.isRequired !== b.isRequired) {
              return a.isRequired ? -1 : 1;
          }

          const modifier = sortConfig.direction === 'asc' ? 1 : -1;

          switch (sortConfig.key) {
              case 'updatedAt': 
                  const timeA = new Date(a.updatedAt).getTime();
                  const timeB = new Date(b.updatedAt).getTime();
                  return (timeA - timeB) * modifier;

              case 'project': 
                  if ((a.project || '') !== (b.project || '')) return (a.project || '').localeCompare(b.project || '') * modifier;
                  if ((a.macroprocess || '') !== (b.macroprocess || '')) return (a.macroprocess || '').localeCompare(b.macroprocess || '') * modifier;
                  if ((a.process || '') !== (b.process || '')) return (a.process || '').localeCompare(b.process || '') * modifier;
                  if ((a.microprocess || '') !== (b.microprocess || '')) return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
                  return (getDocTypeOrder(a.docType) - getDocTypeOrder(b.docType)) * modifier;

              case 'microprocess': return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
              case 'state': return (a.progress - b.progress) * modifier;
              default: return 0;
          }
      });
  }, [tableDocs, sortConfig]);

  const totalItems = sortedDocs.length;
  const totalPages = Math.ceil(totalItems / ITEMS_PER_PAGE);
  const paginatedDocs = useMemo(() => {
      const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
      return sortedDocs.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [sortedDocs, currentPage]);

  const handleExportExcel = () => {
      if (sortedDocs.length === 0) return;
      const getUserNames = (ids: string[]) => ids.map(id => allUsers.find(u => u.id === id)?.name || id).join('; ');

      const headers = ['PROYECTO', 'MACROPROCESO', 'PROCESO', 'MICROPROCESO', 'ANALISTA', 'DOCUMENTO', 'VERSION', 'ESTADO', 'FECHA'];
      const rows = sortedDocs.map(d => [
          d.project || '-',
          d.macroprocess || '-',
          d.process || '-',
          d.microprocess || '-',
          getUserNames(d.assignees || []),
          d.docType || '-',
          d.version || '-',
          STATE_CONFIG[d.state]?.label.split('(')[0] || '-',
          d.state === DocState.NOT_STARTED ? 'Sin actividad' : new Date(d.updatedAt).toLocaleString('es-CL')
      ]);

      const csvContent = [headers.join(';'), ...rows.map(r => r.map(cell => `"${cell}"`).join(';'))].join('\n');
      const blob = new Blob(["\ufeff", csvContent], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.setAttribute('href', url);
      link.setAttribute('download', `SGD_Reporte_${new Date().toISOString().split('T')[0]}.csv`);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
  };

  const chartData = [
    { name: 'No Iniciado', value: stats.notStarted, color: '#e2e8f0' },
    { name: 'En Proceso', value: stats.inProcess, color: '#3b82f6' },
    { name: 'Referente', value: stats.referent, color: '#a855f7' },
    { name: 'Control', value: stats.control, color: '#f97316' },
    { name: 'Finalizado', value: stats.finished, color: '#22c55e' },
  ].filter(d => d.value > 0);

  const handleSort = (key: SortKey) => {
      setSortConfig({ key, direction: sortConfig.key === key && sortConfig.direction === 'asc' ? 'desc' : 'asc' });
  };

  // Added handleQuickFilter to fix missing reference errors in StatCard usages
  const handleQuickFilter = (type: QuickFilterType) => {
    setQuickFilter(type);
    setCurrentPage(1);
  };

  const clearFilters = () => {
      setFilterProject(''); setFilterMacro(''); setFilterProcess(''); setFilterSearch(''); 
      setFilterDocType(''); setFilterState(''); setFilterAnalyst(''); setQuickFilter('ALL');
      setExternalFilterIds(null); navigate(location.pathname, { replace: true, state: {} });
  };

  const SortIcon = ({ column }: { column: SortKey }) => (
      sortConfig.key === column ? (sortConfig.direction === 'asc' ? <ArrowUp size={12} className="text-indigo-600"/> : <ArrowDown size={12} className="text-indigo-600"/>) : <ArrowUpDown size={12} className="opacity-30 group-hover:opacity-100"/>
  );

  const availableProjects = useMemo(() => Array.from(new Set(mergedDocs.map(d => d.project).filter(Boolean))).sort(), [mergedDocs]);
  const availableMacros = useMemo(() => {
      const docs = filterProject ? mergedDocs.filter(d => d.project === filterProject) : mergedDocs;
      return Array.from(new Set(docs.map(d => d.macroprocess).filter(Boolean))).sort();
  }, [mergedDocs, filterProject]);
  const availableProcesses = useMemo(() => {
      let docs = mergedDocs;
      if (filterProject) docs = docs.filter(d => d.project === filterProject);
      if (filterMacro) docs = docs.filter(d => d.macroprocess === filterMacro);
      return Array.from(new Set(docs.map(d => d.process).filter(Boolean))).sort();
  }, [mergedDocs, filterProject, filterMacro]);

  const getUserName = (id: string) => allUsers.find(user => user.id === id)?.name || 'Sin Asignar';

  if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Actualizando dashboard...</div>;

  if (isSystemEmpty) {
      return (
          <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6 bg-white rounded-xl shadow-sm border border-slate-200">
              <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center mb-6"><Database size={40} className="text-indigo-600" /></div>
              <h2 className="text-2xl font-bold text-slate-900 mb-2">Sistema sin Inicializar</h2>
              <p className="text-slate-500 max-w-md mb-8">La matriz de procesos está vacía. Cargue la estructura de procesos para comenzar.</p>
              {(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) && (
                  <Link to="/admin/assignments" className="flex items-center px-6 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-medium shadow-md transition-transform active:scale-95">
                      <Database size={18} className="mr-2" /> Ir a Carga de Datos
                  </Link>
              )}
          </div>
      );
  }

  const hasActiveFilters = filterProject || filterMacro || filterProcess || filterSearch || filterDocType || filterState || filterAnalyst || externalFilterIds;

  return (
    <div className="space-y-6 pb-12">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div><h1 className="text-2xl font-bold text-slate-900">Dashboard</h1><p className="text-slate-500">Vista general de avance institucional</p></div>
        <div className="flex items-center gap-2 w-full sm:w-auto">
            <button onClick={handleExportExcel} className="flex-1 sm:flex-none px-4 py-2 bg-white border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 flex items-center justify-center shadow-sm font-medium transition-colors">
                <FileSpreadsheet size={18} className="mr-2 text-green-600"/> <span className="hidden md:inline">Exportar Excel</span><span className="md:hidden">Excel</span>
            </button>
            {user.role === UserRole.ANALYST && <Link to="/new" className="flex-1 sm:flex-none px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 flex items-center justify-center shadow-sm font-medium"><Plus size={18} className="mr-2"/> Nueva Solicitud</Link>}
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-3">
        <StatCard title="Doc. Requeridos" value={stats.total} icon={BookOpen} color="bg-slate-50 text-slate-600" onClick={() => handleQuickFilter('ALL')} isActive={quickFilter === 'ALL'}/>
        <StatCard title="No Iniciado" value={stats.notStarted} icon={Clock} color="bg-white text-slate-600" onClick={() => handleQuickFilter('NOT_STARTED')} isActive={quickFilter === 'NOT_STARTED'}/>
        <StatCard title="En Proceso" value={stats.inProcess} icon={Activity} color="bg-blue-50 text-blue-600" onClick={() => handleQuickFilter('IN_PROCESS')} isActive={quickFilter === 'IN_PROCESS'}/>
        <StatCard title="Referente" value={stats.referent} icon={Users} color="bg-purple-50 text-purple-600" onClick={() => handleQuickFilter('REFERENT')} isActive={quickFilter === 'REFERENT'}/>
        <StatCard title="Control Gestión" value={stats.control} icon={ShieldCheck} color="bg-orange-50 text-orange-600" onClick={() => handleQuickFilter('CONTROL')} isActive={quickFilter === 'CONTROL'}/>
        <StatCard title="Terminados" value={stats.finished} icon={CheckCircle} color="bg-green-50 text-green-600" onClick={() => handleQuickFilter('FINISHED')} isActive={quickFilter === 'FINISHED'}/>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        <div className="lg:col-span-3 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col min-h-[500px]">
            <div className="p-4 border-b border-slate-100 bg-white">
                <div className="flex items-center justify-between mb-3">
                    <div className="flex items-center gap-2 text-indigo-600 font-semibold text-sm"><Filter size={16} /> Filtros de Visualización</div>
                    {hasActiveFilters && <button onClick={clearFilters} className="text-xs text-red-500 hover:text-red-700 flex items-center gap-1 font-medium"><X size={14} /> Limpiar filtros</button>}
                </div>
                {externalFilterIds ? (
                     <div className="bg-blue-50 border border-blue-100 p-3 rounded-lg mb-2 flex justify-between items-center animate-fadeIn">
                        <span className="text-xs text-blue-700 font-semibold">Filtro Activo: Visualizando {externalFilterIds.length} documentos específicos desde reportes.</span>
                        <button onClick={clearFilters} className="text-xs bg-white border border-blue-200 px-2 py-1 rounded text-blue-600">Mostrar Todo</button>
                     </div>
                ) : (
                    <div className="flex flex-wrap gap-2">
                        {/* ORDEN SOLICITADO: PROYECTO, MACROPROCESO, PROCESO, BUSCAR, DOC, ESTADO, ANALISTA */}
                        <select value={filterProject} onChange={(e) => setFilterProject(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-28">
                            <option value="">PROYECTO</option>
                            {availableProjects.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                        <select value={filterMacro} onChange={(e) => setFilterMacro(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-32">
                            <option value="">MACROPROCESO</option>
                            {availableMacros.map(m => <option key={m} value={m}>{m}</option>)}
                        </select>
                        <select value={filterProcess} onChange={(e) => setFilterProcess(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-32">
                            <option value="">PROCESO</option>
                            {availableProcesses.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                        <div className="relative w-36">
                            <Search size={12} className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400" />
                            <input type="text" value={filterSearch} onChange={(e) => setFilterSearch(e.target.value)} placeholder="BUSCAR..." className="w-full text-[11px] pl-7 p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none" />
                        </div>
                        <select value={filterDocType} onChange={(e) => setFilterDocType(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-24">
                            <option value="">DOC</option>
                            <option value="AS IS">AS IS</option>
                            <option value="FCE">FCE</option>
                            <option value="PM">PM</option>
                            <option value="TO BE">TO BE</option>
                        </select>
                        <select value={filterState} onChange={(e) => setFilterState(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-24">
                            <option value="">ESTADO</option>
                            {Object.entries(STATE_CONFIG).map(([key, cfg]) => <option key={key} value={key}>{cfg.label.split('(')[0]}</option>)}
                        </select>
                        <select value={filterAnalyst} onChange={(e) => setFilterAnalyst(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-32">
                            <option value="">ANALISTA</option>
                            {allUsers.filter(u => u.role === UserRole.ANALYST).map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                        </select>
                    </div>
                )}
            </div>

            <div className="overflow-x-auto flex-1">
                <table className="w-full text-[11px] text-left">
                    <thead className="text-[10px] text-slate-400 uppercase font-bold bg-white border-b border-slate-100">
                        <tr>
                            {/* CABECERAS SOLICITADAS: PROYECTO, JERARQUÍA (MACRO / PROCESO), MICROPROCESO, DOCUMENTO, ESTADO ACTUAL, ÚLTIMA ACTIVIDAD */}
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('project')}>PROYECTO <SortIcon column="project"/></th>
                            <th className="px-4 py-3">JERARQUÍA (MACRO / PROCESO)</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('microprocess')}>MICROPROCESO <SortIcon column="microprocess"/></th>
                            <th className="px-4 py-3">DOCUMENTO</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('state')}>ESTADO ACTUAL <SortIcon column="state"/></th>
                            <th className="px-4 py-3 text-right cursor-pointer group" onClick={() => handleSort('updatedAt')}>ÚLTIMA ACTIVIDAD <SortIcon column="updatedAt"/></th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                        {paginatedDocs.length === 0 ? (
                            <tr><td colSpan={6} className="p-12 text-center text-slate-400"><Search size={40} className="mx-auto mb-2 opacity-20"/><p>Sin resultados.</p></td></tr>
                        ) : paginatedDocs.map((doc, idx) => (
                            <tr key={`${doc.id}-${idx}`} className={`transition-colors ${!doc.isRequired ? 'bg-gray-100 hover:bg-gray-200' : 'hover:bg-slate-50'}`}>
                                <td className={`px-4 py-3 font-bold align-top ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.project}</td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`font-bold ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.macroprocess}</div>
                                    <div className="text-slate-500 text-[10px]">{doc.process}</div>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`font-bold mb-1 ${!doc.isRequired ? 'text-gray-600' : 'text-slate-800'}`}>{doc.microprocess}</div>
                                    <div className="flex items-center gap-1 text-slate-400" title="Analista Asignado">
                                        <UserIcon size={10} /> <span className="text-[10px] truncate max-w-[120px]">{doc.assignees && doc.assignees.length > 0 ? getUserName(doc.assignees[0]) : 'Sin Asignar'}</span>
                                    </div>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <span className={`inline-block px-1.5 py-0.5 rounded border text-[10px] font-bold mb-1 ${!doc.isRequired ? 'bg-gray-200 text-gray-400 border-gray-300' : 'bg-indigo-50 text-indigo-700 border-indigo-100'}`}>{doc.docType}</span>
                                    <Link to={`/doc/${doc.id}`} state={{ docData: doc }} className="flex items-center gap-1 text-[10px] font-bold text-indigo-500 hover:text-indigo-700 underline">Ver Detalle</Link>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`inline-block px-2 py-0.5 rounded-full text-[10px] font-bold mb-1 border ${!doc.isRequired ? 'bg-gray-200 text-gray-500 border-gray-300' : STATE_CONFIG[doc.state].color}`}>{STATE_CONFIG[doc.state].label.split('(')[0]}</div>
                                    <div className="text-[10px] font-mono text-slate-500">v{doc.version} ({doc.progress}%)</div>
                                </td>
                                <td className="px-4 py-3 align-top text-right">
                                    {doc.state !== DocState.NOT_STARTED ? (
                                        <div className="text-slate-600 font-medium">{new Date(doc.updatedAt).toLocaleDateString()}</div>
                                    ) : <span className="text-slate-300">-</span>}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {totalItems > 0 && (
                <div className="px-4 py-3 border-t border-slate-100 bg-slate-50/50 flex flex-col sm:flex-row items-center justify-between gap-4">
                    <div className="text-[11px] text-slate-500">Mostrando <b>{Math.min(totalItems, (currentPage - 1) * ITEMS_PER_PAGE + 1)}</b> a <b>{Math.min(totalItems, currentPage * ITEMS_PER_PAGE)}</b> de <b>{totalItems}</b> registros</div>
                    <div className="flex items-center gap-2">
                        <button onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))} disabled={currentPage === 1} className="p-1.5 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 disabled:opacity-50"><ChevronLeft size={16} /></button>
                        <div className="flex items-center gap-1">
                            {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                                let pageNum = i + 1;
                                if (totalPages > 5 && currentPage > 3) { pageNum = currentPage - 2 + i; if (pageNum > totalPages) pageNum = totalPages - (4 - i); }
                                return <button key={pageNum} onClick={() => setCurrentPage(pageNum)} className={`w-7 h-7 rounded-lg text-xs font-bold border transition-all ${currentPage === pageNum ? 'bg-indigo-600 text-white' : 'bg-white text-slate-600 hover:border-indigo-400'}`}>{pageNum}</button>;
                            })}
                        </div>
                        <button onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))} disabled={currentPage === totalPages} className="p-1.5 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 disabled:opacity-50"><ChevronRight size={16} /></button>
                    </div>
                </div>
            )}
        </div>

        <div className="lg:col-span-1 space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4 min-h-[250px] flex flex-col items-center justify-center">
                <h3 className="font-bold text-center mb-2 text-slate-700 text-xs uppercase">Estado Universo Requerido</h3>
                {chartData.length > 0 ? (
                    <div className="h-44 w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie data={chartData} cx="50%" cy="50%" innerRadius={45} outerRadius={65} paddingAngle={2} dataKey="value">
                                    {chartData.map((e, i) => <Cell key={i} fill={e.color}/>)}
                                </Pie>
                                <Tooltip contentStyle={{fontSize: '11px', borderRadius: '8px'}}/>
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                ) : <p className="text-center text-slate-400 text-[10px]">Sin datos.</p>}
                <div className="flex flex-wrap justify-center gap-x-3 gap-y-1 mt-2">
                    {chartData.map((d, i) => (
                        <div key={i} className="flex items-center gap-1"><span className="w-2 h-2 rounded-full" style={{backgroundColor: d.color}}></span><span className="text-[9px] text-slate-500 uppercase font-bold">{d.name}</span></div>
                    ))}
                </div>
            </div>
            <div className="bg-indigo-50 rounded-xl shadow-sm border border-indigo-100 p-4">
                <h3 className="font-bold text-indigo-900 text-xs uppercase mb-3">Resumen de Cumplimiento</h3>
                <ul className="space-y-2 text-[11px]">
                    <li className="flex justify-between text-slate-600"><span>No Iniciados:</span> <b>{stats.notStarted}</b></li>
                    <li className="flex justify-between text-blue-600"><span>En Proceso:</span> <b>{stats.inProcess}</b></li>
                    <li className="flex justify-between text-purple-600"><span>Referente:</span> <b>{stats.referent}</b></li>
                    <li className="flex justify-between text-orange-600"><span>Control Gestión:</span> <b>{stats.control}</b></li>
                    <li className="border-t border-indigo-200 pt-1 flex justify-between text-green-600 font-bold"><span>Terminados:</span> <span>{stats.finished}</span></li>
                </ul>
                <div className="mt-4 pt-3 border-t border-indigo-200 text-[9px] text-slate-500 flex items-center gap-2"><Archive size={12} /><span>Registros en <b>GRIS</b> son históricos externos.</span></div>
            </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon: Icon, color, isActive, onClick }: any) => (
    <div onClick={onClick} className={`p-3 rounded-xl shadow-sm border cursor-pointer flex items-center space-x-3 transition-all ${isActive ? 'ring-2 ring-indigo-300 scale-105' : 'hover:border-indigo-300'} ${color} border-transparent`}>
        <div className="p-1.5 bg-white/50 rounded-lg shrink-0"><Icon size={18}/></div>
        <div className="min-w-0">
            <p className="text-[9px] uppercase font-bold opacity-70 truncate">{title}</p>
            <p className="text-lg font-bold leading-none">{value}</p>
        </div>
    </div>
);

export default Dashboard;

import React, { useEffect, useState, useMemo } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService } from '../services/firebaseBackend';
import { Document, User, UserRole, DocState, DocType, FullHierarchy } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    Plus, Clock, CheckCircle, Filter, X, Calendar, ArrowRight, Activity, 
    BookOpen, Users, ShieldCheck, ArrowUp, ArrowDown, ArrowUpDown, Loader2,
    User as UserIcon, Database, AlertTriangle, Archive, PlayCircle, Search,
    ChevronLeft, ChevronRight, FileSpreadsheet
} from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

interface DashboardProps {
  user: User;
}

interface DashboardDoc extends Document {
    isRequired: boolean;
}

type SortKey = 'project' | 'microprocess' | 'state' | 'updatedAt';
type QuickFilterType = 'ALL' | 'NOT_STARTED' | 'IN_PROCESS' | 'REFERENT' | 'CONTROL' | 'FINISHED';

const ITEMS_PER_PAGE = 10;

const getDocTypeOrder = (type: string | undefined): number => {
    switch (type) {
        case 'AS IS': return 1;
        case 'FCE': return 2;
        case 'PM': return 3;
        case 'TO BE': return 4;
        default: return 99;
    }
};

const Dashboard: React.FC<DashboardProps> = ({ user }) => {
  const navigate = useNavigate();
  const location = useLocation(); 

  const [mergedDocs, setMergedDocs] = useState<DashboardDoc[]>([]);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSystemEmpty, setIsSystemEmpty] = useState(false);

  // Filtros de Estado
  const [filterProject, setFilterProject] = useState('');
  const [filterMacro, setFilterMacro] = useState('');
  const [filterProcess, setFilterProcess] = useState('');
  const [filterSearch, setFilterSearch] = useState(''); 
  const [filterDocType, setFilterDocType] = useState('');
  const [filterState, setFilterState] = useState(''); 
  const [filterAnalyst, setFilterAnalyst] = useState('');

  // Paginación
  const [currentPage, setCurrentPage] = useState(1);
  const [externalFilterIds, setExternalFilterIds] = useState<string[] | null>(null);
  const [quickFilter, setQuickFilter] = useState<QuickFilterType>('ALL');

  const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: 'asc' | 'desc' }>({
    key: 'project', 
    direction: 'asc'
  });

  useEffect(() => {
    if (location.state?.filterIds && Array.isArray(location.state.filterIds)) {
        setExternalFilterIds(location.state.filterIds);
        setQuickFilter('ALL');
    } else {
        setExternalFilterIds(null);
    }
    loadData();
  }, [location.state]);

  useEffect(() => {
    setCurrentPage(1);
  }, [filterProject, filterMacro, filterProcess, filterSearch, filterDocType, filterState, filterAnalyst, quickFilter, sortConfig]);

  const normalize = (str: string | undefined) => {
      if (!str) return '';
      return str.trim().toUpperCase().normalize("NFD").replace(/[\u0300Host\u036f]/g, "");
  };

  const loadData = async () => {
    setLoading(true);
    try {
        const [realDocsData, users, fullHierarchy] = await Promise.all([
            DocumentService.getAll(),
            UserService.getAll(),
            HierarchyService.getFullHierarchy()
        ]);

        setAllUsers(users);
        const hierarchyKeys = Object.keys(fullHierarchy);

        if (hierarchyKeys.length === 0 && realDocsData.length === 0) {
            setIsSystemEmpty(true);
            setMergedDocs([]);
            setLoading(false);
            return;
        }
        setIsSystemEmpty(false);

        const realDocMap = new Map<string, Document>();
        const processedDocIds = new Set<string>();

        realDocsData.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalize(doc.project)}|${normalize(microName)}|${normalize(docType)}`;

                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        const finalDocsList: DashboardDoc[] = [];

        hierarchyKeys.forEach(proj => {
            Object.keys(fullHierarchy[proj]).forEach(macro => {
                Object.keys(fullHierarchy[proj][macro]).forEach(proc => {
                    const nodes = fullHierarchy[proj][macro][proc];
                    nodes.forEach(node => {
                        if (node.active === false) return; 

                        const requiredTypes = (node.requiredTypes && node.requiredTypes.length > 0) 
                            ? node.requiredTypes 
                            : ['AS IS', 'FCE', 'PM', 'TO BE'];

                        requiredTypes.forEach(type => {
                            const key = `${normalize(proj)}|${normalize(node.name)}|${normalize(type)}`;

                            if (realDocMap.has(key)) {
                                const realDoc = realDocMap.get(key)!;
                                finalDocsList.push({
                                    ...realDoc,
                                    macroprocess: macro,
                                    process: proc,
                                    project: proj,
                                    assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []),
                                    isRequired: true 
                                });
                                processedDocIds.add(realDoc.id); 
                            } else {
                                finalDocsList.push({
                                    id: `virtual-${key}`, 
                                    title: `${node.name} - ${type}`,
                                    description: 'Pendiente de inicio',
                                    project: proj,
                                    macroprocess: macro,
                                    process: proc,
                                    microprocess: node.name,
                                    docType: type as DocType,
                                    authorId: '',
                                    authorName: '',
                                    assignedTo: node.assignees?.[0] || '',
                                    assignees: node.assignees || [],
                                    state: DocState.NOT_STARTED,
                                    version: '-',
                                    progress: 0,
                                    files: [],
                                    createdAt: new Date().toISOString(),
                                    updatedAt: new Date(0).toISOString(), 
                                    hasPendingRequest: false,
                                    isRequired: true 
                                });
                            }
                        });
                    });
                });
            });
        });

        realDocMap.forEach((doc) => {
            if (!processedDocIds.has(doc.id)) {
                finalDocsList.push({
                    ...doc,
                    macroprocess: doc.macroprocess || 'Sin Clasificar',
                    process: doc.process || 'Sin Clasificar',
                    isRequired: false 
                });
            }
        });

        setMergedDocs(finalDocsList);

    } catch (error) {
        console.error("Error loading dashboard data:", error);
    } finally {
        setLoading(false);
    }
  };

  const contextDocs = useMemo(() => {
      let filtered = mergedDocs;

      if (externalFilterIds && externalFilterIds.length > 0) {
          filtered = filtered.filter(d => externalFilterIds.includes(d.id));
      } else {
          if (filterProject) filtered = filtered.filter(d => d.project === filterProject);
          if (filterMacro) filtered = filtered.filter(d => d.macroprocess === filterMacro);
          if (filterProcess) filtered = filtered.filter(d => d.process === filterProcess);
          if (filterDocType) filtered = filtered.filter(d => d.docType === filterDocType);
          if (filterState) filtered = filtered.filter(d => d.state === filterState);
          if (filterAnalyst) filtered = filtered.filter(d => d.assignees && d.assignees.includes(filterAnalyst));

          if (filterSearch) {
              const term = filterSearch.toLowerCase();
              filtered = filtered.filter(d => 
                  (d.microprocess || '').toLowerCase().includes(term) || 
                  (d.title || '').toLowerCase().includes(term)
              );
          }
      }

      return filtered;
  }, [mergedDocs, filterProject, filterMacro, filterProcess, filterDocType, filterState, filterAnalyst, filterSearch, externalFilterIds]);

  const stats = useMemo(() => {
      const requiredDocs = contextDocs.filter(d => d.isRequired);

      return {
        total: requiredDocs.length,
        notStarted: requiredDocs.filter(d => d.state === DocState.NOT_STARTED).length,
        inProcess: requiredDocs.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW).length,
        referent: requiredDocs.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW).length,
        control: requiredDocs.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW).length,
        finished: requiredDocs.filter(d => d.state === DocState.APPROVED).length
      };
  }, [contextDocs]);

  const tableDocs = useMemo(() => {
      let filtered = contextDocs;

      if (quickFilter !== 'ALL') {
          switch (quickFilter) {
              case 'NOT_STARTED': filtered = filtered.filter(d => d.state === DocState.NOT_STARTED); break;
              case 'IN_PROCESS': filtered = filtered.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW); break;
              case 'REFERENT': filtered = filtered.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW); break;
              case 'CONTROL': filtered = filtered.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW); break;
              case 'FINISHED': filtered = filtered.filter(d => d.state === DocState.APPROVED); break;
          }
      }
      return filtered;
  }, [contextDocs, quickFilter]);

  const sortedDocs = useMemo(() => {
      return [...tableDocs].sort((a, b) => {
          if (a.isRequired !== b.isRequired) {
              return a.isRequired ? -1 : 1;
          }

          const modifier = sortConfig.direction === 'asc' ? 1 : -1;

          switch (sortConfig.key) {
              case 'updatedAt': 
                  const timeA = new Date(a.updatedAt).getTime();
                  const timeB = new Date(b.updatedAt).getTime();
                  return (timeA - timeB) * modifier;

              case 'project': 
                  if ((a.project || '') !== (b.project || '')) return (a.project || '').localeCompare(b.project || '') * modifier;
                  if ((a.macroprocess || '') !== (b.macroprocess || '')) return (a.macroprocess || '').localeCompare(b.macroprocess || '') * modifier;
                  if ((a.process || '') !== (b.process || '')) return (a.process || '').localeCompare(b.process || '') * modifier;
                  if ((a.microprocess || '') !== (b.microprocess || '')) return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
                  return (getDocTypeOrder(a.docType) - getDocTypeOrder(b.docType)) * modifier;

              case 'microprocess': return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
              case 'state': return (a.progress - b.progress) * modifier;
              default: return 0;
          }
      });
  }, [tableDocs, sortConfig]);

  const totalItems = sortedDocs.length;
  const totalPages = Math.ceil(totalItems / ITEMS_PER_PAGE);
  const paginatedDocs = useMemo(() => {
      const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
      return sortedDocs.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [sortedDocs, currentPage]);

  const handleExportExcel = () => {
      if (sortedDocs.length === 0) return;
      const getUserNames = (ids: string[]) => ids.map(id => allUsers.find(u => u.id === id)?.name || id).join('; ');

      const headers = ['PROYECTO', 'MACROPROCESO', 'PROCESO', 'MICROPROCESO', 'ANALISTA', 'DOCUMENTO', 'VERSION', 'ESTADO', 'FECHA'];
      const rows = sortedDocs.map(d => {
          // Formateo de fecha DD-MM-YYYY sin hora
          let fechaStr = 'Sin actividad';
          if (d.state !== DocState.NOT_STARTED && d.updatedAt) {
              const date = new Date(d.updatedAt);
              const day = String(date.getDate()).padStart(2, '0');
              const month = String(date.getMonth() + 1).padStart(2, '0');
              const year = date.getFullYear();
              fechaStr = `${day}-${month}-${year}`;
          }

          return [
              d.project || '-',
              d.macroprocess || '-',
              d.process || '-',
              d.microprocess || '-',
              getUserNames(d.assignees || []),
              d.docType || '-',
              d.version || '-',
              STATE_CONFIG[d.state]?.label.split('(')[0] || '-',
              fechaStr
          ];
      });

      const csvContent = [headers.join(';'), ...rows.map(r => r.map(cell => `"${cell}"`).join(';'))].join('\n');
      const blob = new Blob(["\ufeff", csvContent], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.setAttribute('href', url);
      link.setAttribute('download', `SGD_Reporte_${new Date().toISOString().split('T')[0]}.csv`);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
  };

  const handleSort = (key: SortKey) => {
      setSortConfig({ key, direction: sortConfig.key === key && sortConfig.direction === 'asc' ? 'desc' : 'asc' });
  };

  // Added handleQuickFilter to fix missing reference errors in StatCard usages
  const handleQuickFilter = (type: QuickFilterType) => {
    setQuickFilter(type);
    setCurrentPage(1);
  };

  const clearFilters = () => {
      setFilterProject(''); setFilterMacro(''); setFilterProcess(''); setFilterSearch(''); 
      setFilterDocType(''); setFilterState(''); setFilterAnalyst(''); setQuickFilter('ALL');
      setExternalFilterIds(null); navigate(location.pathname, { replace: true, state: {} });
  };

  const SortIcon = ({ column }: { column: SortKey }) => (
      sortConfig.key === column ? (sortConfig.direction === 'asc' ? <ArrowUp size={12} className="text-indigo-600"/> : <ArrowDown size={12} className="text-indigo-600"/>) : <ArrowUpDown size={12} className="opacity-30 group-hover:opacity-100"/>
  );

  const availableProjects = useMemo(() => Array.from(new Set(mergedDocs.map(d => d.project).filter(Boolean))).sort(), [mergedDocs]);
  const availableMacros = useMemo(() => {
      const docs = filterProject ? mergedDocs.filter(d => d.project === filterProject) : mergedDocs;
      return Array.from(new Set(docs.map(d => d.macroprocess).filter(Boolean))).sort();
  }, [mergedDocs, filterProject]);
  const availableProcesses = useMemo(() => {
      let docs = mergedDocs;
      if (filterProject) docs = docs.filter(d => d.project === filterProject);
      if (filterMacro) docs = docs.filter(d => d.macroprocess === filterMacro);
      return Array.from(new Set(docs.map(d => d.process).filter(Boolean))).sort();
  }, [mergedDocs, filterProject, filterMacro]);

  const getUserName = (id: string) => allUsers.find(user => user.id === id)?.name || 'Sin Asignar';

  if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Actualizando dashboard...</div>;

  if (isSystemEmpty) {
      return (
          <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6 bg-white rounded-xl shadow-sm border border-slate-200">
              <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center mb-6"><Database size={40} className="text-indigo-600" /></div>
              <h2 className="text-2xl font-bold text-slate-900 mb-2">Sistema sin Inicializar</h2>
              <p className="text-slate-500 max-w-md mb-8">La matriz de procesos está vacía. Cargue la estructura de procesos para comenzar.</p>
              {(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) && (
                  <Link to="/admin/assignments" className="flex items-center px-6 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-medium shadow-md transition-transform active:scale-95">
                      <Database size={18} className="mr-2" /> Ir a Carga de Datos
                  </Link>
              )}
          </div>
      );
  }

  const hasActiveFilters = filterProject || filterMacro || filterProcess || filterSearch || filterDocType || filterState || filterAnalyst || externalFilterIds;

  return (
    <div className="space-y-6 pb-12">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div><h1 className="text-2xl font-bold text-slate-900">Dashboard</h1><p className="text-slate-500">Vista general de avance institucional</p></div>
        <div className="flex items-center gap-2 w-full sm:w-auto">
            <button onClick={handleExportExcel} className="flex-1 sm:flex-none px-4 py-2 bg-white border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 flex items-center justify-center shadow-sm font-medium transition-colors">
                <FileSpreadsheet size={18} className="mr-2 text-green-600"/> <span className="hidden md:inline">Exportar Excel</span><span className="md:hidden">Excel</span>
            </button>
            {user.role === UserRole.ANALYST && <Link to="/new" className="flex-1 sm:flex-none px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 flex items-center justify-center shadow-sm font-medium"><Plus size={18} className="mr-2"/> Nueva Solicitud</Link>}
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-3">
        <StatCard title="Doc. Requeridos" value={stats.total} icon={BookOpen} color="bg-slate-50 text-slate-600" onClick={() => handleQuickFilter('ALL')} isActive={quickFilter === 'ALL'}/>
        <StatCard title="No Iniciado" value={stats.notStarted} icon={Clock} color="bg-white text-slate-600" onClick={() => handleQuickFilter('NOT_STARTED')} isActive={quickFilter === 'NOT_STARTED'}/>
        <StatCard title="En Proceso" value={stats.inProcess} icon={Activity} color="bg-blue-50 text-blue-600" onClick={() => handleQuickFilter('IN_PROCESS')} isActive={quickFilter === 'IN_PROCESS'}/>
        <StatCard title="Referente" value={stats.referent} icon={Users} color="bg-purple-50 text-purple-600" onClick={() => handleQuickFilter('REFERENT')} isActive={quickFilter === 'REFERENT'}/>
        <StatCard title="Control Gestión" value={stats.control} icon={ShieldCheck} color="bg-orange-50 text-orange-600" onClick={() => handleQuickFilter('CONTROL')} isActive={quickFilter === 'CONTROL'}/>
        <StatCard title="Terminados" value={stats.finished} icon={CheckCircle} color="bg-green-50 text-green-600" onClick={() => handleQuickFilter('FINISHED')} isActive={quickFilter === 'FINISHED'}/>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        <div className="lg:col-span-3 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col min-h-[500px]">
            <div className="p-4 border-b border-slate-100 bg-white">
                <div className="flex items-center justify-between mb-3">
                    <div className="flex items-center gap-2 text-indigo-600 font-semibold text-sm"><Filter size={16} /> Filtros de Visualización</div>
                    {hasActiveFilters && <button onClick={clearFilters} className="text-xs text-red-500 hover:text-red-700 flex items-center gap-1 font-medium"><X size={14} /> Limpiar filtros</button>}
                </div>
                {externalFilterIds ? (
                     <div className="bg-blue-50 border border-blue-100 p-3 rounded-lg mb-2 flex justify-between items-center animate-fadeIn">
                        <span className="text-xs text-blue-700 font-semibold">Filtro Activo: Visualizando {externalFilterIds.length} documentos específicos desde reportes.</span>
                        <button onClick={clearFilters} className="text-xs bg-white border border-blue-200 px-2 py-1 rounded text-blue-600">Mostrar Todo</button>
                     </div>
                ) : (
                    <div className="flex flex-wrap gap-2">
                        <select value={filterProject} onChange={(e) => setFilterProject(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-28">
                            <option value="">PROYECTO</option>
                            {availableProjects.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                        <select value={filterMacro} onChange={(e) => setFilterMacro(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-32">
                            <option value="">MACROPROCESO</option>
                            {availableMacros.map(m => <option key={m} value={m}>{m}</option>)}
                        </select>
                        <select value={filterProcess} onChange={(e) => setFilterProcess(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-32">
                            <option value="">PROCESO</option>
                            {availableProcesses.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                        <div className="relative w-36">
                            <Search size={12} className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400" />
                            <input type="text" value={filterSearch} onChange={(e) => setFilterSearch(e.target.value)} placeholder="BUSCAR..." className="w-full text-[11px] pl-7 p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none" />
                        </div>
                        <select value={filterDocType} onChange={(e) => setFilterDocType(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-24">
                            <option value="">DOC</option>
                            <option value="AS IS">AS IS</option>
                            <option value="FCE">FCE</option>
                            <option value="PM">PM</option>
                            <option value="TO BE">TO BE</option>
                        </select>
                        <select value={filterState} onChange={(e) => setFilterState(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-24">
                            <option value="">ESTADO</option>
                            {Object.entries(STATE_CONFIG).map(([key, cfg]) => <option key={key} value={key}>{cfg.label.split('(')[0]}</option>)}
                        </select>
                        <select value={filterAnalyst} onChange={(e) => setFilterAnalyst(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-32">
                            <option value="">ANALISTA</option>
                            {allUsers.filter(u => u.role === UserRole.ANALYST).map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                        </select>
                    </div>
                )}
            </div>

            <div className="overflow-x-auto flex-1">
                <table className="w-full text-[11px] text-left">
                    <thead className="text-[10px] text-slate-400 uppercase font-bold bg-white border-b border-slate-100">
                        <tr>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('project')}>PROYECTO <SortIcon column="project"/></th>
                            <th className="px-4 py-3">JERARQUÍA (MACRO / PROCESO)</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('microprocess')}>MICROPROCESO <SortIcon column="microprocess"/></th>
                            <th className="px-4 py-3">DOCUMENTO</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('state')}>ESTADO ACTUAL <SortIcon column="state"/></th>
                            <th className="px-4 py-3 text-right cursor-pointer group" onClick={() => handleSort('updatedAt')}>ÚLTIMA ACTIVIDAD <SortIcon column="updatedAt"/></th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                        {paginatedDocs.length === 0 ? (
                            <tr><td colSpan={6} className="p-12 text-center text-slate-400"><Search size={40} className="mx-auto mb-2 opacity-20"/><p>Sin resultados.</p></td></tr>
                        ) : paginatedDocs.map((doc, idx) => (
                            <tr key={`${doc.id}-${idx}`} className={`transition-colors ${!doc.isRequired ? 'bg-gray-100 hover:bg-gray-200' : 'hover:bg-slate-50'}`}>
                                <td className={`px-4 py-3 font-bold align-top ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.project}</td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`font-bold ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.macroprocess}</div>
                                    <div className="text-slate-500 text-[10px]">{doc.process}</div>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`font-bold mb-1 ${!doc.isRequired ? 'text-gray-600' : 'text-slate-800'}`}>{doc.microprocess}</div>
                                    <div className="flex items-center gap-1 text-slate-400" title="Analista Asignado">
                                        <UserIcon size={10} /> <span className="text-[10px] truncate max-w-[120px]">{doc.assignees && doc.assignees.length > 0 ? getUserName(doc.assignees[0]) : 'Sin Asignar'}</span>
                                    </div>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <span className={`inline-block px-1.5 py-0.5 rounded border text-[10px] font-bold mb-1 ${!doc.isRequired ? 'bg-gray-200 text-gray-400 border-gray-300' : 'bg-indigo-50 text-indigo-700 border-indigo-100'}`}>{doc.docType}</span>
                                    <Link to={`/doc/${doc.id}`} state={{ docData: doc }} className="flex items-center gap-1 text-[10px] font-bold text-indigo-500 hover:text-indigo-700 underline">Ver Detalle</Link>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`inline-block px-2 py-0.5 rounded-full text-[10px] font-bold mb-1 border ${!doc.isRequired ? 'bg-gray-200 text-gray-500 border-gray-300' : STATE_CONFIG[doc.state].color}`}>{STATE_CONFIG[doc.state].label.split('(')[0]}</div>
                                    <div className="text-[10px] font-mono text-slate-500">v{doc.version} ({doc.progress}%)</div>
                                </td>
                                <td className="px-4 py-3 align-top text-right">
                                    {doc.state !== DocState.NOT_STARTED ? (
                                        <div className="text-slate-600 font-medium">{new Date(doc.updatedAt).toLocaleDateString()}</div>
                                    ) : <span className="text-slate-300">-</span>}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {totalItems > 0 && (
                <div className="px-4 py-3 border-t border-slate-100 bg-slate-50/50 flex flex-col sm:flex-row items-center justify-between gap-4">
                    <div className="text-[11px] text-slate-500">Mostrando <b>{Math.min(totalItems, (currentPage - 1) * ITEMS_PER_PAGE + 1)}</b> a <b>{Math.min(totalItems, currentPage * ITEMS_PER_PAGE)}</b> de <b>{totalItems}</b> registros</div>
                    <div className="flex items-center gap-2">
                        <button onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))} disabled={currentPage === 1} className="p-1.5 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 disabled:opacity-50"><ChevronLeft size={16} /></button>
                        <div className="flex items-center gap-1">
                            {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                                let pageNum = i + 1;
                                if (totalPages > 5 && currentPage > 3) { pageNum = currentPage - 2 + i; if (pageNum > totalPages) pageNum = totalPages - (4 - i); }
                                return <button key={pageNum} onClick={() => setCurrentPage(pageNum)} className={`w-7 h-7 rounded-lg text-xs font-bold border transition-all ${currentPage === pageNum ? 'bg-indigo-600 text-white' : 'bg-white text-slate-600 hover:border-indigo-400'}`}>{pageNum}</button>;
                            })}
                        </div>
                        <button onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))} disabled={currentPage === totalPages} className="p-1.5 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 disabled:opacity-50"><ChevronRight size={16} /></button>
                    </div>
                </div>
            )}
        </div>

        <div className="lg:col-span-1 space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4 min-h-[250px] flex flex-col items-center justify-center">
                <h3 className="font-bold text-center mb-2 text-slate-700 text-xs uppercase">Estado Universo Requerido</h3>
                {chartData.length > 0 ? (
                    <div className="h-44 w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie data={chartData} cx="50%" cy="50%" innerRadius={45} outerRadius={65} paddingAngle={2} dataKey="value">
                                    {chartData.map((e, i) => <Cell key={i} fill={e.color}/>)}
                                </Pie>
                                <Tooltip contentStyle={{fontSize: '11px', borderRadius: '8px'}}/>
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                ) : <p className="text-center text-slate-400 text-[10px]">Sin datos.</p>}
                <div className="flex flex-wrap justify-center gap-x-3 gap-y-1 mt-2">
                    {chartData.map((d, i) => (
                        <div key={i} className="flex items-center gap-1"><span className="w-2 h-2 rounded-full" style={{backgroundColor: d.color}}></span><span className="text-[9px] text-slate-500 uppercase font-bold">{d.name}</span></div>
                    ))}
                </div>
            </div>
            <div className="bg-indigo-50 rounded-xl shadow-sm border border-indigo-100 p-4">
                <h3 className="font-bold text-indigo-900 text-xs uppercase mb-3">Resumen de Cumplimiento</h3>
                <ul className="space-y-2 text-[11px]">
                    <li className="flex justify-between text-slate-600"><span>No Iniciados:</span> <b>{stats.notStarted}</b></li>
                    <li className="flex justify-between text-blue-600"><span>En Proceso:</span> <b>{stats.inProcess}</b></li>
                    <li className="flex justify-between text-purple-600"><span>Referente:</span> <b>{stats.referent}</b></li>
                    <li className="flex justify-between text-orange-600"><span>Control Gestión:</span> <b>{stats.control}</b></li>
                    <li className="border-t border-indigo-200 pt-1 flex justify-between text-green-600 font-bold"><span>Terminados:</span> <span>{stats.finished}</span></li>
                </ul>
                <div className="mt-4 pt-3 border-t border-indigo-200 text-[9px] text-slate-500 flex items-center gap-2"><Archive size={12} /><span>Registros en <b>GRIS</b> son históricos externos.</span></div>
            </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon: Icon, color, isActive, onClick }: any) => (
    <div onClick={onClick} className={`p-3 rounded-xl shadow-sm border cursor-pointer flex items-center space-x-3 transition-all ${isActive ? 'ring-2 ring-indigo-300 scale-105' : 'hover:border-indigo-300'} ${color} border-transparent`}>
        <div className="p-1.5 bg-white/50 rounded-lg shrink-0"><Icon size={18}/></div>
        <div className="min-w-0">
            <p className="text-[9px] uppercase font-bold opacity-70 truncate">{title}</p>
            <p className="text-lg font-bold leading-none">{value}</p>
        </div>
    </div>
);

export default Dashboard;

import React, { useEffect, useState, useMemo } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService } from '../services/firebaseBackend';
import { Document, User, UserRole, DocState, DocType, FullHierarchy } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    Plus, Clock, CheckCircle, Filter, X, Calendar, ArrowRight, Activity, 
    BookOpen, Users, ShieldCheck, ArrowUp, ArrowDown, ArrowUpDown, Loader2,
    User as UserIcon, Database, AlertTriangle, Archive, PlayCircle, Search,
    ChevronLeft, ChevronRight, FileSpreadsheet
} from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

interface DashboardProps {
  user: User;
}

interface DashboardDoc extends Document {
    isRequired: boolean;
}

type SortKey = 'project' | 'microprocess' | 'state' | 'updatedAt';
type QuickFilterType = 'ALL' | 'NOT_STARTED' | 'IN_PROCESS' | 'REFERENT' | 'CONTROL' | 'FINISHED';

const ITEMS_PER_PAGE = 10;

const getDocTypeOrder = (type: string | undefined): number => {
    switch (type) {
        case 'AS IS': return 1;
        case 'FCE': return 2;
        case 'PM': return 3;
        case 'TO BE': return 4;
        default: return 99;
    }
};

const Dashboard: React.FC<DashboardProps> = ({ user }) => {
  const navigate = useNavigate();
  const location = useLocation(); 

  const [mergedDocs, setMergedDocs] = useState<DashboardDoc[]>([]);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSystemEmpty, setIsSystemEmpty] = useState(false);

  // Filtros de Estado
  const [filterProject, setFilterProject] = useState('');
  const [filterMacro, setFilterMacro] = useState('');
  const [filterProcess, setFilterProcess] = useState('');
  const [filterSearch, setFilterSearch] = useState(''); 
  const [filterDocType, setFilterDocType] = useState('');
  const [filterState, setFilterState] = useState(''); 
  const [filterAnalyst, setFilterAnalyst] = useState('');

  // Paginación
  const [currentPage, setCurrentPage] = useState(1);
  const [externalFilterIds, setExternalFilterIds] = useState<string[] | null>(null);
  const [quickFilter, setQuickFilter] = useState<QuickFilterType>('ALL');

  const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: 'asc' | 'desc' }>({
    key: 'project', 
    direction: 'asc'
  });

  useEffect(() => {
    if (location.state?.filterIds && Array.isArray(location.state.filterIds)) {
        setExternalFilterIds(location.state.filterIds);
        setQuickFilter('ALL');
    } else {
        setExternalFilterIds(null);
    }
    loadData();
  }, [location.state]);

  useEffect(() => {
    setCurrentPage(1);
  }, [filterProject, filterMacro, filterProcess, filterSearch, filterDocType, filterState, filterAnalyst, quickFilter, sortConfig]);

  const normalize = (str: string | undefined) => {
      if (!str) return '';
      return str.trim().toUpperCase().normalize("NFD").replace(/[\u0300Host\u036f]/g, "");
  };

  const loadData = async () => {
    setLoading(true);
    try {
        const [realDocsData, users, fullHierarchy] = await Promise.all([
            DocumentService.getAll(),
            UserService.getAll(),
            HierarchyService.getFullHierarchy()
        ]);

        setAllUsers(users);
        const hierarchyKeys = Object.keys(fullHierarchy);

        if (hierarchyKeys.length === 0 && realDocsData.length === 0) {
            setIsSystemEmpty(true);
            setMergedDocs([]);
            setLoading(false);
            return;
        }
        setIsSystemEmpty(false);

        const realDocMap = new Map<string, Document>();
        const processedDocIds = new Set<string>();

        realDocsData.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalize(doc.project)}|${normalize(microName)}|${normalize(docType)}`;

                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        const finalDocsList: DashboardDoc[] = [];

        hierarchyKeys.forEach(proj => {
            Object.keys(fullHierarchy[proj]).forEach(macro => {
                Object.keys(fullHierarchy[proj][macro]).forEach(proc => {
                    const nodes = fullHierarchy[proj][macro][proc];
                    nodes.forEach(node => {
                        if (node.active === false) return; 

                        const requiredTypes = (node.requiredTypes && node.requiredTypes.length > 0) 
                            ? node.requiredTypes 
                            : ['AS IS', 'FCE', 'PM', 'TO BE'];

                        requiredTypes.forEach(type => {
                            const key = `${normalize(proj)}|${normalize(node.name)}|${normalize(type)}`;

                            if (realDocMap.has(key)) {
                                const realDoc = realDocMap.get(key)!;
                                finalDocsList.push({
                                    ...realDoc,
                                    macroprocess: macro,
                                    process: proc,
                                    project: proj,
                                    assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []),
                                    isRequired: true 
                                });
                                processedDocIds.add(realDoc.id); 
                            } else {
                                finalDocsList.push({
                                    id: `virtual-${key}`, 
                                    title: `${node.name} - ${type}`,
                                    description: 'Pendiente de inicio',
                                    project: proj,
                                    macroprocess: macro,
                                    process: proc,
                                    microprocess: node.name,
                                    docType: type as DocType,
                                    authorId: '',
                                    authorName: '',
                                    assignedTo: node.assignees?.[0] || '',
                                    assignees: node.assignees || [],
                                    state: DocState.NOT_STARTED,
                                    version: '-',
                                    progress: 0,
                                    files: [],
                                    createdAt: new Date().toISOString(),
                                    updatedAt: new Date(0).toISOString(), 
                                    hasPendingRequest: false,
                                    isRequired: true 
                                });
                            }
                        });
                    });
                });
            });
        });

        realDocMap.forEach((doc) => {
            if (!processedDocIds.has(doc.id)) {
                finalDocsList.push({
                    ...doc,
                    macroprocess: doc.macroprocess || 'Sin Clasificar',
                    process: doc.process || 'Sin Clasificar',
                    isRequired: false 
                });
            }
        });

        setMergedDocs(finalDocsList);

    } catch (error) {
        console.error("Error loading dashboard data:", error);
    } finally {
        setLoading(false);
    }
  };

  const contextDocs = useMemo(() => {
      let filtered = mergedDocs;

      if (externalFilterIds && externalFilterIds.length > 0) {
          filtered = filtered.filter(d => externalFilterIds.includes(d.id));
      } else {
          if (filterProject) filtered = filtered.filter(d => d.project === filterProject);
          if (filterMacro) filtered = filtered.filter(d => d.macroprocess === filterMacro);
          if (filterProcess) filtered = filtered.filter(d => d.process === filterProcess);
          if (filterDocType) filtered = filtered.filter(d => d.docType === filterDocType);
          if (filterState) filtered = filtered.filter(d => d.state === filterState);
          if (filterAnalyst) filtered = filtered.filter(d => d.assignees && d.assignees.includes(filterAnalyst));

          if (filterSearch) {
              const term = filterSearch.toLowerCase();
              filtered = filtered.filter(d => 
                  (d.microprocess || '').toLowerCase().includes(term) || 
                  (d.title || '').toLowerCase().includes(term)
              );
          }
      }

      return filtered;
  }, [mergedDocs, filterProject, filterMacro, filterProcess, filterDocType, filterState, filterAnalyst, filterSearch, externalFilterIds]);

  const stats = useMemo(() => {
      const requiredDocs = contextDocs.filter(d => d.isRequired);

      return {
        total: requiredDocs.length,
        notStarted: requiredDocs.filter(d => d.state === DocState.NOT_STARTED).length,
        inProcess: requiredDocs.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW).length,
        referent: requiredDocs.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW).length,
        control: requiredDocs.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW).length,
        finished: requiredDocs.filter(d => d.state === DocState.APPROVED).length
      };
  }, [contextDocs]);

  // Fix: Added chartData useMemo to resolve missing variable errors in the pie chart section.
  const chartData = useMemo(() => {
    return [
      { name: 'No Iniciado', value: stats.notStarted, color: '#94a3b8' },
      { name: 'En Proceso', value: stats.inProcess, color: '#3b82f6' },
      { name: 'Referente', value: stats.referent, color: '#a855f7' },
      { name: 'Control', value: stats.control, color: '#f97316' },
      { name: 'Terminados', value: stats.finished, color: '#22c55e' }
    ].filter(d => d.value > 0);
  }, [stats]);

  const tableDocs = useMemo(() => {
      let filtered = contextDocs;

      if (quickFilter !== 'ALL') {
          switch (quickFilter) {
              case 'NOT_STARTED': filtered = filtered.filter(d => d.state === DocState.NOT_STARTED); break;
              case 'IN_PROCESS': filtered = filtered.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW); break;
              case 'REFERENT': filtered = filtered.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW); break;
              case 'CONTROL': filtered = filtered.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW); break;
              case 'FINISHED': filtered = filtered.filter(d => d.state === DocState.APPROVED); break;
          }
      }
      return filtered;
  }, [contextDocs, quickFilter]);

  const sortedDocs = useMemo(() => {
      return [...tableDocs].sort((a, b) => {
          if (a.isRequired !== b.isRequired) {
              return a.isRequired ? -1 : 1;
          }

          const modifier = sortConfig.direction === 'asc' ? 1 : -1;

          switch (sortConfig.key) {
              case 'updatedAt': 
                  const timeA = new Date(a.updatedAt).getTime();
                  const timeB = new Date(b.updatedAt).getTime();
                  return (timeA - timeB) * modifier;

              case 'project': 
                  if ((a.project || '') !== (b.project || '')) return (a.project || '').localeCompare(b.project || '') * modifier;
                  if ((a.macroprocess || '') !== (b.macroprocess || '')) return (a.macroprocess || '').localeCompare(b.macroprocess || '') * modifier;
                  if ((a.process || '') !== (b.process || '')) return (a.process || '').localeCompare(b.process || '') * modifier;
                  if ((a.microprocess || '') !== (b.microprocess || '')) return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
                  return (getDocTypeOrder(a.docType) - getDocTypeOrder(b.docType)) * modifier;

              case 'microprocess': return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
              case 'state': return (a.progress - b.progress) * modifier;
              default: return 0;
          }
      });
  }, [tableDocs, sortConfig]);

  const totalItems = sortedDocs.length;
  const totalPages = Math.ceil(totalItems / ITEMS_PER_PAGE);
  const paginatedDocs = useMemo(() => {
      const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
      return sortedDocs.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [sortedDocs, currentPage]);

  const handleExportExcel = () => {
      if (sortedDocs.length === 0) return;
      const getUserNames = (ids: string[]) => ids.map(id => allUsers.find(u => u.id === id)?.name || id).join('; ');

      const headers = ['PROYECTO', 'MACROPROCESO', 'PROCESO', 'MICROPROCESO', 'ANALISTA', 'DOCUMENTO', 'VERSION', 'ESTADO', 'FECHA'];
      const rows = sortedDocs.map(d => {
          // Formateo de fecha DD-MM-YYYY sin hora
          let fechaStr = 'Sin actividad';
          if (d.state !== DocState.NOT_STARTED && d.updatedAt) {
              const date = new Date(d.updatedAt);
              const day = String(date.getDate()).padStart(2, '0');
              const month = String(date.getMonth() + 1).padStart(2, '0');
              const year = date.getFullYear();
              fechaStr = `${day}-${month}-${year}`;
          }

          return [
              d.project || '-',
              d.macroprocess || '-',
              d.process || '-',
              d.microprocess || '-',
              getUserNames(d.assignees || []),
              d.docType || '-',
              d.version || '-',
              STATE_CONFIG[d.state]?.label.split('(')[0] || '-',
              fechaStr
          ];
      });

      const csvContent = [headers.join(';'), ...rows.map(r => r.map(cell => `"${cell}"`).join(';'))].join('\n');
      const blob = new Blob(["\ufeff", csvContent], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.setAttribute('href', url);
      link.setAttribute('download', `SGD_Reporte_${new Date().toISOString().split('T')[0]}.csv`);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
  };

  const handleSort = (key: SortKey) => {
      setSortConfig({ key, direction: sortConfig.key === key && sortConfig.direction === 'asc' ? 'desc' : 'asc' });
  };

  // Added handleQuickFilter to fix missing reference errors in StatCard usages
  const handleQuickFilter = (type: QuickFilterType) => {
    setQuickFilter(type);
    setCurrentPage(1);
  };

  const clearFilters = () => {
      setFilterProject(''); setFilterMacro(''); setFilterProcess(''); setFilterSearch(''); 
      setFilterDocType(''); setFilterState(''); setFilterAnalyst(''); setQuickFilter('ALL');
      setExternalFilterIds(null); navigate(location.pathname, { replace: true, state: {} });
  };

  const SortIcon = ({ column }: { column: SortKey }) => (
      sortConfig.key === column ? (sortConfig.direction === 'asc' ? <ArrowUp size={12} className="text-indigo-600"/> : <ArrowDown size={12} className="text-indigo-600"/>) : <ArrowUpDown size={12} className="opacity-30 group-hover:opacity-100"/>
  );

  const availableProjects = useMemo(() => Array.from(new Set(mergedDocs.map(d => d.project).filter(Boolean))).sort(), [mergedDocs]);
  const availableMacros = useMemo(() => {
      const docs = filterProject ? mergedDocs.filter(d => d.project === filterProject) : mergedDocs;
      return Array.from(new Set(docs.map(d => d.macroprocess).filter(Boolean))).sort();
  }, [mergedDocs, filterProject]);
  const availableProcesses = useMemo(() => {
      let docs = mergedDocs;
      if (filterProject) docs = docs.filter(d => d.project === filterProject);
      if (filterMacro) docs = docs.filter(d => d.macroprocess === filterMacro);
      return Array.from(new Set(docs.map(d => d.process).filter(Boolean))).sort();
  }, [mergedDocs, filterProject, filterMacro]);

  const getUserName = (id: string) => allUsers.find(user => user.id === id)?.name || 'Sin Asignar';

  if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Actualizando dashboard...</div>;

  if (isSystemEmpty) {
      return (
          <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6 bg-white rounded-xl shadow-sm border border-slate-200">
              <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center mb-6"><Database size={40} className="text-indigo-600" /></div>
              <h2 className="text-2xl font-bold text-slate-900 mb-2">Sistema sin Inicializar</h2>
              <p className="text-slate-500 max-w-md mb-8">La matriz de procesos está vacía. Cargue la estructura de procesos para comenzar.</p>
              {(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) && (
                  <Link to="/admin/assignments" className="flex items-center px-6 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-medium shadow-md transition-transform active:scale-95">
                      <Database size={18} className="mr-2" /> Ir a Carga de Datos
                  </Link>
              )}
          </div>
      );
  }

  const hasActiveFilters = filterProject || filterMacro || filterProcess || filterSearch || filterDocType || filterState || filterAnalyst || externalFilterIds;

  return (
    <div className="space-y-6 pb-12">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div><h1 className="text-2xl font-bold text-slate-900">Dashboard</h1><p className="text-slate-500">Vista general de avance institucional</p></div>
        <div className="flex items-center gap-2 w-full sm:w-auto">
            <button onClick={handleExportExcel} className="flex-1 sm:flex-none px-4 py-2 bg-white border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 flex items-center justify-center shadow-sm font-medium transition-colors">
                <FileSpreadsheet size={18} className="mr-2 text-green-600"/> <span className="hidden md:inline">Exportar Excel</span><span className="md:hidden">Excel</span>
            </button>
            {user.role === UserRole.ANALYST && <Link to="/new" className="flex-1 sm:flex-none px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 flex items-center justify-center shadow-sm font-medium"><Plus size={18} className="mr-2"/> Nueva Solicitud</Link>}
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-3">
        <StatCard title="Doc. Requeridos" value={stats.total} icon={BookOpen} color="bg-slate-50 text-slate-600" onClick={() => handleQuickFilter('ALL')} isActive={quickFilter === 'ALL'}/>
        <StatCard title="No Iniciado" value={stats.notStarted} icon={Clock} color="bg-white text-slate-600" onClick={() => handleQuickFilter('NOT_STARTED')} isActive={quickFilter === 'NOT_STARTED'}/>
        <StatCard title="En Proceso" value={stats.inProcess} icon={Activity} color="bg-blue-50 text-blue-600" onClick={() => handleQuickFilter('IN_PROCESS')} isActive={quickFilter === 'IN_PROCESS'}/>
        <StatCard title="Referente" value={stats.referent} icon={Users} color="bg-purple-50 text-purple-600" onClick={() => handleQuickFilter('REFERENT')} isActive={quickFilter === 'REFERENT'}/>
        <StatCard title="Control Gestión" value={stats.control} icon={ShieldCheck} color="bg-orange-50 text-orange-600" onClick={() => handleQuickFilter('CONTROL')} isActive={quickFilter === 'CONTROL'}/>
        <StatCard title="Terminados" value={stats.finished} icon={CheckCircle} color="bg-green-50 text-green-600" onClick={() => handleQuickFilter('FINISHED')} isActive={quickFilter === 'FINISHED'}/>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        <div className="lg:col-span-3 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col min-h-[500px]">
            <div className="p-4 border-b border-slate-100 bg-white">
                <div className="flex items-center justify-between mb-3">
                    <div className="flex items-center gap-2 text-indigo-600 font-semibold text-sm"><Filter size={16} /> Filtros de Visualización</div>
                    {hasActiveFilters && <button onClick={clearFilters} className="text-xs text-red-500 hover:text-red-700 flex items-center gap-1 font-medium"><X size={14} /> Limpiar filtros</button>}
                </div>
                {externalFilterIds ? (
                     <div className="bg-blue-50 border border-blue-100 p-3 rounded-lg mb-2 flex justify-between items-center animate-fadeIn">
                        <span className="text-xs text-blue-700 font-semibold">Filtro Activo: Visualizando {externalFilterIds.length} documentos específicos desde reportes.</span>
                        <button onClick={clearFilters} className="text-xs bg-white border border-blue-200 px-2 py-1 rounded text-blue-600">Mostrar Todo</button>
                     </div>
                ) : (
                    <div className="flex flex-wrap gap-2">
                        <select value={filterProject} onChange={(e) => setFilterProject(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-28">
                            <option value="">PROYECTO</option>
                            {availableProjects.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                        <select value={filterMacro} onChange={(e) => setFilterMacro(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-32">
                            <option value="">MACROPROCESO</option>
                            {availableMacros.map(m => <option key={m} value={m}>{m}</option>)}
                        </select>
                        <select value={filterProcess} onChange={(e) => setFilterProcess(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-32">
                            <option value="">PROCESO</option>
                            {availableProcesses.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                        <div className="relative w-36">
                            <Search size={12} className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400" />
                            <input type="text" value={filterSearch} onChange={(e) => setFilterSearch(e.target.value)} placeholder="BUSCAR..." className="w-full text-[11px] pl-7 p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none" />
                        </div>
                        <select value={filterDocType} onChange={(e) => setFilterDocType(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-24">
                            <option value="">DOC</option>
                            <option value="AS IS">AS IS</option>
                            <option value="FCE">FCE</option>
                            <option value="PM">PM</option>
                            <option value="TO BE">TO BE</option>
                        </select>
                        <select value={filterState} onChange={(e) => setFilterState(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-24">
                            <option value="">ESTADO</option>
                            {Object.entries(STATE_CONFIG).map(([key, cfg]) => <option key={key} value={key}>{cfg.label.split('(')[0]}</option>)}
                        </select>
                        <select value={filterAnalyst} onChange={(e) => setFilterAnalyst(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-32">
                            <option value="">ANALISTA</option>
                            {allUsers.filter(u => u.role === UserRole.ANALYST).map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                        </select>
                    </div>
                )}
            </div>

            <div className="overflow-x-auto flex-1">
                <table className="w-full text-[11px] text-left">
                    <thead className="text-[10px] text-slate-400 uppercase font-bold bg-white border-b border-slate-100">
                        <tr>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('project')}>PROYECTO <SortIcon column="project"/></th>
                            <th className="px-4 py-3">JERARQUÍA (MACRO / PROCESO)</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('microprocess')}>MICROPROCESO <SortIcon column="microprocess"/></th>
                            <th className="px-4 py-3">DOCUMENTO</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('state')}>ESTADO ACTUAL <SortIcon column="state"/></th>
                            <th className="px-4 py-3 text-right cursor-pointer group" onClick={() => handleSort('updatedAt')}>ÚLTIMA ACTIVIDAD <SortIcon column="updatedAt"/></th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                        {paginatedDocs.length === 0 ? (
                            <tr><td colSpan={6} className="p-12 text-center text-slate-400"><Search size={40} className="mx-auto mb-2 opacity-20"/><p>Sin resultados.</p></td></tr>
                        ) : paginatedDocs.map((doc, idx) => (
                            <tr key={`${doc.id}-${idx}`} className={`transition-colors ${!doc.isRequired ? 'bg-gray-100 hover:bg-gray-200' : 'hover:bg-slate-50'}`}>
                                <td className={`px-4 py-3 font-bold align-top ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.project}</td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`font-bold ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.macroprocess}</div>
                                    <div className="text-slate-500 text-[10px]">{doc.process}</div>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`font-bold mb-1 ${!doc.isRequired ? 'text-gray-600' : 'text-slate-800'}`}>{doc.microprocess}</div>
                                    <div className="flex items-center gap-1 text-slate-400" title="Analista Asignado">
                                        <UserIcon size={10} /> <span className="text-[10px] truncate max-w-[120px]">{doc.assignees && doc.assignees.length > 0 ? getUserName(doc.assignees[0]) : 'Sin Asignar'}</span>
                                    </div>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <span className={`inline-block px-1.5 py-0.5 rounded border text-[10px] font-bold mb-1 ${!doc.isRequired ? 'bg-gray-200 text-gray-400 border-gray-300' : 'bg-indigo-50 text-indigo-700 border-indigo-100'}`}>{doc.docType}</span>
                                    <Link to={`/doc/${doc.id}`} state={{ docData: doc }} className="flex items-center gap-1 text-[10px] font-bold text-indigo-500 hover:text-indigo-700 underline">Ver Detalle</Link>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`inline-block px-2 py-0.5 rounded-full text-[10px] font-bold mb-1 border ${!doc.isRequired ? 'bg-gray-200 text-gray-500 border-gray-300' : STATE_CONFIG[doc.state].color}`}>{STATE_CONFIG[doc.state].label.split('(')[0]}</div>
                                    <div className="text-[10px] font-mono text-slate-500">v{doc.version} ({doc.progress}%)</div>
                                </td>
                                <td className="px-4 py-3 align-top text-right">
                                    {doc.state !== DocState.NOT_STARTED ? (
                                        <div className="text-slate-600 font-medium">{new Date(doc.updatedAt).toLocaleDateString()}</div>
                                    ) : <span className="text-slate-300">-</span>}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {totalItems > 0 && (
                <div className="px-4 py-3 border-t border-slate-100 bg-slate-50/50 flex flex-col sm:flex-row items-center justify-between gap-4">
                    <div className="text-[11px] text-slate-500">Mostrando <b>{Math.min(totalItems, (currentPage - 1) * ITEMS_PER_PAGE + 1)}</b> a <b>{Math.min(totalItems, currentPage * ITEMS_PER_PAGE)}</b> de <b>{totalItems}</b> registros</div>
                    <div className="flex items-center gap-2">
                        <button onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))} disabled={currentPage === 1} className="p-1.5 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 disabled:opacity-50"><ChevronLeft size={16} /></button>
                        <div className="flex items-center gap-1">
                            {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                                let pageNum = i + 1;
                                if (totalPages > 5 && currentPage > 3) { pageNum = currentPage - 2 + i; if (pageNum > totalPages) pageNum = totalPages - (4 - i); }
                                return <button key={pageNum} onClick={() => setCurrentPage(pageNum)} className={`w-7 h-7 rounded-lg text-xs font-bold border transition-all ${currentPage === pageNum ? 'bg-indigo-600 text-white' : 'bg-white text-slate-600 hover:border-indigo-400'}`}>{pageNum}</button>;
                            })}
                        </div>
                        <button onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))} disabled={currentPage === totalPages} className="p-1.5 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 disabled:opacity-50"><ChevronRight size={16} /></button>
                    </div>
                </div>
            )}
        </div>

        <div className="lg:col-span-1 space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4 min-h-[250px] flex flex-col items-center justify-center">
                <h3 className="font-bold text-center mb-2 text-slate-700 text-xs uppercase">Estado Universo Requerido</h3>
                {chartData.length > 0 ? (
                    <div className="h-44 w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie data={chartData} cx="50%" cy="50%" innerRadius={45} outerRadius={65} paddingAngle={2} dataKey="value">
                                    {chartData.map((e, i) => <Cell key={i} fill={e.color}/>)}
                                </Pie>
                                <Tooltip contentStyle={{fontSize: '11px', borderRadius: '8px'}}/>
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                ) : <p className="text-center text-slate-400 text-[10px]">Sin datos.</p>}
                <div className="flex flex-wrap justify-center gap-x-3 gap-y-1 mt-2">
                    {chartData.map((d, i) => (
                        <div key={i} className="flex items-center gap-1"><span className="w-2 h-2 rounded-full" style={{backgroundColor: d.color}}></span><span className="text-[9px] text-slate-500 uppercase font-bold">{d.name}</span></div>
                    ))}
                </div>
            </div>
            <div className="bg-indigo-50 rounded-xl shadow-sm border border-indigo-100 p-4">
                <h3 className="font-bold text-indigo-900 text-xs uppercase mb-3">Resumen de Cumplimiento</h3>
                <ul className="space-y-2 text-[11px]">
                    <li className="flex justify-between text-slate-600"><span>No Iniciados:</span> <b>{stats.notStarted}</b></li>
                    <li className="flex justify-between text-blue-600"><span>En Proceso:</span> <b>{stats.inProcess}</b></li>
                    <li className="flex justify-between text-purple-600"><span>Referente:</span> <b>{stats.referent}</b></li>
                    <li className="flex justify-between text-orange-600"><span>Control Gestión:</span> <b>{stats.control}</b></li>
                    <li className="border-t border-indigo-200 pt-1 flex justify-between text-green-600 font-bold"><span>Terminados:</span> <span>{stats.finished}</span></li>
                </ul>
                <div className="mt-4 pt-3 border-t border-indigo-200 text-[9px] text-slate-500 flex items-center gap-2"><Archive size={12} /><span>Registros en <b>GRIS</b> son históricos externos.</span></div>
            </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon: Icon, color, isActive, onClick }: any) => (
    <div onClick={onClick} className={`p-3 rounded-xl shadow-sm border cursor-pointer flex items-center space-x-3 transition-all ${isActive ? 'ring-2 ring-indigo-300 scale-105' : 'hover:border-indigo-300'} ${color} border-transparent`}>
        <div className="p-1.5 bg-white/50 rounded-lg shrink-0"><Icon size={18}/></div>
        <div className="min-w-0">
            <p className="text-[9px] uppercase font-bold opacity-70 truncate">{title}</p>
            <p className="text-lg font-bold leading-none">{value}</p>
        </div>
    </div>
);

export default Dashboard;

import React, { useEffect, useState, useMemo } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService } from '../services/firebaseBackend';
import { Document, User, UserRole, DocState, DocType, FullHierarchy } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    Plus, Clock, CheckCircle, Filter, X, Calendar, ArrowRight, Activity, 
    BookOpen, Users, ShieldCheck, ArrowUp, ArrowDown, ArrowUpDown, Loader2,
    User as UserIcon, Database, AlertTriangle, Archive, PlayCircle, Search,
    ChevronLeft, ChevronRight, FileSpreadsheet
} from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

interface DashboardProps {
  user: User;
}

interface DashboardDoc extends Document {
    isRequired: boolean;
}

type SortKey = 'project' | 'microprocess' | 'state' | 'updatedAt';
type QuickFilterType = 'ALL' | 'NOT_STARTED' | 'IN_PROCESS' | 'REFERENT' | 'CONTROL' | 'FINISHED';

const ITEMS_PER_PAGE = 10;

const getDocTypeOrder = (type: string | undefined): number => {
    switch (type) {
        case 'AS IS': return 1;
        case 'FCE': return 2;
        case 'PM': return 3;
        case 'TO BE': return 4;
        default: return 99;
    }
};

const Dashboard: React.FC<DashboardProps> = ({ user }) => {
  const navigate = useNavigate();
  const location = useLocation(); 

  const [mergedDocs, setMergedDocs] = useState<DashboardDoc[]>([]);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSystemEmpty, setIsSystemEmpty] = useState(false);

  // Filtros de Estado
  const [filterProject, setFilterProject] = useState('');
  const [filterMacro, setFilterMacro] = useState('');
  const [filterProcess, setFilterProcess] = useState('');
  const [filterSearch, setFilterSearch] = useState(''); 
  const [filterDocType, setFilterDocType] = useState('');
  const [filterState, setFilterState] = useState(''); 
  const [filterAnalyst, setFilterAnalyst] = useState('');

  // Paginación
  const [currentPage, setCurrentPage] = useState(1);
  const [externalFilterIds, setExternalFilterIds] = useState<string[] | null>(null);
  const [quickFilter, setQuickFilter] = useState<QuickFilterType>('ALL');

  const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: 'asc' | 'desc' }>({
    key: 'project', 
    direction: 'asc'
  });

  useEffect(() => {
    if (location.state?.filterIds && Array.isArray(location.state.filterIds)) {
        setExternalFilterIds(location.state.filterIds);
        setQuickFilter('ALL');
    } else {
        setExternalFilterIds(null);
    }
    loadData();
  }, [location.state]);

  useEffect(() => {
    setCurrentPage(1);
  }, [filterProject, filterMacro, filterProcess, filterSearch, filterDocType, filterState, filterAnalyst, quickFilter, sortConfig]);

  const normalize = (str: string | undefined) => {
      if (!str) return '';
      return str.trim().toUpperCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  };

  const loadData = async () => {
    setLoading(true);
    try {
        const [realDocsData, users, fullHierarchy] = await Promise.all([
            DocumentService.getAll(),
            UserService.getAll(),
            HierarchyService.getFullHierarchy()
        ]);

        setAllUsers(users);
        const hierarchyKeys = Object.keys(fullHierarchy);

        if (hierarchyKeys.length === 0 && realDocsData.length === 0) {
            setIsSystemEmpty(true);
            setMergedDocs([]);
            setLoading(false);
            return;
        }
        setIsSystemEmpty(false);

        const realDocMap = new Map<string, Document>();
        const processedDocIds = new Set<string>();

        realDocsData.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalize(doc.project)}|${normalize(microName)}|${normalize(docType)}`;

                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        const finalDocsList: DashboardDoc[] = [];

        hierarchyKeys.forEach(proj => {
            Object.keys(fullHierarchy[proj]).forEach(macro => {
                Object.keys(fullHierarchy[proj][macro]).forEach(proc => {
                    const nodes = fullHierarchy[proj][macro][proc];
                    nodes.forEach(node => {
                        if (node.active === false) return; 

                        const requiredTypes = (node.requiredTypes && node.requiredTypes.length > 0) 
                            ? node.requiredTypes 
                            : ['AS IS', 'FCE', 'PM', 'TO BE'];

                        requiredTypes.forEach(type => {
                            const key = `${normalize(proj)}|${normalize(node.name)}|${normalize(type)}`;

                            if (realDocMap.has(key)) {
                                const realDoc = realDocMap.get(key)!;
                                finalDocsList.push({
                                    ...realDoc,
                                    macroprocess: macro,
                                    process: proc,
                                    project: proj,
                                    assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []),
                                    isRequired: true 
                                });
                                processedDocIds.add(realDoc.id); 
                            } else {
                                finalDocsList.push({
                                    id: `virtual-${key}`, 
                                    title: `${node.name} - ${type}`,
                                    description: 'Pendiente de inicio',
                                    project: proj,
                                    macroprocess: macro,
                                    process: proc,
                                    microprocess: node.name,
                                    docType: type as DocType,
                                    authorId: '',
                                    authorName: '',
                                    assignedTo: node.assignees?.[0] || '',
                                    assignees: node.assignees || [],
                                    state: DocState.NOT_STARTED,
                                    version: '-',
                                    progress: 0,
                                    files: [],
                                    createdAt: new Date().toISOString(),
                                    updatedAt: new Date(0).toISOString(), 
                                    hasPendingRequest: false,
                                    isRequired: true 
                                });
                            }
                        });
                    });
                });
            });
        });

        realDocMap.forEach((doc) => {
            if (!processedDocIds.has(doc.id)) {
                finalDocsList.push({
                    ...doc,
                    macroprocess: doc.macroprocess || 'Sin Clasificar',
                    process: doc.process || 'Sin Clasificar',
                    isRequired: false 
                });
            }
        });

        setMergedDocs(finalDocsList);

    } catch (error) {
        console.error("Error loading dashboard data:", error);
    } finally {
        setLoading(false);
    }
  };

  const contextDocs = useMemo(() => {
      let filtered = mergedDocs;

      if (externalFilterIds && externalFilterIds.length > 0) {
          filtered = filtered.filter(d => externalFilterIds.includes(d.id));
      } else {
          if (filterProject) filtered = filtered.filter(d => d.project === filterProject);
          if (filterMacro) filtered = filtered.filter(d => d.macroprocess === filterMacro);
          if (filterProcess) filtered = filtered.filter(d => d.process === filterProcess);
          if (filterDocType) filtered = filtered.filter(d => d.docType === filterDocType);
          if (filterState) filtered = filtered.filter(d => d.state === filterState);
          if (filterAnalyst) filtered = filtered.filter(d => d.assignees && d.assignees.includes(filterAnalyst));

          if (filterSearch) {
              const term = filterSearch.toLowerCase();
              filtered = filtered.filter(d => 
                  (d.microprocess || '').toLowerCase().includes(term) || 
                  (d.title || '').toLowerCase().includes(term)
              );
          }
      }

      return filtered;
  }, [mergedDocs, filterProject, filterMacro, filterProcess, filterDocType, filterState, filterAnalyst, filterSearch, externalFilterIds]);

  const stats = useMemo(() => {
      const requiredDocs = contextDocs.filter(d => d.isRequired);

      return {
        total: requiredDocs.length,
        notStarted: requiredDocs.filter(d => d.state === DocState.NOT_STARTED).length,
        inProcess: requiredDocs.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW).length,
        referent: requiredDocs.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW).length,
        control: requiredDocs.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW).length,
        finished: requiredDocs.filter(d => d.state === DocState.APPROVED).length
      };
  }, [contextDocs]);

  // Fix: Added chartData useMemo to resolve missing variable errors in the pie chart section.
  const chartData = useMemo(() => {
    return [
      { name: 'No Iniciado', value: stats.notStarted, color: '#94a3b8' },
      { name: 'En Proceso', value: stats.inProcess, color: '#3b82f6' },
      { name: 'Referente', value: stats.referent, color: '#a855f7' },
      { name: 'Control', value: stats.control, color: '#f97316' },
      { name: 'Terminados', value: stats.finished, color: '#22c55e' }
    ].filter(d => d.value > 0);
  }, [stats]);

  const tableDocs = useMemo(() => {
      let filtered = contextDocs;

      if (quickFilter !== 'ALL') {
          switch (quickFilter) {
              case 'NOT_STARTED': filtered = filtered.filter(d => d.state === DocState.NOT_STARTED); break;
              case 'IN_PROCESS': filtered = filtered.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW); break;
              case 'REFERENT': filtered = filtered.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW); break;
              case 'CONTROL': filtered = filtered.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW); break;
              case 'FINISHED': filtered = filtered.filter(d => d.state === DocState.APPROVED); break;
          }
      }
      return filtered;
  }, [contextDocs, quickFilter]);

  const sortedDocs = useMemo(() => {
      return [...tableDocs].sort((a, b) => {
          if (a.isRequired !== b.isRequired) {
              return a.isRequired ? -1 : 1;
          }

          const modifier = sortConfig.direction === 'asc' ? 1 : -1;

          switch (sortConfig.key) {
              case 'updatedAt': 
                  const timeA = new Date(a.updatedAt).getTime();
                  const timeB = new Date(b.updatedAt).getTime();
                  return (timeA - timeB) * modifier;

              case 'project': 
                  if ((a.project || '') !== (b.project || '')) return (a.project || '').localeCompare(b.project || '') * modifier;
                  if ((a.macroprocess || '') !== (b.macroprocess || '')) return (a.macroprocess || '').localeCompare(b.macroprocess || '') * modifier;
                  if ((a.process || '') !== (b.process || '')) return (a.process || '').localeCompare(b.process || '') * modifier;
                  if ((a.microprocess || '') !== (b.microprocess || '')) return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
                  return (getDocTypeOrder(a.docType) - getDocTypeOrder(b.docType)) * modifier;

              case 'microprocess': return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
              case 'state': return (a.progress - b.progress) * modifier;
              default: return 0;
          }
      });
  }, [tableDocs, sortConfig]);

  const totalItems = sortedDocs.length;
  const totalPages = Math.ceil(totalItems / ITEMS_PER_PAGE);
  const paginatedDocs = useMemo(() => {
      const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
      return sortedDocs.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [sortedDocs, currentPage]);

  const handleExportExcel = () => {
      if (sortedDocs.length === 0) return;
      const getUserNames = (ids: string[]) => ids.map(id => allUsers.find(u => u.id === id)?.name || id).join('; ');

      // Orden definitivo solicitado: PROYECTO, MACROPROCESO, PROCESO, MICROPROCESO, DOCUMENTO, VERSION, ESTADO, FECHA, ANALISTA
      const headers = ['PROYECTO', 'MACROPROCESO', 'PROCESO', 'MICROPROCESO', 'DOCUMENTO', 'VERSION', 'ESTADO', 'FECHA', 'ANALISTA'];
      const rows = sortedDocs.map(d => {
          // Formateo de fecha DD-MM-YYYY sin hora
          let fechaStr = 'Sin actividad';
          if (d.state !== DocState.NOT_STARTED && d.updatedAt) {
              const date = new Date(d.updatedAt);
              const day = String(date.getDate()).padStart(2, '0');
              const month = String(date.getMonth() + 1).padStart(2, '0');
              const year = date.getFullYear();
              fechaStr = `${day}-${month}-${year}`;
          }

          return [
              d.project || '-',
              d.macroprocess || '-',
              d.process || '-',
              d.microprocess || '-',
              d.docType || '-',
              d.version || '-',
              STATE_CONFIG[d.state]?.label.split('(')[0] || '-',
              fechaStr,
              getUserNames(d.assignees || [])
          ];
      });

      const csvContent = [headers.join(';'), ...rows.map(r => r.map(cell => `"${cell}"`).join(';'))].join('\n');
      const blob = new Blob(["\ufeff", csvContent], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.setAttribute('href', url);
      link.setAttribute('download', `SGD_Reporte_${new Date().toISOString().split('T')[0]}.csv`);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
  };

  const handleSort = (key: SortKey) => {
      setSortConfig({ key, direction: sortConfig.key === key && sortConfig.direction === 'asc' ? 'desc' : 'asc' });
  };

  // Added handleQuickFilter to fix missing reference errors in StatCard usages
  const handleQuickFilter = (type: QuickFilterType) => {
    setQuickFilter(type);
    setCurrentPage(1);
  };

  const clearFilters = () => {
      setFilterProject(''); setFilterMacro(''); setFilterProcess(''); setFilterSearch(''); 
      setFilterDocType(''); setFilterState(''); setFilterAnalyst(''); setQuickFilter('ALL');
      setExternalFilterIds(null); navigate(location.pathname, { replace: true, state: {} });
  };

  const SortIcon = ({ column }: { column: SortKey }) => (
      sortConfig.key === column ? (sortConfig.direction === 'asc' ? <ArrowUp size={12} className="text-indigo-600"/> : <ArrowDown size={12} className="text-indigo-600"/>) : <ArrowUpDown size={12} className="opacity-30 group-hover:opacity-100"/>
  );

  const availableProjects = useMemo(() => Array.from(new Set(mergedDocs.map(d => d.project).filter(Boolean))).sort(), [mergedDocs]);
  const availableMacros = useMemo(() => {
      const docs = filterProject ? mergedDocs.filter(d => d.project === filterProject) : mergedDocs;
      return Array.from(new Set(docs.map(d => d.macroprocess).filter(Boolean))).sort();
  }, [mergedDocs, filterProject]);
  const availableProcesses = useMemo(() => {
      let docs = mergedDocs;
      if (filterProject) docs = docs.filter(d => d.project === filterProject);
      if (filterMacro) docs = docs.filter(d => d.macroprocess === filterMacro);
      return Array.from(new Set(docs.map(d => d.process).filter(Boolean))).sort();
  }, [mergedDocs, filterProject, filterMacro]);

  const getUserName = (id: string) => allUsers.find(user => user.id === id)?.name || 'Sin Asignar';

  if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Actualizando dashboard...</div>;

  if (isSystemEmpty) {
      return (
          <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6 bg-white rounded-xl shadow-sm border border-slate-200">
              <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center mb-6"><Database size={40} className="text-indigo-600" /></div>
              <h2 className="text-2xl font-bold text-slate-900 mb-2">Sistema sin Inicializar</h2>
              <p className="text-slate-500 max-w-md mb-8">La matriz de procesos está vacía. Cargue la estructura de procesos para comenzar.</p>
              {(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) && (
                  <Link to="/admin/assignments" className="flex items-center px-6 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-medium shadow-md transition-transform active:scale-95">
                      <Database size={18} className="mr-2" /> Ir a Carga de Datos
                  </Link>
              )}
          </div>
      );
  }

  const hasActiveFilters = filterProject || filterMacro || filterProcess || filterSearch || filterDocType || filterState || filterAnalyst || externalFilterIds;

  return (
    <div className="space-y-6 pb-12">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div><h1 className="text-2xl font-bold text-slate-900">Dashboard</h1><p className="text-slate-500">Vista general de avance institucional</p></div>
        <div className="flex items-center gap-2 w-full sm:w-auto">
            <button onClick={handleExportExcel} className="flex-1 sm:flex-none px-4 py-2 bg-white border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 flex items-center justify-center shadow-sm font-medium transition-colors">
                <FileSpreadsheet size={18} className="mr-2 text-green-600"/> <span className="hidden md:inline">Exportar Excel</span><span className="md:hidden">Excel</span>
            </button>
            {user.role === UserRole.ANALYST && <Link to="/new" className="flex-1 sm:flex-none px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 flex items-center justify-center shadow-sm font-medium"><Plus size={18} className="mr-2"/> Nueva Solicitud</Link>}
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-3">
        <StatCard title="Doc. Requeridos" value={stats.total} icon={BookOpen} color="bg-slate-50 text-slate-600" onClick={() => handleQuickFilter('ALL')} isActive={quickFilter === 'ALL'}/>
        <StatCard title="No Iniciado" value={stats.notStarted} icon={Clock} color="bg-white text-slate-600" onClick={() => handleQuickFilter('NOT_STARTED')} isActive={quickFilter === 'NOT_STARTED'}/>
        <StatCard title="En Proceso" value={stats.inProcess} icon={Activity} color="bg-blue-50 text-blue-600" onClick={() => handleQuickFilter('IN_PROCESS')} isActive={quickFilter === 'IN_PROCESS'}/>
        <StatCard title="Referente" value={stats.referent} icon={Users} color="bg-purple-50 text-purple-600" onClick={() => handleQuickFilter('REFERENT')} isActive={quickFilter === 'REFERENT'}/>
        <StatCard title="Control Gestión" value={stats.control} icon={ShieldCheck} color="bg-orange-50 text-orange-600" onClick={() => handleQuickFilter('CONTROL')} isActive={quickFilter === 'CONTROL'}/>
        <StatCard title="Terminados" value={stats.finished} icon={CheckCircle} color="bg-green-50 text-green-600" onClick={() => handleQuickFilter('FINISHED')} isActive={quickFilter === 'FINISHED'}/>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        <div className="lg:col-span-3 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col min-h-[500px]">
            <div className="p-4 border-b border-slate-100 bg-white">
                <div className="flex items-center justify-between mb-3">
                    <div className="flex items-center gap-2 text-indigo-600 font-semibold text-sm"><Filter size={16} /> Filtros de Visualización</div>
                    {hasActiveFilters && <button onClick={clearFilters} className="text-xs text-red-500 hover:text-red-700 flex items-center gap-1 font-medium"><X size={14} /> Limpiar filtros</button>}
                </div>
                {externalFilterIds ? (
                     <div className="bg-blue-50 border border-blue-100 p-3 rounded-lg mb-2 flex justify-between items-center animate-fadeIn">
                        <span className="text-xs text-blue-700 font-semibold">Filtro Activo: Visualizando {externalFilterIds.length} documentos específicos desde reportes.</span>
                        <button onClick={clearFilters} className="text-xs bg-white border border-blue-200 px-2 py-1 rounded text-blue-600">Mostrar Todo</button>
                     </div>
                ) : (
                    <div className="flex flex-wrap gap-2">
                        <select value={filterProject} onChange={(e) => setFilterProject(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-28">
                            <option value="">PROYECTO</option>
                            {availableProjects.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                        <select value={filterMacro} onChange={(e) => setFilterMacro(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-32">
                            <option value="">MACROPROCESO</option>
                            {availableMacros.map(m => <option key={m} value={m}>{m}</option>)}
                        </select>
                        <select value={filterProcess} onChange={(e) => setFilterProcess(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-32">
                            <option value="">PROCESO</option>
                            {availableProcesses.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                        <div className="relative w-36">
                            <Search size={12} className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400" />
                            <input type="text" value={filterSearch} onChange={(e) => setFilterSearch(e.target.value)} placeholder="BUSCAR..." className="w-full text-[11px] pl-7 p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none" />
                        </div>
                        <select value={filterDocType} onChange={(e) => setFilterDocType(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-24">
                            <option value="">DOC</option>
                            <option value="AS IS">AS IS</option>
                            <option value="FCE">FCE</option>
                            <option value="PM">PM</option>
                            <option value="TO BE">TO BE</option>
                        </select>
                        <select value={filterState} onChange={(e) => setFilterState(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-24">
                            <option value="">ESTADO</option>
                            {Object.entries(STATE_CONFIG).map(([key, cfg]) => <option key={key} value={key}>{cfg.label.split('(')[0]}</option>)}
                        </select>
                        <select value={filterAnalyst} onChange={(e) => setFilterAnalyst(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-32">
                            <option value="">ANALISTA</option>
                            {allUsers.filter(u => u.role === UserRole.ANALYST).map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                        </select>
                    </div>
                )}
            </div>

            <div className="overflow-x-auto flex-1">
                <table className="w-full text-[11px] text-left">
                    <thead className="text-[10px] text-slate-400 uppercase font-bold bg-white border-b border-slate-100">
                        <tr>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('project')}>PROYECTO <SortIcon column="project"/></th>
                            <th className="px-4 py-3">JERARQUÍA (MACRO / PROCESO)</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('microprocess')}>MICROPROCESO <SortIcon column="microprocess"/></th>
                            <th className="px-4 py-3">DOCUMENTO</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('state')}>ESTADO ACTUAL <SortIcon column="state"/></th>
                            <th className="px-4 py-3 text-right cursor-pointer group" onClick={() => handleSort('updatedAt')}>ÚLTIMA ACTIVIDAD <SortIcon column="updatedAt"/></th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                        {paginatedDocs.length === 0 ? (
                            <tr><td colSpan={6} className="p-12 text-center text-slate-400"><Search size={40} className="mx-auto mb-2 opacity-20"/><p>Sin resultados.</p></td></tr>
                        ) : paginatedDocs.map((doc, idx) => (
                            <tr key={`${doc.id}-${idx}`} className={`transition-colors ${!doc.isRequired ? 'bg-gray-100 hover:bg-gray-200' : 'hover:bg-slate-50'}`}>
                                <td className={`px-4 py-3 font-bold align-top ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.project}</td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`font-bold ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.macroprocess}</div>
                                    <div className="text-slate-500 text-[10px]">{doc.process}</div>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`font-bold mb-1 ${!doc.isRequired ? 'text-gray-600' : 'text-slate-800'}`}>{doc.microprocess}</div>
                                    <div className="flex items-center gap-1 text-slate-400" title="Analista Asignado">
                                        <UserIcon size={10} /> <span className="text-[10px] truncate max-w-[120px]">{doc.assignees && doc.assignees.length > 0 ? getUserName(doc.assignees[0]) : 'Sin Asignar'}</span>
                                    </div>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <span className={`inline-block px-1.5 py-0.5 rounded border text-[10px] font-bold mb-1 ${!doc.isRequired ? 'bg-gray-200 text-gray-400 border-gray-300' : 'bg-indigo-50 text-indigo-700 border-indigo-100'}`}>{doc.docType}</span>
                                    <Link to={`/doc/${doc.id}`} state={{ docData: doc }} className="flex items-center gap-1 text-[10px] font-bold text-indigo-500 hover:text-indigo-700 underline">Ver Detalle</Link>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`inline-block px-2 py-0.5 rounded-full text-[10px] font-bold mb-1 border ${!doc.isRequired ? 'bg-gray-200 text-gray-500 border-gray-300' : STATE_CONFIG[doc.state].color}`}>{STATE_CONFIG[doc.state].label.split('(')[0]}</div>
                                    <div className="text-[10px] font-mono text-slate-500">v{doc.version} ({doc.progress}%)</div>
                                </td>
                                <td className="px-4 py-3 align-top text-right">
                                    {doc.state !== DocState.NOT_STARTED ? (
                                        <div className="text-slate-600 font-medium">{new Date(doc.updatedAt).toLocaleDateString()}</div>
                                    ) : <span className="text-slate-300">-</span>}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {totalItems > 0 && (
                <div className="px-4 py-3 border-t border-slate-100 bg-slate-50/50 flex flex-col sm:flex-row items-center justify-between gap-4">
                    <div className="text-[11px] text-slate-500">Mostrando <b>{Math.min(totalItems, (currentPage - 1) * ITEMS_PER_PAGE + 1)}</b> a <b>{Math.min(totalItems, currentPage * ITEMS_PER_PAGE)}</b> de <b>{totalItems}</b> registros</div>
                    <div className="flex items-center gap-2">
                        <button onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))} disabled={currentPage === 1} className="p-1.5 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 disabled:opacity-50"><ChevronLeft size={16} /></button>
                        <div className="flex items-center gap-1">
                            {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                                let pageNum = i + 1;
                                if (totalPages > 5 && currentPage > 3) { pageNum = currentPage - 2 + i; if (pageNum > totalPages) pageNum = totalPages - (4 - i); }
                                return <button key={pageNum} onClick={() => setCurrentPage(pageNum)} className={`w-7 h-7 rounded-lg text-xs font-bold border transition-all ${currentPage === pageNum ? 'bg-indigo-600 text-white' : 'bg-white text-slate-600 hover:border-indigo-400'}`}>{pageNum}</button>;
                            })}
                        </div>
                        <button onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))} disabled={currentPage === totalPages} className="p-1.5 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 disabled:opacity-50"><ChevronRight size={16} /></button>
                    </div>
                </div>
            )}
        </div>

        <div className="lg:col-span-1 space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4 min-h-[250px] flex flex-col items-center justify-center">
                <h3 className="font-bold text-center mb-2 text-slate-700 text-xs uppercase">Estado Universo Requerido</h3>
                {chartData.length > 0 ? (
                    <div className="h-44 w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie data={chartData} cx="50%" cy="50%" innerRadius={45} outerRadius={65} paddingAngle={2} dataKey="value">
                                    {chartData.map((e, i) => <Cell key={i} fill={e.color}/>)}
                                </Pie>
                                <Tooltip contentStyle={{fontSize: '11px', borderRadius: '8px'}}/>
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                ) : <p className="text-center text-slate-400 text-[10px]">Sin datos.</p>}
                <div className="flex flex-wrap justify-center gap-x-3 gap-y-1 mt-2">
                    {chartData.map((d, i) => (
                        <div key={i} className="flex items-center gap-1"><span className="w-2 h-2 rounded-full" style={{backgroundColor: d.color}}></span><span className="text-[9px] text-slate-500 uppercase font-bold">{d.name}</span></div>
                    ))}
                </div>
            </div>
            <div className="bg-indigo-50 rounded-xl shadow-sm border border-indigo-100 p-4">
                <h3 className="font-bold text-indigo-900 text-xs uppercase mb-3">Resumen de Cumplimiento</h3>
                <ul className="space-y-2 text-[11px]">
                    <li className="flex justify-between text-slate-600"><span>No Iniciados:</span> <b>{stats.notStarted}</b></li>
                    <li className="flex justify-between text-blue-600"><span>En Proceso:</span> <b>{stats.inProcess}</b></li>
                    <li className="flex justify-between text-purple-600"><span>Referente:</span> <b>{stats.referent}</b></li>
                    <li className="flex justify-between text-orange-600"><span>Control Gestión:</span> <b>{stats.control}</b></li>
                    <li className="border-t border-indigo-200 pt-1 flex justify-between text-green-600 font-bold"><span>Terminados:</span> <span>{stats.finished}</span></li>
                </ul>
                <div className="mt-4 pt-3 border-t border-indigo-200 text-[9px] text-slate-500 flex items-center gap-2"><Archive size={12} /><span>Registros en <b>GRIS</b> son históricos externos.</span></div>
            </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon: Icon, color, isActive, onClick }: any) => (
    <div onClick={onClick} className={`p-3 rounded-xl shadow-sm border cursor-pointer flex items-center space-x-3 transition-all ${isActive ? 'ring-2 ring-indigo-300 scale-105' : 'hover:border-indigo-300'} ${color} border-transparent`}>
        <div className="p-1.5 bg-white/50 rounded-lg shrink-0"><Icon size={18}/></div>
        <div className="min-w-0">
            <p className="text-[9px] uppercase font-bold opacity-70 truncate">{title}</p>
            <p className="text-lg font-bold leading-none">{value}</p>
        </div>
    </div>
);

export default Dashboard;

import React, { useEffect, useState, useMemo } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService } from '../services/firebaseBackend';
import { Document, User, UserRole, DocState, DocType, FullHierarchy } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    Plus, Clock, CheckCircle, Filter, X, Activity, 
    BookOpen, Users, ShieldCheck, ArrowUp, ArrowDown, ArrowUpDown, Loader2,
    User as UserIcon, Database, Archive, Search,
    ChevronLeft, ChevronRight, FileSpreadsheet
} from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

interface DashboardProps {
  user: User;
}

interface DashboardDoc extends Document {
    isRequired: boolean;
}

type SortKey = 'project' | 'microprocess' | 'state' | 'updatedAt';
type QuickFilterType = 'ALL' | 'NOT_STARTED' | 'IN_PROCESS' | 'REFERENT' | 'CONTROL' | 'FINISHED';

const ITEMS_PER_PAGE = 10;

const getDocTypeOrder = (type: string | undefined): number => {
    switch (type) {
        case 'AS IS': return 1;
        case 'FCE': return 2;
        case 'PM': return 3;
        case 'TO BE': return 4;
        default: return 99;
    }
};

const Dashboard: React.FC<DashboardProps> = ({ user }) => {
  const navigate = useNavigate();
  const location = useLocation(); 

  const [mergedDocs, setMergedDocs] = useState<DashboardDoc[]>([]);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSystemEmpty, setIsSystemEmpty] = useState(false);

  // Filtros de Estado
  const [filterProject, setFilterProject] = useState('');
  const [filterMacro, setFilterMacro] = useState('');
  const [filterProcess, setFilterProcess] = useState('');
  const [filterSearch, setFilterSearch] = useState(''); 
  const [filterDocType, setFilterDocType] = useState('');
  const [filterState, setFilterState] = useState(''); 
  const [filterAnalyst, setFilterAnalyst] = useState('');

  // Paginación
  const [currentPage, setCurrentPage] = useState(1);
  const [externalFilterIds, setExternalFilterIds] = useState<string[] | null>(null);
  const [quickFilter, setQuickFilter] = useState<QuickFilterType>('ALL');

  const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: 'asc' | 'desc' }>({
    key: 'project', 
    direction: 'asc'
  });

  useEffect(() => {
    if (location.state?.filterIds && Array.isArray(location.state.filterIds)) {
        setExternalFilterIds(location.state.filterIds);
        setQuickFilter('ALL');
    } else {
        setExternalFilterIds(null);
    }
    loadData();
  }, [location.state]);

  useEffect(() => {
    setCurrentPage(1);
  }, [filterProject, filterMacro, filterProcess, filterSearch, filterDocType, filterState, filterAnalyst, quickFilter, sortConfig]);

  const normalize = (str: string | undefined) => {
      if (!str) return '';
      return str.trim().toUpperCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  };

  const loadData = async () => {
    setLoading(true);
    try {
        const [realDocsData, users, fullHierarchy] = await Promise.all([
            DocumentService.getAll(),
            UserService.getAll(),
            HierarchyService.getFullHierarchy()
        ]);

        setAllUsers(users);
        const hierarchyKeys = Object.keys(fullHierarchy);

        if (hierarchyKeys.length === 0 && realDocsData.length === 0) {
            setIsSystemEmpty(true);
            setMergedDocs([]);
            setLoading(false);
            return;
        }
        setIsSystemEmpty(false);

        const realDocMap = new Map<string, Document>();
        const processedDocIds = new Set<string>();

        realDocsData.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalize(doc.project)}|${normalize(microName)}|${normalize(docType)}`;

                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        const finalDocsList: DashboardDoc[] = [];

        hierarchyKeys.forEach(proj => {
            Object.keys(fullHierarchy[proj]).forEach(macro => {
                Object.keys(fullHierarchy[proj][macro]).forEach(proc => {
                    const nodes = fullHierarchy[proj][macro][proc];
                    nodes.forEach(node => {
                        if (node.active === false) return; 

                        const requiredTypes = (node.requiredTypes && node.requiredTypes.length > 0) 
                            ? node.requiredTypes 
                            : ['AS IS', 'FCE', 'PM', 'TO BE'];

                        requiredTypes.forEach(type => {
                            const key = `${normalize(proj)}|${normalize(node.name)}|${normalize(type)}`;

                            if (realDocMap.has(key)) {
                                const realDoc = realDocMap.get(key)!;
                                finalDocsList.push({
                                    ...realDoc,
                                    macroprocess: macro,
                                    process: proc,
                                    project: proj,
                                    assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []),
                                    isRequired: true 
                                });
                                processedDocIds.add(realDoc.id); 
                            } else {
                                finalDocsList.push({
                                    id: `virtual-${key}`, 
                                    title: `${node.name} - ${type}`,
                                    description: 'Pendiente de inicio',
                                    project: proj,
                                    macroprocess: macro,
                                    process: proc,
                                    microprocess: node.name,
                                    docType: type as DocType,
                                    authorId: '',
                                    authorName: '',
                                    assignedTo: node.assignees?.[0] || '',
                                    assignees: node.assignees || [],
                                    state: DocState.NOT_STARTED,
                                    version: '-',
                                    progress: 0,
                                    files: [],
                                    createdAt: new Date().toISOString(),
                                    updatedAt: new Date(0).toISOString(), 
                                    hasPendingRequest: false,
                                    isRequired: true 
                                });
                            }
                        });
                    });
                });
            });
        });

        realDocMap.forEach((doc) => {
            if (!processedDocIds.has(doc.id)) {
                finalDocsList.push({
                    ...doc,
                    macroprocess: doc.macroprocess || 'Sin Clasificar',
                    process: doc.process || 'Sin Clasificar',
                    isRequired: false 
                });
            }
        });

        setMergedDocs(finalDocsList);

    } catch (error) {
        console.error("Error loading dashboard data:", error);
    } finally {
        setLoading(false);
    }
  };

  const contextDocs = useMemo(() => {
      let filtered = mergedDocs;

      if (externalFilterIds && externalFilterIds.length > 0) {
          filtered = filtered.filter(d => externalFilterIds.includes(d.id));
      } else {
          if (filterProject) filtered = filtered.filter(d => d.project === filterProject);
          if (filterMacro) filtered = filtered.filter(d => d.macroprocess === filterMacro);
          if (filterProcess) filtered = filtered.filter(d => d.process === filterProcess);
          if (filterDocType) filtered = filtered.filter(d => d.docType === filterDocType);
          if (filterState) filtered = filtered.filter(d => d.state === filterState);
          if (filterAnalyst) filtered = filtered.filter(d => d.assignees && d.assignees.includes(filterAnalyst));

          if (filterSearch) {
              const term = filterSearch.toLowerCase();
              filtered = filtered.filter(d => 
                  (d.microprocess || '').toLowerCase().includes(term) || 
                  (d.title || '').toLowerCase().includes(term)
              );
          }
      }

      return filtered;
  }, [mergedDocs, filterProject, filterMacro, filterProcess, filterDocType, filterState, filterAnalyst, filterSearch, externalFilterIds]);

  const stats = useMemo(() => {
      const requiredDocs = contextDocs.filter(d => d.isRequired);

      return {
        total: requiredDocs.length,
        notStarted: requiredDocs.filter(d => d.state === DocState.NOT_STARTED).length,
        inProcess: requiredDocs.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW).length,
        referent: requiredDocs.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW).length,
        control: requiredDocs.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW).length,
        finished: requiredDocs.filter(d => d.state === DocState.APPROVED).length
      };
  }, [contextDocs]);

  const chartData = useMemo(() => {
    return [
      { name: 'No Iniciado', value: stats.notStarted, color: '#94a3b8' },
      { name: 'En Proceso', value: stats.inProcess, color: '#3b82f6' },
      { name: 'Referente', value: stats.referent, color: '#a855f7' },
      { name: 'Control', value: stats.control, color: '#f97316' },
      { name: 'Terminados', value: stats.finished, color: '#22c55e' }
    ].filter(d => d.value > 0);
  }, [stats]);

  const tableDocs = useMemo(() => {
      let filtered = contextDocs;

      if (quickFilter !== 'ALL') {
          switch (quickFilter) {
              case 'NOT_STARTED': filtered = filtered.filter(d => d.state === DocState.NOT_STARTED); break;
              case 'IN_PROCESS': filtered = filtered.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW); break;
              case 'REFERENT': filtered = filtered.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW); break;
              case 'CONTROL': filtered = filtered.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW); break;
              case 'FINISHED': filtered = filtered.filter(d => d.state === DocState.APPROVED); break;
          }
      }
      return filtered;
  }, [contextDocs, quickFilter]);

  const sortedDocs = useMemo(() => {
      return [...tableDocs].sort((a, b) => {
          if (a.isRequired !== b.isRequired) {
              return a.isRequired ? -1 : 1;
          }

          const modifier = sortConfig.direction === 'asc' ? 1 : -1;

          switch (sortConfig.key) {
              case 'updatedAt': 
                  const timeA = new Date(a.updatedAt).getTime();
                  const timeB = new Date(b.updatedAt).getTime();
                  return (timeA - timeB) * modifier;

              case 'project': 
                  if ((a.project || '') !== (b.project || '')) return (a.project || '').localeCompare(b.project || '') * modifier;
                  if ((a.macroprocess || '') !== (b.macroprocess || '')) return (a.macroprocess || '').localeCompare(b.macroprocess || '') * modifier;
                  if ((a.process || '') !== (b.process || '')) return (a.process || '').localeCompare(b.process || '') * modifier;
                  if ((a.microprocess || '') !== (b.microprocess || '')) return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
                  return (getDocTypeOrder(a.docType) - getDocTypeOrder(b.docType)) * modifier;

              case 'microprocess': return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
              case 'state': return (a.progress - b.progress) * modifier;
              default: return 0;
          }
      });
  }, [tableDocs, sortConfig]);

  const totalItems = sortedDocs.length;
  const totalPages = Math.ceil(totalItems / ITEMS_PER_PAGE);
  const paginatedDocs = useMemo(() => {
      const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
      return sortedDocs.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [sortedDocs, currentPage]);

  const handleExportExcel = () => {
      if (sortedDocs.length === 0) return;
      const getUserNames = (ids: string[]) => ids.map(id => allUsers.find(u => u.id === id)?.name || id).join('; ');

      const headers = ['PROYECTO', 'MACROPROCESO', 'PROCESO', 'MICROPROCESO', 'DOCUMENTO', 'VERSION', 'ESTADO', 'FECHA', 'ANALISTA'];
      const rows = sortedDocs.map(d => {
          let fechaStr = 'Sin actividad';
          if (d.state !== DocState.NOT_STARTED && d.updatedAt) {
              const date = new Date(d.updatedAt);
              const day = String(date.getDate()).padStart(2, '0');
              const month = String(date.getMonth() + 1).padStart(2, '0');
              const year = date.getFullYear();
              fechaStr = `${day}-${month}-${year}`;
          }

          return [
              d.project || '-',
              d.macroprocess || '-',
              d.process || '-',
              d.microprocess || '-',
              d.docType || '-',
              d.version || '-',
              STATE_CONFIG[d.state]?.label.split('(')[0] || '-',
              fechaStr,
              getUserNames(d.assignees || [])
          ];
      });

      const csvContent = [headers.join(';'), ...rows.map(r => r.map(cell => `"${cell}"`).join(';'))].join('\n');
      const blob = new Blob(["\ufeff", csvContent], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.setAttribute('href', url);
      link.setAttribute('download', `SGD_Reporte_${new Date().toISOString().split('T')[0]}.csv`);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
  };

  const handleSort = (key: SortKey) => {
      setSortConfig({ key, direction: sortConfig.key === key && sortConfig.direction === 'asc' ? 'desc' : 'asc' });
  };

  const handleQuickFilter = (type: QuickFilterType) => {
    setQuickFilter(type);
    setCurrentPage(1);
  };

  const clearFilters = () => {
      setFilterProject(''); setFilterMacro(''); setFilterProcess(''); setFilterSearch(''); 
      setFilterDocType(''); setFilterState(''); setFilterAnalyst(''); setQuickFilter('ALL');
      setExternalFilterIds(null); navigate(location.pathname, { replace: true, state: {} });
  };

  const SortIcon = ({ column }: { column: SortKey }) => (
      sortConfig.key === column ? (sortConfig.direction === 'asc' ? <ArrowUp size={12} className="text-indigo-600"/> : <ArrowDown size={12} className="text-indigo-600"/>) : <ArrowUpDown size={12} className="opacity-30 group-hover:opacity-100"/>
  );

  const availableProjects = useMemo(() => Array.from(new Set(mergedDocs.map(d => d.project).filter(Boolean))).sort(), [mergedDocs]);
  const availableMacros = useMemo(() => {
      const docs = filterProject ? mergedDocs.filter(d => d.project === filterProject) : mergedDocs;
      return Array.from(new Set(docs.map(d => d.macroprocess).filter(Boolean))).sort();
  }, [mergedDocs, filterProject]);
  const availableProcesses = useMemo(() => {
      let docs = mergedDocs;
      if (filterProject) docs = docs.filter(d => d.project === filterProject);
      if (filterMacro) docs = docs.filter(d => d.macroprocess === filterMacro);
      return Array.from(new Set(docs.map(d => d.process).filter(Boolean))).sort();
  }, [mergedDocs, filterProject, filterMacro]);

  const getUserName = (id: string) => allUsers.find(user => user.id === id)?.name || 'Sin Asignar';

  if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Actualizando dashboard...</div>;

  if (isSystemEmpty) {
      return (
          <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6 bg-white rounded-xl shadow-sm border border-slate-200">
              <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center mb-6"><Database size={40} className="text-indigo-600" /></div>
              <h2 className="text-2xl font-bold text-slate-900 mb-2">Sistema sin Inicializar</h2>
              <p className="text-slate-500 max-w-md mb-8">La matriz de procesos está vacía. Cargue la estructura de procesos para comenzar.</p>
              {(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) && (
                  <Link to="/admin/assignments" className="flex items-center px-6 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-medium shadow-md transition-transform active:scale-95">
                      <Database size={18} className="mr-2" /> Ir a Carga de Datos
                  </Link>
              )}
          </div>
      );
  }

  const hasActiveFilters = filterProject || filterMacro || filterProcess || filterSearch || filterDocType || filterState || filterAnalyst || externalFilterIds;

  return (
    <div className="space-y-6 pb-12">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div><h1 className="text-2xl font-bold text-slate-900">Dashboard</h1><p className="text-slate-500">Vista general de avance institucional</p></div>
        <div className="flex items-center gap-2 w-full sm:w-auto">
            <button onClick={handleExportExcel} className="flex-1 sm:flex-none px-4 py-2 bg-white border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 flex items-center justify-center shadow-sm font-medium transition-colors">
                <FileSpreadsheet size={18} className="mr-2 text-green-600"/> <span className="hidden md:inline">Exportar Excel</span><span className="md:hidden">Excel</span>
            </button>
            {user.role === UserRole.ANALYST && <Link to="/new" className="flex-1 sm:flex-none px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 flex items-center justify-center shadow-sm font-medium"><Plus size={18} className="mr-2"/> Nueva Solicitud</Link>}
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-3">
        <StatCard title="Doc. Requeridos" value={stats.total} icon={BookOpen} color="bg-slate-50 text-slate-600" onClick={() => handleQuickFilter('ALL')} isActive={quickFilter === 'ALL'}/>
        <StatCard title="No Iniciado" value={stats.notStarted} icon={Clock} color="bg-white text-slate-600" onClick={() => handleQuickFilter('NOT_STARTED')} isActive={quickFilter === 'NOT_STARTED'}/>
        <StatCard title="En Proceso" value={stats.inProcess} icon={Activity} color="bg-blue-50 text-blue-600" onClick={() => handleQuickFilter('IN_PROCESS')} isActive={quickFilter === 'IN_PROCESS'}/>
        <StatCard title="Referente" value={stats.referent} icon={Users} color="bg-purple-50 text-purple-600" onClick={() => handleQuickFilter('REFERENT')} isActive={quickFilter === 'REFERENT'}/>
        <StatCard title="Control Gestión" value={stats.control} icon={ShieldCheck} color="bg-orange-50 text-orange-600" onClick={() => handleQuickFilter('CONTROL')} isActive={quickFilter === 'CONTROL'}/>
        <StatCard title="Terminados" value={stats.finished} icon={CheckCircle} color="bg-green-50 text-green-600" onClick={() => handleQuickFilter('FINISHED')} isActive={quickFilter === 'FINISHED'}/>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        <div className="lg:col-span-3 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col min-h-[500px]">
            <div className="p-4 border-b border-slate-100 bg-white">
                <div className="flex items-center justify-between mb-3">
                    <div className="flex items-center gap-2 text-indigo-600 font-semibold text-sm"><Filter size={16} /> Filtros de Visualización</div>
                    {hasActiveFilters && <button onClick={clearFilters} className="text-xs text-red-500 hover:text-red-700 flex items-center gap-1 font-medium"><X size={14} /> Limpiar filtros</button>}
                </div>
                {externalFilterIds ? (
                     <div className="bg-blue-50 border border-blue-100 p-3 rounded-lg mb-2 flex justify-between items-center animate-fadeIn">
                        <span className="text-xs text-blue-700 font-semibold">Filtro Activo: Visualizando {externalFilterIds.length} documentos específicos desde reportes.</span>
                        <button onClick={clearFilters} className="text-xs bg-white border border-blue-200 px-2 py-1 rounded text-blue-600">Mostrar Todo</button>
                     </div>
                ) : (
                    <div className="flex flex-wrap gap-2">
                        {/* ORDEN SOLICITADO: PROYECTO, MACROPROCESO, PROCESO, BUSCAR, DOC, ESTADO, ANALISTA */}
                        <select value={filterProject} onChange={(e) => setFilterProject(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-28">
                            <option value="">PROYECTO</option>
                            {availableProjects.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                        <select value={filterMacro} onChange={(e) => setFilterMacro(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-32">
                            <option value="">MACROPROCESO</option>
                            {availableMacros.map(m => <option key={m} value={m}>{m}</option>)}
                        </select>
                        <select value={filterProcess} onChange={(e) => setFilterProcess(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-32">
                            <option value="">PROCESO</option>
                            {availableProcesses.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                        <div className="relative w-36">
                            <Search size={12} className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400" />
                            <input type="text" value={filterSearch} onChange={(e) => setFilterSearch(e.target.value)} placeholder="BUSCAR..." className="w-full text-[11px] pl-7 p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none" />
                        </div>
                        <select value={filterDocType} onChange={(e) => setFilterDocType(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-24">
                            <option value="">DOC</option>
                            <option value="AS IS">AS IS</option>
                            <option value="FCE">FCE</option>
                            <option value="PM">PM</option>
                            <option value="TO BE">TO BE</option>
                        </select>
                        <select value={filterState} onChange={(e) => setFilterState(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-24">
                            <option value="">ESTADO</option>
                            {Object.entries(STATE_CONFIG).map(([key, cfg]) => <option key={key} value={key}>{cfg.label.split('(')[0]}</option>)}
                        </select>
                        <select value={filterAnalyst} onChange={(e) => setFilterAnalyst(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-32">
                            <option value="">ANALISTA</option>
                            {allUsers.filter(u => u.role === UserRole.ANALYST).map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                        </select>
                    </div>
                )}
            </div>

            <div className="overflow-x-auto flex-1">
                <table className="w-full text-[11px] text-left">
                    <thead className="text-[10px] text-slate-400 uppercase font-bold bg-white border-b border-slate-100">
                        <tr>
                            {/* CABECERAS SOLICITADAS: PROYECTO, JERARQUÍA (MACRO / PROCESO), MICROPROCESO, DOCUMENTO, ESTADO ACTUAL, ÚLTIMA ACTIVIDAD */}
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('project')}>PROYECTO <SortIcon column="project"/></th>
                            <th className="px-4 py-3">JERARQUÍA (MACRO / PROCESO)</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('microprocess')}>MICROPROCESO <SortIcon column="microprocess"/></th>
                            <th className="px-4 py-3">DOCUMENTO</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('state')}>ESTADO ACTUAL <SortIcon column="state"/></th>
                            <th className="px-4 py-3 text-right cursor-pointer group" onClick={() => handleSort('updatedAt')}>ÚLTIMA ACTIVIDAD <SortIcon column="updatedAt"/></th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                        {paginatedDocs.length === 0 ? (
                            <tr><td colSpan={6} className="p-12 text-center text-slate-400"><Search size={40} className="mx-auto mb-2 opacity-20"/><p>Sin resultados.</p></td></tr>
                        ) : paginatedDocs.map((doc, idx) => (
                            <tr key={`${doc.id}-${idx}`} className={`transition-colors ${!doc.isRequired ? 'bg-gray-100 hover:bg-gray-200' : 'hover:bg-slate-50'}`}>
                                <td className={`px-4 py-3 font-bold align-top ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.project}</td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`font-bold ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.macroprocess}</div>
                                    <div className="text-slate-500 text-[10px]">{doc.process}</div>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`font-bold mb-1 ${!doc.isRequired ? 'text-gray-600' : 'text-slate-800'}`}>{doc.microprocess}</div>
                                    <div className="flex items-center gap-1 text-slate-400" title="Analista Asignado">
                                        <UserIcon size={10} /> <span className="text-[10px] truncate max-w-[120px]">{doc.assignees && doc.assignees.length > 0 ? getUserName(doc.assignees[0]) : 'Sin Asignar'}</span>
                                    </div>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <span className={`inline-block px-1.5 py-0.5 rounded border text-[10px] font-bold mb-1 ${!doc.isRequired ? 'bg-gray-200 text-gray-400 border-gray-300' : 'bg-indigo-50 text-indigo-700 border-indigo-100'}`}>{doc.docType}</span>
                                    <Link to={`/doc/${doc.id}`} state={{ docData: doc }} className="flex items-center gap-1 text-[10px] font-bold text-indigo-500 hover:text-indigo-700 underline">Ver Detalle</Link>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`inline-block px-2 py-0.5 rounded-full text-[10px] font-bold mb-1 border ${!doc.isRequired ? 'bg-gray-200 text-gray-500 border-gray-300' : STATE_CONFIG[doc.state].color}`}>{STATE_CONFIG[doc.state].label.split('(')[0]}</div>
                                    {/* CORRECCIÓN: Se eliminó la 'v' duplicada. La variable {doc.version} ya trae el prefijo si corresponde */}
                                    <div className="text-[10px] font-mono text-slate-500">{doc.version} ({doc.progress}%)</div>
                                </td>
                                <td className="px-4 py-3 align-top text-right">
                                    {doc.state !== DocState.NOT_STARTED ? (
                                        <div className="text-slate-600 font-medium">{new Date(doc.updatedAt).toLocaleDateString()}</div>
                                    ) : <span className="text-slate-300">-</span>}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {totalItems > 0 && (
                <div className="px-4 py-3 border-t border-slate-100 bg-slate-50/50 flex flex-col sm:flex-row items-center justify-between gap-4">
                    <div className="text-[11px] text-slate-500">Mostrando <b>{Math.min(totalItems, (currentPage - 1) * ITEMS_PER_PAGE + 1)}</b> a <b>{Math.min(totalItems, currentPage * ITEMS_PER_PAGE)}</b> de <b>{totalItems}</b> registros</div>
                    <div className="flex items-center gap-2">
                        <button onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))} disabled={currentPage === 1} className="p-1.5 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 disabled:opacity-50"><ChevronLeft size={16} /></button>
                        <div className="flex items-center gap-1">
                            {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                                let pageNum = i + 1;
                                if (totalPages > 5 && currentPage > 3) { pageNum = currentPage - 2 + i; if (pageNum > totalPages) pageNum = totalPages - (4 - i); }
                                return <button key={pageNum} onClick={() => setCurrentPage(pageNum)} className={`w-7 h-7 rounded-lg text-xs font-bold border transition-all ${currentPage === pageNum ? 'bg-indigo-600 text-white' : 'bg-white text-slate-600 hover:border-indigo-400'}`}>{pageNum}</button>;
                            })}
                        </div>
                        <button onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))} disabled={currentPage === totalPages} className="p-1.5 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 disabled:opacity-50"><ChevronRight size={16} /></button>
                    </div>
                </div>
            )}
        </div>

        <div className="lg:col-span-1 space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4 min-h-[250px] flex flex-col items-center justify-center">
                <h3 className="font-bold text-center mb-2 text-slate-700 text-xs uppercase">Estado Universo Requerido</h3>
                {chartData.length > 0 ? (
                    <div className="h-44 w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie data={chartData} cx="50%" cy="50%" innerRadius={45} outerRadius={65} paddingAngle={2} dataKey="value">
                                    {chartData.map((e, i) => <Cell key={i} fill={e.color}/>)}
                                </Pie>
                                <Tooltip contentStyle={{fontSize: '11px', borderRadius: '8px'}}/>
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                ) : <p className="text-center text-slate-400 text-[10px]">Sin datos.</p>}
                <div className="flex flex-wrap justify-center gap-x-3 gap-y-1 mt-2">
                    {chartData.map((d, i) => (
                        <div key={i} className="flex items-center gap-1"><span className="w-2 h-2 rounded-full" style={{backgroundColor: d.color}}></span><span className="text-[9px] text-slate-500 uppercase font-bold">{d.name}</span></div>
                    ))}
                </div>
            </div>
            <div className="bg-indigo-50 rounded-xl shadow-sm border border-indigo-100 p-4">
                <h3 className="font-bold text-indigo-900 text-xs uppercase mb-3">Resumen de Cumplimiento</h3>
                <ul className="space-y-2 text-[11px]">
                    <li className="flex justify-between text-slate-600"><span>No Iniciados:</span> <b>{stats.notStarted}</b></li>
                    <li className="flex justify-between text-blue-600"><span>En Proceso:</span> <b>{stats.inProcess}</b></li>
                    <li className="flex justify-between text-purple-600"><span>Referente:</span> <b>{stats.referent}</b></li>
                    <li className="flex justify-between text-orange-600"><span>Control Gestión:</span> <b>{stats.control}</b></li>
                    <li className="border-t border-indigo-200 pt-1 flex justify-between text-green-600 font-bold"><span>Terminados:</span> <span>{stats.finished}</span></li>
                </ul>
                <div className="mt-4 pt-3 border-t border-indigo-200 text-[9px] text-slate-500 flex items-center gap-2"><Archive size={12} /><span>Registros en <b>GRIS</b> son históricos externos.</span></div>
            </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon: Icon, color, isActive, onClick }: any) => (
    <div onClick={onClick} className={`p-3 rounded-xl shadow-sm border cursor-pointer flex items-center space-x-3 transition-all ${isActive ? 'ring-2 ring-indigo-300 scale-105' : 'hover:border-indigo-300'} ${color} border-transparent`}>
        <div className="p-1.5 bg-white/50 rounded-lg shrink-0"><Icon size={18}/></div>
        <div className="min-w-0">
            <p className="text-[9px] uppercase font-bold opacity-70 truncate">{title}</p>
            <p className="text-lg font-bold leading-none">{value}</p>
        </div>
    </div>
);

export default Dashboard;
